// ─── Firebase internal state ──────────────────────────────────────────────────
let _fbDb    = null;
let _fbReady = false;
let _fbFns   = null; // { doc, setDoc, getDoc, onSnapshot, collection, getDocs }

// ─── initFirebase: lazy-init, called before any Firestore operation ───────────
async function initFirebase() {
  if (_fbReady && _fbDb) return _fbDb;
  try {
    const { initializeApp, getApps } = await import(
      "https://www.gstatic.com/firebasejs/10.12.0/firebase-app.js"
    );
    const {
      getFirestore, doc, setDoc, getDoc, onSnapshot,
      collection, getDocs, deleteDoc,
    } = await import(
      "https://www.gstatic.com/firebasejs/10.12.0/firebase-firestore.js"
    );
    const app = getApps().length ? getApps()[0] : initializeApp(FIREBASE_CONFIG);
    _fbDb    = getFirestore(app);
    _fbFns   = { doc, setDoc, getDoc, onSnapshot, collection, getDocs, deleteDoc };
    _fbReady = true;
    console.log("%c✅ VBT: Firestore connected", "color:#27ae60;font-weight:700");
    return _fbDb;
  } catch(e) {
    console.warn("⚠️ VBT: Firebase init failed — falling back to localStorage:", e.message);
    return null;
  }
}

// ─── fbSaveDoc: save a single document ───────────────────────────────────────
// collection: "companies" | "companyStates"
// docId: company.id
// data: any JS object
async function fbSaveDoc(colName, docId, data) {
  const db = await initFirebase();
  if (!db) return false;
  try {
    const { doc, setDoc } = _fbFns;
    await setDoc(doc(db, colName, String(docId)), {
      data:      JSON.stringify(data),
      docId:     String(docId),
      updatedAt: Date.now(),
    });
    return true;
  } catch(e) {
    console.warn("FB saveDoc error:", colName, docId, e.message);
    return false;
  }
}

// ─── fbLoadDoc: load a single document ───────────────────────────────────────
async function fbLoadDoc(colName, docId) {
  const db = await initFirebase();
  if (!db) return null;
  try {
    const { doc, getDoc } = _fbFns;
    const snap = await getDoc(doc(db, colName, String(docId)));
    if (!snap.exists()) return null;
    return JSON.parse(snap.data().data);
  } catch(e) {
    console.warn("FB loadDoc error:", colName, docId, e.message);
    return null;
  }
}

// ─── fbLoadAll: load ALL documents from a collection ─────────────────────────
async function fbLoadAll(colName) {
  const db = await initFirebase();
  if (!db) return null;
  try {
    const { collection, getDocs } = _fbFns;
    const snap = await getDocs(collection(db, colName));
    const result = {};
    snap.forEach(d => {
      try { result[d.id] = JSON.parse(d.data().data); } catch {}
    });
    return result; // { docId: data, ... }
  } catch(e) {
    console.warn("FB loadAll error:", colName, e.message);
    return null;
  }
}

// ─── fbSubscribeDoc: real-time listener for one document ─────────────────────
function fbSubscribeDoc(colName, docId, callback) {
  initFirebase().then(db => {
    if (!db) return;
    const { doc, onSnapshot } = _fbFns;
    return onSnapshot(doc(db, colName, String(docId)), snap => {
      if (snap.exists()) {
        try { callback(JSON.parse(snap.data().data)); } catch {}
      }
    });
  });
}

// ─── fbDeleteDoc: delete a document ──────────────────────────────────────────
async function fbDeleteDoc(colName, docId) {
  const db = await initFirebase();
  if (!db) return false;
  try {
    const { doc, deleteDoc } = _fbFns;
    await deleteDoc(doc(db, colName, String(docId)));
    return true;
  } catch(e) {
    console.warn("FB deleteDoc error:", e.message);
    return false;
  }
}

// Backward-compat wrappers (old code used fbSave/fbLoad/fbSubscribe)
const fbSave      = (col, id, data) => fbSaveDoc(col, id, data);
const fbLoad      = (col, id)       => fbLoadDoc(col, id);
const fbSubscribe = (col, id, cb)   => fbSubscribeDoc(col, id, cb);

