const DEFAULT_THEME = "dark_orange";

// Safe browser API wrappers (works in browser; no-op in React Native)
const _isWeb = typeof document !== "undefined" && typeof document.documentElement !== "undefined";
const _ls = {
  get: (k) => { try { const v = _isWeb && localStorage.getItem(k); return (v === "null" || v === null) ? null : v; } catch { return null; } },
  set: (k,v) => { try { if (_isWeb) { if (v === null || v === undefined) localStorage.removeItem(k); else localStorage.setItem(k, v); } } catch {} },
};

function applyTheme(themeKey) {
  const theme = THEMES[themeKey] || THEMES[DEFAULT_THEME];
  if (_isWeb) {
    Object.entries(theme.vars).forEach(([k,v]) =>
      document.documentElement.style.setProperty(k, v));
  }
  _ls.set("vbt_theme", themeKey);
}

function ThemePicker({ currentTheme, onChange }) {
  const [open, setOpen] = useState(false);
  const [hov,  setHov]  = useState(null);
  const cur = THEMES[currentTheme] || THEMES[DEFAULT_THEME];

  const groups = [
    { id:"dark",    label:"🌙 Dark",    keys: Object.keys(THEMES).filter(k=>THEMES[k].group==="dark") },
    { id:"special", label:"✨ Special", keys: Object.keys(THEMES).filter(k=>THEMES[k].group==="special") },
    { id:"light",   label:"☀️ Light",   keys: Object.keys(THEMES).filter(k=>THEMES[k].group==="light") },
  ];

  return (
    <div style={{position:"relative",zIndex:99999}}>
      {/* Trigger button */}
      <button
        title="Theme / Colour Scheme badlein"
        onClick={() => setOpen(o => !o)}
        style={{
          background: open ? "var(--accent)" : "var(--bg-card)",
          border: `1.5px solid ${open ? "var(--accent)" : "var(--border-inp)"}`,
          borderRadius: 8, color: open ? "#fff" : "var(--text-main)",
          padding: "5px 11px", cursor: "pointer", fontSize: 12, fontWeight: 700,
          display: "flex", alignItems: "center", gap: 5, whiteSpace: "nowrap",
          transition: "all 0.15s",
        }}
      >
        🎨
        <span style={{display:"flex",gap:2,alignItems:"center"}}>
          {(cur.preview||[]).map((c,i)=>(
            <span key={i} style={{display:"inline-block",width:8,height:8,borderRadius:2,background:c,border:"1px solid rgba(255,255,255,0.15)"}}/>
          ))}
        </span>
        <span style={{color: open?"#fff":"var(--accent)"}}>{cur.label}</span>
        <span style={{fontSize:9,opacity:0.6}}>{open?"▲":"▼"}</span>
      </button>

      {open && (
        <>
          <div style={{position:"fixed",inset:0,zIndex:998}} onClick={()=>setOpen(false)} />
          <div style={{
            position:"absolute", top:"110%", right:0, zIndex:999,
            background:"#181818", border:"1.5px solid #333",
            borderRadius:14, padding:14, width:360,
            boxShadow:"0 16px 48px rgba(0,0,0,0.8)",
          }}>
            <div style={{fontSize:12,fontWeight:800,color:"#ccc",marginBottom:10,
              display:"flex",alignItems:"center",justifyContent:"space-between"}}>
              <span>🎨 Theme Chunein</span>
              <span style={{fontSize:10,color:"#555"}}>{Object.keys(THEMES).length} themes</span>
            </div>

            {groups.map(g => (
              <div key={g.id} style={{marginBottom:10}}>
                <div style={{fontSize:10,fontWeight:700,color:"#555",letterSpacing:1.2,
                  textTransform:"uppercase",marginBottom:5,paddingBottom:3,borderBottom:"1px solid #252525"}}>
                  {g.label} ({g.keys.length})
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:5}}>
                  {g.keys.map(k => {
                    const t = THEMES[k];
                    const isCur = k === currentTheme;
                    const isHov = k === hov;
                    return (
                      <button key={k}
                        onClick={() => { onChange(k); setOpen(false); }}
                        onMouseEnter={() => setHov(k)}
                        onMouseLeave={() => setHov(null)}
                        title={t.label}
                        style={{
                          background: isCur ? t.vars["--accent"]+"28" : isHov ? "#252525" : "transparent",
                          border: `2px solid ${isCur ? t.vars["--accent"] : isHov ? t.vars["--accent"]+"66" : "#2a2a2a"}`,
                          borderRadius: 9, padding: "7px 5px", cursor: "pointer",
                          display:"flex", flexDirection:"column", gap:4, alignItems:"center",
                          transition:"all 0.13s",
                        }}
                      >
                        {/* Three color dots: bg, card, accent */}
                        <div style={{display:"flex",gap:2}}>
                          {(t.preview||[]).map((c,i)=>(
                            <div key={i} style={{
                              width:i===2?12:8, height:i===2?12:8,
                              borderRadius:i===2?3:2, background:c,
                              border:"1px solid rgba(255,255,255,0.1)",
                              flexShrink:0
                            }}/>
                          ))}
                        </div>
                        <div style={{fontSize:9,lineHeight:1.2,textAlign:"center",
                          color: isCur ? t.vars["--accent"] : "#888",
                          fontWeight: isCur ? 700 : 400}}>
                          {t.icon}{isCur?" ✓":""}<br/>{t.label}
                        </div>
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}

            {/* Accent colour strip */}
            <div style={{marginTop:6,borderTop:"1px solid #252525",paddingTop:8}}>
              <div style={{display:"flex",gap:2,height:6,borderRadius:3,overflow:"hidden",marginBottom:6}}>
                {Object.values(THEMES).map((t,i)=>(
                  <div key={i} title={t.label} style={{flex:1,background:t.vars["--accent"]}}/>
                ))}
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8,background:"#111",borderRadius:8,padding:"5px 10px"}}>
                <div style={{display:"flex",gap:3}}>
                  {(cur.preview||[]).map((c,i)=>(
                    <div key={i} style={{width:12,height:12,borderRadius:3,background:c,border:"1px solid rgba(255,255,255,0.1)"}}/>
                  ))}
                </div>
                <span style={{fontSize:11,color:"#666"}}>Active:</span>
                <span style={{fontSize:11,fontWeight:700,color:"var(--accent)"}}>{cur.icon} {cur.label}</span>
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

const uid = () => Math.random().toString(36).slice(2) + Date.now().toString(36);
const today = () => new Date().toISOString().slice(0, 10);

// Auto-format: UPPERCASE for names/firms/codes, lowercase for email
const _UPPER_KEYS = [
  // Person / entity names
  "name","firm","company","organisation","organization","party","supplier","contractor","client","builder","payee","paid to","received from","issued to","received by","prepared by","authorised by","verified by","checked by","approved by","operator","designation","father","witness","signatory","proprietor","partner","director","person",
  // Financial / tax codes
  "pan","gstin","gst","ifsc","tin","cin","udyam","msme","iec","bank","branch","account","acno","a/c",
  // Location
  "city","place","location","district","state","country","address","village","tehsil","taluka","taluk","mandal","pincode","pin code","post","police station","landmark",
  // Vehicle / transport / document numbers
  "vehicle","tempo","challan","dc /","delivery challan","lr no","lr number","invoice no","bill no","receipt no","waybill","eway","e-way",
];
const _LOWER_KEYS = ["email","mail","url","website","http","username","user name","login id","login"];
const autoFmt = (label, value) => {
  if (!value || typeof value !== "string") return value ?? "";
  const lb = (label || "").toLowerCase();
  if (_LOWER_KEYS.some(k => lb.includes(k))) return value; // username — as-is, no case change
  if (_UPPER_KEYS.some(k => lb.includes(k))) return value.toUpperCase();
  return value;
};
// Shorthand for raw <input> onChange — apply uppercase by field name/label
const UC = (v) => (v && typeof v === "string") ? v.toUpperCase() : v;

const MATERIAL_UNITS = ["Bags", "MT", "Cft", "Cum", "Sq.m", "Sqft", "Nos", "Ltrs", "KG", "RFT", "Ton", "Quintal"];

