// ─── getMaterialInfo: Central material lookup ─────────────────────────────────
// Har jagah use karo: Indent, GRN, IssueForm, PO — sab ek hi source se sync
const getMaterialInfo = (name, materialMaster, masterRates) => {
  if (!name) return { unit: "Nos", rate: 0, gst: 18, hsnCode: "" };
  const key = name.toLowerCase().trim();
  // 1. materialMaster (user-edited, highest priority)
  const mm = (materialMaster || []).find(m => (m.name || "").toLowerCase() === key);
  if (mm) return { unit: mm.unit || "Nos", rate: mm.rate || 0, gst: mm.gst || 18, hsnCode: mm.hsnCode || "", category: mm.category || "" };
  // 2. masterRates.materials (pre-built rate master)
  const mr = ((masterRates || {}).materials || []).find(m => (m.name || "").toLowerCase() === key);
  if (mr) return { unit: mr.unit || "Nos", rate: mr.avgRate || mr.rate || 0, gst: mr.gst || 18, hsnCode: mr.hsnCode || "", category: mr.category || "" };
  // 3. BUILTIN_CATEGORIES items (flat search)
  try {
    for (const cat of (BUILTIN_CATEGORIES || [])) {
      if (!cat) continue;
      for (const sub of (cat.subcategories || [])) {
        if (!sub) continue;
        for (const stage of (sub.substages || [])) {
          if (!stage) continue;
          const item = (stage.items || []).find(it => (it.name || "").toLowerCase() === key);
          if (item) return { unit: item.unit || "Nos", rate: item.rate || 0, gst: 18, hsnCode: "", category: cat.name };
        }
      }
    }
  } catch(e) { console.warn("getMaterialInfo BUILTIN loop:", e); }
  return { unit: "Nos", rate: 0, gst: 18, hsnCode: "" };
};
