const r3 = (v) => Math.round(v * 1000) / 1000;

function buildFloorItems(qtyMap, slabSqft) {
  const A = slabSqft || 0;
  const items = [];
  const add = (name, unit, ratio) => {
    if (!ratio) return;
    items.push({ name, unit, qty: A > 0 ? r3(ratio * A) : 0 });};
  if (qtyMap.excavation)      add("Excavation",            "Cu.m",  qtyMap.excavation);
  if (qtyMap.pcc)             add("PCC M10",               "Cu.m",  qtyMap.pcc);
  if (qtyMap.rcc !== undefined) add("RCC M25",             "Cu.m",  qtyMap.rcc);
  if (qtyMap.steel)           add("Steel Reinforcement",   "KG",    qtyMap.steel);
  if (qtyMap.formwork)        add("Shuttering / Formwork", "Sq.m",  qtyMap.formwork);
  if (qtyMap.brickwork)       add("230mm Brickwork",       "Cu.m",  qtyMap.brickwork);
  if (qtyMap.internalPlaster) add("Internal Plaster",      "Sq.m",  qtyMap.internalPlaster);
  if (qtyMap.externalPlaster) add("External Plaster",      "Sq.m",  qtyMap.externalPlaster);
  if (qtyMap.flooring)        add("Tile Flooring",         "Sq.m",  qtyMap.flooring);
  if (qtyMap.tileDado)        add("Tile Dado",             "Sq.m",  qtyMap.tileDado);
  if (qtyMap.doors)           add("Door Frames & Shutters","Sq.m",  qtyMap.doors);
  if (qtyMap.windows)         add("Window Frames & Glass", "Sq.m",  qtyMap.windows);
  if (qtyMap.plumbing)        add("Plumbing Pipes",        "Rmt",   qtyMap.plumbing);
  if (qtyMap.electrical)      add("Electrical Conduit & Wiring", "Rmt", qtyMap.electrical);
  if (qtyMap.paint)           add("Paint + Putty",         "Sq.m",  qtyMap.paint);
  if (qtyMap.waterproofing)   add("Waterproofing",         "Sq.m",  qtyMap.waterproofing);
  if (qtyMap.floorFinish)     add("Floor Finish",          "Sq.m",  qtyMap.floorFinish);
  if (qtyMap.drainagePipe)    add("Drainage Pipe",         "Rmt",   qtyMap.drainagePipe);
  if (qtyMap.parapetBrickwork) add("Parapet Brickwork",   "Cu.m",  qtyMap.parapetBrickwork);
  if (qtyMap.terraceTile)     add("Terrace Tile",          "Sq.m",  qtyMap.terraceTile);
  if (qtyMap.plaster)         add("Plaster",               "Sq.m",  qtyMap.plaster);
  return items;
}

function generateFloorSubstages(floorCount, hasBasement = false, floorAreas = {}) {
  const FL = (i) => i === 0 ? "GF" : i <= 10 ? ["1F","2F","3F","4F","5F","6F","7F","8F","9F","10F"][i-1] : `${i}F`;
  const A = (key, idx) => {
    if (key === "B")       return floorAreas.basement || 0;
    if (key === "GF")      return floorAreas.ground   || 0;
    if (key === "T")       return floorAreas.terrace  || floorAreas.ground || 0;
    return (floorAreas.floors || [])[idx] || floorAreas.ground || 0;};
  const stages = [];
  // ── 1. SITE PREPARATION ────────────────────────────────────────────
  stages.push({ name: "Site Preparation", items: [
    { name: "Soil Testing",            unit: "Nos",  qty: 1 },
    { name: "Site Clearing & Layout",  unit: "Sqft", qty: A("GF") },
    { name: "Borehole / Level Setting",unit: "Nos",  qty: 4 },]});
  // ── 2. FOUNDATION ─────────────────────────────────────────────────
  if (hasBasement) {
    const bA = A("B");
    const bQ = QTY_WITH_BASEMENT.basement;
    stages.push({ name: "Excavation", items: [
      { name: "Excavation",         unit: "Cu.m", qty: r3(bQ.excavation * bA) },
      { name: "Dewatering",         unit: "LS",   qty: 1 },
      { name: "Earth Disposal",     unit: "Cu.m", qty: r3(bQ.excavation * 0.6 * bA) },]});
    stages.push({ name: "Foundation PCC & Raft", items: [
      { name: "PCC M10",            unit: "Cu.m", qty: r3(bQ.pcc * bA) },
      { name: "RCC M25",            unit: "Cu.m", qty: r3(bQ.rcc * 0.45 * bA) },
      { name: "Steel Reinforcement",unit: "KG",   qty: r3(bQ.steel * 0.45 * bA) },
      { name: "Shuttering",         unit: "Sq.m", qty: r3(bQ.formwork * 0.3 * bA) },]});
    stages.push({ name: "Basement Retaining Wall", items: [
      { name: "RCC M25",            unit: "Cu.m", qty: r3(bQ.rcc * 0.55 * bA) },
      { name: "Steel Reinforcement",unit: "KG",   qty: r3(bQ.steel * 0.55 * bA) },
      { name: "Shuttering",         unit: "Sq.m", qty: r3(bQ.formwork * 0.7 * bA) },
      { name: "Waterproofing (Ext.)",unit:"Sq.m", qty: r3(bQ.waterproofing * bA) },]});
    stages.push({ name: "Basement Slab", items: [
      { name: "Shuttering / Centering",unit:"Sq.m",qty: r3(bQ.formwork * bA) },
      { name: "RCC M25",            unit: "Cu.m", qty: r3(0.012 * bA) },
      { name: "Steel Reinforcement",unit: "KG",   qty: r3(1.5 * bA) },
      { name: "Curing",             unit: "Days", qty: 14 },]});
    stages.push({ name: "Basement Finishing", items: [
      { name: "Internal Plaster",   unit: "Sq.m", qty: r3(bQ.internalPlaster * bA) },
      { name: "Floor Finish",       unit: "Sq.m", qty: r3(bQ.floorFinish * bA) },
      { name: "Waterproofing (Int.)",unit:"Sq.m", qty: r3(bQ.waterproofing * bA) },
      { name: "Drainage Pipe",      unit: "Rmt",  qty: r3(bQ.drainagePipe * bA) },
      { name: "Electrical Conduit", unit: "Rmt",  qty: r3(bQ.electrical * bA) },]});
  } else {
    const gA = A("GF");
    const q  = QTY_NO_BASEMENT.ground;
    stages.push({ name: "Excavation", items: [
      { name: "Excavation",         unit: "Cu.m", qty: r3(q.excavation * gA) },
      { name: "Anti-termite Treatment",unit:"Sqm",qty: r3(gA * 0.093) },
      { name: "Earth Disposal",     unit: "Cu.m", qty: r3(q.excavation * 0.5 * gA) },]});
    stages.push({ name: "Foundation", items: [
      { name: "PCC M10",            unit: "Cu.m", qty: r3(q.pcc * gA) },
      { name: "RCC M25",            unit: "Cu.m", qty: r3(q.rcc * 0.4 * gA) },
      { name: "Steel Reinforcement",unit: "KG",   qty: r3(q.steel * 0.3 * gA) },
      { name: "Shuttering",         unit: "Sq.m", qty: r3(q.formwork * 0.2 * gA) },
      { name: "Backfilling",        unit: "Cu.m", qty: r3(q.excavation * 0.4 * gA) },]});}
  // ── 3. PLINTH BEAM ────────────────────────────────────────────────
  {
    const gA = A("GF");
    stages.push({ name: "Plinth Beam", items: [
      { name: "Shuttering",          unit: "Sq.m", qty: r3(0.04 * gA) },
      { name: "Steel Reinforcement", unit: "KG",   qty: r3(0.8 * gA) },
      { name: "RCC M25",             unit: "Cu.m", qty: r3(0.006 * gA) },
      { name: "Curing",              unit: "Days", qty: 7 },]});}
  // ── 4. GROUND FLOOR — Column → Slab → Brickwork → Plaster → Finishing ──
  {
    const gA  = A("GF");
    const q   = hasBasement ? QTY_WITH_BASEMENT.ground : QTY_NO_BASEMENT.ground;
    stages.push({ name: "GF Column", items: [
      { name: "Shuttering",          unit: "Sq.m", qty: r3(q.formwork * 0.35 * gA) },
      { name: "Steel Reinforcement", unit: "KG",   qty: r3(q.steel    * 0.35 * gA) },
      { name: "RCC M25",             unit: "Cu.m", qty: r3(q.rcc      * 0.35 * gA) },
      { name: "Curing",              unit: "Days", qty: 7 },]});
    stages.push({ name: "GF Slab", items: [
      { name: "Shuttering / Centering",unit:"Sq.m",qty: r3(q.formwork * 0.65 * gA) },
      { name: "Steel Reinforcement", unit: "KG",   qty: r3(q.steel    * 0.65 * gA) },
      { name: "RCC M25",             unit: "Cu.m", qty: r3(q.rcc      * 0.65 * gA) },
      { name: "Curing",              unit: "Days", qty: 14 },]});
    stages.push({ name: "GF Brickwork", items: [
      { name: "230mm Brickwork",     unit: "Cu.m", qty: r3(q.brickwork * 0.75 * gA) },
      { name: "115mm Partition",     unit: "Cu.m", qty: r3(q.brickwork * 0.25 * gA) },]});
    stages.push({ name: "GF Plaster", items: [
      { name: "Internal Plaster 12mm",unit:"Sq.m", qty: r3(q.internalPlaster * gA) },
      { name: "Ceiling Plaster",     unit: "Sq.m", qty: r3(0.05 * gA) },
      { name: "External Plaster 20mm",unit:"Sq.m", qty: r3(q.externalPlaster * gA) },]});
    stages.push({ name: "GF Flooring & Finishing", items: [
      { name: "Tile Flooring",       unit: "Sq.m", qty: r3(q.flooring    * gA) },
      { name: "Door Frames & Shutters",unit:"Nos", qty: r3(q.doors       * gA) },
      { name: "Window Frames",       unit: "Nos",  qty: r3(q.windows     * gA) },
      { name: "Plumbing Pipes",      unit: "Rmt",  qty: r3(q.plumbing    * gA) },
      { name: "Electrical Conduit",  unit: "Rmt",  qty: r3(q.electrical  * gA) },
      { name: "Paint + Putty",       unit: "Sq.m", qty: r3(q.paint       * gA) },]});}
  // ── 5. UPPER FLOORS (1st, 2nd ... nth) ────────────────────────────
  for (let f = 1; f <= floorCount; f++) {
    const fl  = FL(f);
    const fA  = A("floor", f - 1);  // floorAreas.floors[0]=1F, [1]=2F ...
    const isTop = (f === floorCount);
    const q   = isTop && !hasBasement
      ? QTY_NO_BASEMENT.topFloor
      : (hasBasement ? QTY_WITH_BASEMENT.typical : QTY_NO_BASEMENT.typical);
    stages.push({ name: `${fl} Column`, items: [
      { name: "Shuttering",          unit: "Sq.m", qty: r3(q.formwork * 0.35 * fA) },
      { name: "Steel Reinforcement", unit: "KG",   qty: r3(q.steel    * 0.35 * fA) },
      { name: "RCC M25",             unit: "Cu.m", qty: r3(q.rcc      * 0.35 * fA) },
      { name: "Curing",              unit: "Days", qty: 7 },]});
    stages.push({ name: `${fl} Slab`, items: [
      { name: "Shuttering / Centering",unit:"Sq.m",qty: r3(q.formwork * 0.65 * fA) },
      { name: "Steel Reinforcement", unit: "KG",   qty: r3(q.steel    * 0.65 * fA) },
      { name: "RCC M25",             unit: "Cu.m", qty: r3(q.rcc      * 0.65 * fA) },
      { name: "Curing",              unit: "Days", qty: 14 },]});
    stages.push({ name: `${fl} Brickwork`, items: [
      { name: "230mm Brickwork",     unit: "Cu.m", qty: r3(q.brickwork * 0.75 * fA) },
      { name: "115mm Partition",     unit: "Cu.m", qty: r3(q.brickwork * 0.25 * fA) },]});
    stages.push({ name: `${fl} Plaster`, items: [
      { name: "Internal Plaster 12mm",unit:"Sq.m", qty: r3(q.internalPlaster * fA) },
      { name: "Ceiling Plaster",     unit: "Sq.m", qty: r3(0.05 * fA) },
      { name: "External Plaster 20mm",unit:"Sq.m", qty: r3(q.externalPlaster * fA) },]});
    stages.push({ name: `${fl} Flooring & Finishing`, items: [
      { name: "Tile Flooring",       unit: "Sq.m", qty: r3(q.flooring    * fA) },
      ...(q.tileDado ? [{ name: "Tile Dado",unit:"Sq.m",qty: r3(q.tileDado * fA) }] : []),
      { name: "Door Frames & Shutters",unit:"Nos", qty: r3(q.doors       * fA) },
      { name: "Window Frames",       unit: "Nos",  qty: r3(q.windows     * fA) },
      { name: "Plumbing Pipes",      unit: "Rmt",  qty: r3(q.plumbing    * fA) },
      { name: "Electrical Conduit",  unit: "Rmt",  qty: r3(q.electrical  * fA) },
      { name: "Paint + Putty",       unit: "Sq.m", qty: r3(q.paint       * fA) },]});}
  // ── 6. TERRACE SLAB ───────────────────────────────────────────────
  {
    const tA = A("T");
    const tQ = hasBasement ? QTY_WITH_BASEMENT.terrace
      : { rcc:0.021, steel:3.2, formwork:0.38, parapetBrickwork:0.0043, waterproofing:0.127, terraceTile:0.116, plaster:0.058 };
    stages.push({ name: "Terrace Slab", items: [
      { name: "Shuttering / Centering",unit:"Sq.m",qty: r3(tQ.formwork * tA) },
      { name: "Steel Reinforcement", unit: "KG",   qty: r3(tQ.steel * tA) },
      { name: "RCC M25",             unit: "Cu.m", qty: r3(tQ.rcc * tA) },
      { name: "Curing",              unit: "Days", qty: 14 },]});
    stages.push({ name: "Terrace Waterproofing & Finishing", items: [
      { name: "Parapet Brickwork",   unit: "Cu.m", qty: r3(tQ.parapetBrickwork * tA) },
      { name: "Waterproofing Membrane",unit:"Sq.m",qty: r3(tQ.waterproofing * tA) },
      { name: "Terrace Tile / IPS",  unit: "Sq.m", qty: r3(tQ.terraceTile * tA) },
      { name: "Plaster",             unit: "Sq.m", qty: r3(tQ.plaster * tA) },]});}
  // ── 7. COMMON FINISHING (whole building) ──────────────────────────
  stages.push({ name: "External Plaster & Elevation", items: [
    { name: "External Plaster 20mm", unit: "Sq.m", qty: 0 },
    { name: "Elevation Cladding / Texture", unit: "Sq.m", qty: 0 },]});
  stages.push({ name: "Doors & Windows (Final)", items: [
    { name: "Door Polish / PU Coat", unit: "Nos", qty: 0 },
    { name: "Window Grills / Safety Net", unit: "Nos", qty: 0 },
    { name: "Main Gate / Staircase Railing", unit: "Nos", qty: 0 },]});
  stages.push({ name: "Electrical Work", items: [
    { name: "Main Panel & DB Boards", unit: "Nos", qty: floorCount + 1 },
    { name: "Points (Fan/Light/AC)", unit: "Nos", qty: 0 },
    { name: "Lifts / Common Lighting", unit: "LS", qty: 1 },]});
  stages.push({ name: "Plumbing & Sanitary", items: [
    { name: "Overhead / UG Tank",   unit: "Nos", qty: 1 },
    { name: "Sanitary Fittings",    unit: "Nos", qty: 0 },
    { name: "Solar / Pump",         unit: "Nos", qty: 1 },]});
  stages.push({ name: "Painting (Final)", items: [
    { name: "Putty + Primer",             unit: "Sq.m", qty: 0 },
    { name: "Interior Paint (2 coats)",   unit: "Sq.m", qty: 0 },
    { name: "Exterior Paint / Texture",   unit: "Sq.m", qty: 0 },]});
  return stages;
}

function resolveSubstages(cat, subcat, floorAreas = {}) {
  if (subcat.substages) return subcat.substages;
  return generateFloorSubstages(subcat.floorCount || 1, subcat.hasBasement || false, floorAreas);
}

function buildSubstagesFromTemplate(stageTemplates) {
  return stageTemplates.map((ss) => ({
    id: uid(),
    name: ss.name,
    status: "pending",
    startDate: "",
    endDate: "",
    amount: 0,
    items: (ss.items || []).map((it) => ({
      id: uid(),
      name: it.name,
      unit: it.unit || "Nos",
      qty: it.qty || 0,
      materials: [],
      manpower: [],
      resources: [],
      amount: 0,
      status: "pending",})),}));}
