// ─── ITEM MASTER DATA ────────────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════════

function applyApprovedProgress(entry, state) {
  const patch = {};
  const proj = (state.projects || []).find(p => p.id === entry.projectId);
  if (!proj) return patch;
  const itemMaster  = state.itemMaster  || ITEM_MASTER_DEFAULTS;
  const masterRates = state.masterRates || DEFAULT_MASTER_RATES;
  const manpowerMaster = state.manpowerMaster || [];
  const musterRoll  = [...(state.musterRoll  || [])];
  const inventory   = [...(state.inventory   || [])];
  const workBills   = [...(state.workBills   || [])];
  const clientBills = [...(state.clientBills || [])];
  const workOrders  = state.workOrders  || [];
  const agreements  = state.agreements  || [];
  const allProgress = state.projectProgress || [];
  // ── Helper: get labour rate from master ─────────────────────────────────
  const getLabourRate = (type) => {
    const key = type?.toLowerCase().replace(/\s+/g,"_").replace("bar_bender","barbinder");
    return masterRates.manpower?.find(m => m.key === key || m.label?.toLowerCase() === type?.toLowerCase())?.rate || 500;
  };
  // ── Helper: get material rate from master ───────────────────────────────
  const getMatRate = (name) => {
    return masterRates.materials?.find(m =>
      m.name?.toLowerCase().includes(name?.toLowerCase().split(" ")[0])
    )?.rate || 0;};
  // ── 1. MUSTER ROLL → PROGRESS: us date ka attendance read karke
  const musterAtt = musterRoll.filter(m =>
    m.type === "attendance" &&
    m.date === entry.date &&
    m.projectId === entry.projectId &&
    m.status !== "A");
  const musterTypeMap = {};
  musterAtt.forEach(a => {
    const t = a.labourType || "Other";
    if (!musterTypeMap[t]) musterTypeMap[t] = { type: t, count: 0, names: [], totalAmt: 0 };
    musterTypeMap[t].count++;
    musterTypeMap[t].names.push(a.labourName || t);
    musterTypeMap[t].totalAmt += (a.amount || 0)
    }
    );
  const companyLabourFromMuster = Object.values(musterTypeMap);
  // ── 2. ITEM PROGRESS — resolve units + fill defaults if qty missing ──────
  let itemProgressResolved = [...(entry.itemProgress || [])];
  itemProgressResolved = itemProgressResolved.map(ip => {
    if (!ip.qty || ip.qty === 0) return ip; // skip zero qty items
    const im = itemMaster.find(m =>
      m.id === ip.imId || m.id === ip.itemMasterId ||
      m.name?.toLowerCase() === ip.itemName?.toLowerCase());
    return { ...ip, _im: im };
  }).filter(ip => ip.qty > 0);
  // ── 3. MATERIAL CONSUMPTION — auto-fill if not provided ─────────────────
  let matConsumption = [...(entry.materialConsumption || [])];
  if (matConsumption.filter(m => m.qty > 0).length === 0) {
    const matMap = {};
    itemProgressResolved.forEach(ip => {
      const im = ip._im;
      if (!im) return;
      (im.materials || []).forEach(mat => {
        const k = mat.name;
        if (!matMap[k]) matMap[k] = { material: mat.name, unit: mat.unit, qty: 0, auto: true };
        matMap[k].qty = Math.round((matMap[k].qty + mat.qty * ip.qty) * 1000) / 1000;})
        }
        );
    matConsumption = Object.values(matMap);}
  // ── 4. MACHINERY USAGE — auto-fill if not provided ──────────────────────
  let machineryUsage = [...(entry.machineryUsage || [])];
  if (machineryUsage.filter(m => m.qty > 0).length === 0) {
    const machMap = {};
    itemProgressResolved.forEach(ip => {
      const im = ip._im;
      if (!im) return;
      (im.machinery || []).forEach(mach => {
        const k = mach.name;
        if (!machMap[k]) machMap[k] = { machine: mach.name, unit: mach.unit, qty: 0, auto: true };
        machMap[k].qty = Math.round((machMap[k].qty + mach.qty * ip.qty) * 1000) / 1000;})
        }
        );
    machineryUsage = Object.values(machMap);}
  // ── 5. INVENTORY — deduct consumed materials ─────────────────────────────
  let inv = [...(state.inventory || [])];
  matConsumption.filter(m => m.qty > 0).forEach(mat => {
    inv.push({
      id: uid(),
      name: mat.material,
      qty: -mat.qty,
      unit: mat.unit,
      date: entry.date,
      project: proj.name,
      projectId: entry.projectId,
      source: "Progress Consumption",
      progressEntryId: entry.id,
      rate: getMatRate(mat.material),})
      }
      );
  patch.inventory = inv;
  // ── 6. ACCOUNTS TRANSACTIONS ─────────────────────────────────────────────
  const newTxns = [];
  const musterLabourCost = musterAtt.reduce((s, a) => s + (a.amount || 0), 0);
  const contractorLabourCost = (entry.contractorLabour || [])
    .reduce((s, cl) => s + getLabourRate(cl.type) * (cl.count || 0), 0);
  const labourCost = (musterLabourCost > 0 ? musterLabourCost : 0) + contractorLabourCost;
  if (labourCost > 0) {
    newTxns.push({
      id: uid(), type: "out", category: "Manpower",
      date: entry.date,
      description: `Labour — ${entry.stageName || "Progress"} (${entry.date}) [MusterRoll: ${musterAtt.length} nos]`,
      amount: labourCost,
      source: "progress_entry", progressEntryId: entry.id,});}
  const materialCost = matConsumption.filter(m => m.qty > 0).reduce((s, m) => {
    return s + m.qty * getMatRate(m.material);
  }, 0);
  if (materialCost > 0) {
    newTxns.push({
      id: uid(), type: "out", category: "Material",
      date: entry.date,
      description: `Material — ${entry.stageName || "Progress"} (${entry.date}) [auto from progress]`,
      amount: materialCost,
      source: "progress_entry", progressEntryId: entry.id,});}
  const machineCost = machineryUsage.filter(m => m.qty > 0).reduce((s, m) => {
    const rate = masterRates.materials?.find(r =>
      r.name?.toLowerCase().includes(m.machine?.toLowerCase().split(" ")[0])
    )?.rate || 0;
    return s + m.qty * rate;
  }, 0);
  if (newTxns.length > 0) {
    const updatedProj = {
      ...proj,
      transactions: [...(proj.transactions || []), ...newTxns],};
    patch.projects = (state.projects || []).map(p =>
      p.id === proj.id ? updatedProj : p);}
  // ── 7. STAGE COMPLETION — update substages ───────────────────────────────
  if (entry.stageId) {
    const substages = proj.substages || [];
    const stageIsCompleted = entry._stageComplete || entry.stageCompletedInEntry;
    if (stageIsCompleted) {
      const curIdx  = substages.findIndex(ss => ss.id === entry.stageId);
      const nextSS  = substages.slice(curIdx + 1).find(ss => ss.status !== "done");
      const updated = substages.map(ss => {
        if (ss.id === entry.stageId) return { ...ss, status: "done", completedDate: entry.date };
        if (nextSS && ss.id === nextSS.id) return { ...ss, status: "ongoing" };
        return ss;});
      const projToUpdate = patch.projects
        ? patch.projects.find(p => p.id === proj.id)
        : proj;
      const updatedWithStages = { ...projToUpdate, substages: updated };
      patch.projects = (patch.projects || state.projects || []).map(p =>
        p.id === proj.id ? updatedWithStages : p)}
}
  // ── 8. CONTRACTOR BILL — auto-generate if WO linked to this project ──────
  const projectWOs = workOrders.filter(wo =>
    wo.projectId === entry.projectId && wo.status === "active");
  projectWOs.forEach(wo => {
    const existingBill = workBills.find(b =>
      b.woId === wo.id && b.stageId === entry.stageId &&
      b.source === "progress_auto" && b.status !== "rejected");
    if (existingBill) return;
    if (!entry.stageId) return;
    const billItems = itemProgressResolved.map(ip => ({
      id: uid(), liId: ip.itemId, desc: ip.itemName, unit: ip.unit,
      aggQty: ip.aggQty || 0, progressQty: ip.qty, qty: ip.qty,
      rate: (wo.lineItems || []).find(li => li.id === ip.itemId || li.name === ip.itemName)?.rate || ip.rate || 0,
      releasePct: 100,
    })).filter(bi => bi.qty > 0 && bi.rate > 0);
    const grossFromItems = billItems.reduce((s, bi) => s + bi.qty * bi.rate, 0);
    // Fallback: use WO stage-wise breakdown or proportional WO amount
    let grossAmount = grossFromItems;
    if (grossAmount <= 0 && wo.amount > 0) {
      // Try to find matching payment term in WO
      const woStage = (wo.paymentTerms || []).find(pt =>
        pt.stage?.toLowerCase().includes(entry.stageName?.toLowerCase()) ||
        entry.stageName?.toLowerCase().includes(pt.stage?.toLowerCase())
      );
      if (woStage) {
        grossAmount = Math.round(wo.amount * (woStage.pct || 0) / 100);
      } else {
        // Proportional: WO amount / total substages
        const projSubstages = proj.substages?.length || 1;
        grossAmount = Math.round(wo.amount / projSubstages);
      }
    }
    if (grossAmount <= 0) return;
    const retentionPct = 5;
    const tdsPct = 2;
    const retention = Math.round(grossAmount * retentionPct / 100);
    const tds = Math.round(grossAmount * tdsPct / 100);
    const netAmount = grossAmount - retention - tds;
    workBills.push({
      id: uid(),
      billNo: `RB-${Date.now().toString().slice(-6)}`,
      date: entry.date,
      contractorId: wo.contractorId,
      contractorName: wo.contractorName,
      woId: wo.id, woNo: wo.woNo,
      projectId: entry.projectId, projectName: proj.name,
      stageId: entry.stageId, stage: entry.stageName,
      billType: "Running Bill",
      billItems: billItems.length > 0 ? billItems : [{
        id: uid(), desc: entry.stageName, unit: "LS", qty: 1,
        rate: grossAmount, releasePct: 100,
      }],
      grossAmount, retention, retentionPct,
      tds, tdsPct, advance: 0, otherDeduc: 0,
      netAmount,
      status: "pending",
      source: "progress_auto",
      progressEntryId: entry.id,
      note: `Auto-generated from approved progress entry dated ${entry.date}`,
    });
  });
  if (workBills.length > (state.workBills || []).length) {
    patch.workBills = workBills;}
  // ── 9. CLIENT BILL — auto-generate if agreement linked ───────────────────
  const clientAgreements = agreements.filter(ag =>
    ag.type === "client" && ag.projectId === entry.projectId && ag.status !== "cancelled");
  clientAgreements.forEach(ag => {
    const existingBill = clientBills.find(b =>
      b.agId === ag.id && b.stageId === entry.stageId &&
      b.source === "progress_auto" && b.status !== "rejected");
    if (existingBill) return;
    if (!entry.stageId) return;
    const payStage = (ag.paymentTerms || []).find(pt =>
      pt.stage?.toLowerCase().includes(entry.stageName?.toLowerCase()) ||
      entry.stageName?.toLowerCase().includes(pt.stage?.toLowerCase()));
    const billItems = itemProgressResolved.map(ip => ({
      id: uid(), liId: ip.itemId, desc: ip.itemName, unit: ip.unit,
      aggQty: ip.aggQty || 0, progressQty: ip.qty, qty: ip.qty,
      rate: (ag.lineItems || []).find(li => li.id === ip.itemId || li.name === ip.itemName)?.rate || ip.rate || 0,
      releasePct: 100,
    })).filter(bi => bi.qty > 0 && bi.rate > 0);
    const grossFromItems  = billItems.reduce((s, bi) => s + bi.qty * bi.rate, 0);
    const grossFromStage  = payStage ? Math.round((ag.value || 0) * payStage.pct / 100) : 0;
    const grossAmount     = grossFromItems > 0 ? grossFromItems : grossFromStage;
    if (grossAmount <= 0) return;
    const gstPct = 18;
    const gst = Math.round(grossAmount * gstPct / 100);
    const retentionPct = 5;
    const retention = Math.round(grossAmount * retentionPct / 100);
    const tdsPct = 2;
    const tds = Math.round(grossAmount * tdsPct / 100);
    const netAmount = grossAmount + gst - retention - tds;
    clientBills.push({
      id: uid(),
      billNo: `CB-${Date.now().toString().slice(-6)}`,
      date: entry.date,
      clientId: ag.partyId,
      clientName: ag.partyName,
      agId: ag.id, agNo: ag.agNo,
      projectId: entry.projectId, projectName: proj.name,
      stageId: entry.stageId, stage: entry.stageName,
      paymentStageId: payStage?.id || "",
      billType: "Running Bill",
      billItems: billItems.length > 0 ? billItems : [],
      grossAmount, gst, gstPct, retention, retentionPct,
      tds, tdsPct, advance: 0, otherDeduc: 0,
      netAmount,
      status: "draft",
      source: "progress_auto",
      progressEntryId: entry.id,
      note: `Auto-generated from approved progress entry dated ${entry.date}`,})
      }
    );
  if (clientBills.length > (state.clientBills || []).length) {
    patch.clientBills = clientBills;}
  // ── 10. Update progress entry itself — mark approved + pull labour from muster ──
  patch.projectProgress = allProgress.map(e =>
    e.id === entry.id ? {
      ...e,
      status: "approved",
      approvedAt: new Date().toISOString(),
      materialConsumption: matConsumption,
      machineryUsage: machineryUsage,
      companyLabour: companyLabourFromMuster.length > 0
        ? companyLabourFromMuster
        : (e.companyLabour || []),
      musterLabourTotal: musterAtt.length,
      musterLabourCost: musterAtt.reduce((s,a)=>s+(a.amount||0),0),
    } : e);
  return patch;
}
