// ════════════════════════════════════════════════════════════════════════════
// MESSENGER + TASK SCHEDULER + NOTIFICATION SYSTEM
// ════════════════════════════════════════════════════════════════════════════

// ── Notification helpers ──────────────────────────────────────────────────────
function getNotifications(state) {
  const me = state.currentUser || {};
  const myId = me.id;
  const notifs = [];

  // 1. Unread messages
  (state.messages || []).forEach(msg => {
    if ((msg.toId === myId || (msg.toIds||[]).includes(myId)) && !msg.readBy?.includes(myId)) {
      notifs.push({
        id: `msg-${msg.id}`,
        type: "message",
        icon: "💬",
        title: `${msg.fromName}: ${(msg.text||"").slice(0,50)}`,
        time: msg.sentAt,
        action: "messenger",
        data: msg,
      });
    }
  });

  // 2. Pending tasks assigned to me
  (state.tasks || []).forEach(task => {
    if (task.assignedToId === myId && task.status === "pending") {
      notifs.push({
        id: `task-${task.id}`,
        type: "task",
        icon: "📋",
        title: `Task: ${task.title}`,
        sub: `From: ${task.assignedByName} | Due: ${task.dueDate||"—"}`,
        time: task.createdAt,
        action: "tasks",
        data: task,
      });
    }
  });

  // 3. Pending approvals (for users with approvalRights)
  const approvalRights = me.approvalRights || [];

  // indent approvals
  if (approvalRights.includes("indent_approve") || me.isMaster || EQUIP_SENIOR_ROLES.includes(me.role)) {
    (state.indents||[]).filter(i=>i.status==="pending"||i.status==="submitted").forEach(indent=>{
      notifs.push({
        id: `indent-${indent.id}`,
        type: "approval",
        icon: "📦",
        title: `Indent Approval: ${indent.item||indent.title||"Item"}`,
        sub: `By: ${indent.requestedBy||"—"} | Qty: ${indent.qty} ${indent.unit||""}`,
        time: indent.createdAt||indent.date,
        action: "indent",
        data: indent,
        approveKey: "indents",
      });
    });
  }

  // Field MB approvals
  if (approvalRights.includes("field_mb_approve") || me.isMaster || EQUIP_SENIOR_ROLES.includes(me.role)) {
    (state.fieldMBEntries||[]).filter(e=>e.status==="submitted").forEach(entry=>{
      notifs.push({
        id: `fmb-${entry.id}`,
        type: "approval",
        icon: "📝",
        title: `Field Entry Approval: ${entry.stageName||"Entry"}`,
        sub: `By: ${entry.submittedBy} | ${entry.date}`,
        time: entry.submittedAt,
        action: "fieldmb",
        data: entry,
        approveKey: "fieldMBEntries",
      });
    });
  }

  // Equipment demand suspended users alert
  if (EQUIP_SENIOR_ROLES.includes(me.role) || me.isMaster) {
    (state.equipSuspended||[]).filter(s=>s.active && !s.notifReadBy?.includes(myId)).forEach(s=>{
      notifs.push({
        id: `susp-${s.userId}`,
        type: "alert",
        icon: "⛔",
        title: `Equipment Demand Suspended: ${s.userName}`,
        sub: s.reason,
        time: s.suspendedAt,
        action: "equipdemand",
        data: s,
      });
    });
  }

  return notifs.sort((a,b) => (b.time||"").localeCompare(a.time||"")).slice(0, 50);
}

// ── NOTIFICATION BELL (in Header) ────────────────────────────────────────────
function NotificationBell({ state, upd, setTab }) {
  const [open, setOpen] = useState(false);
  const me = state.currentUser || {};
  const notifs = getNotifications(state);
  const unread = notifs.length;

  const handleAction = (notif) => {
    // Mark field MB as approved (one-click)
    if (notif.type === "approval" && notif.approveKey === "fieldMBEntries") {
      const entry = notif.data;
      const progressEntry = {
        id: uid(), projectId: entry.projectId, projectName: entry.projectName,
        date: entry.date, stageId: entry.stageId, stageName: entry.stageName,
        items: entry.items||[], materialConsumption: entry.materials||[],
        labourDetails: entry.labours||[], status:"approved", source:"field_mb",
        fieldMBId: entry.id, submittedBy: entry.submittedBy,
        approvedBy: me.name, approvedAt: new Date().toISOString(),
      };
      upd({
        fieldMBEntries: (state.fieldMBEntries||[]).map(e =>
          e.id===entry.id ? {...e, status:"approved", approvedBy:me.name, approvedAt:new Date().toISOString()} : e
        ),
        projectProgress: [...(state.projectProgress||[]), progressEntry],
      });
    }
    // Navigate to module
    if (notif.action) setTab(notif.action);
    setOpen(false);
  };

  const markMsgRead = (msgId) => {
    upd({
      messages: (state.messages||[]).map(m =>
        m.id === msgId
          ? { ...m, readBy: [...new Set([...(m.readBy||[]), me.id])] }
          : m
      )
    });
  };

  return (
    <div style={{position:"relative",zIndex:99990,flexShrink:0}}>
      <button
        onClick={()=>setOpen(!open)}
        style={{
          position:"relative",
          background:"var(--bg-input)",border:"1px solid var(--border)",
          borderRadius:6,padding:"5px 8px",fontSize:16,cursor:"pointer",
          color:"var(--text-main)",lineHeight:1,
        }}>
        🔔
        {unread > 0 && (
          <span style={{
            position:"absolute",top:-4,right:-4,
            background:"#e74c3c",color:"#fff",
            borderRadius:"50%",width:16,height:16,
            fontSize:9,fontWeight:900,lineHeight:"16px",
            display:"flex",alignItems:"center",justifyContent:"center",
          }}>{unread > 9 ? "9+" : unread}</span>
        )}
      </button>

      {open && (
        <>
          <div onClick={()=>setOpen(false)}
            style={{position:"fixed",inset:0,zIndex:99989}}/>
          <div style={{
            position:"fixed",right:8,top:52,
            background:"var(--bg-card)",
            border:"1px solid var(--border)",borderRadius:10,
            padding:0,width:320,maxHeight:"70vh",
            overflowY:"auto",zIndex:99990,
            boxShadow:"0 6px 24px rgba(0,0,0,0.6)",
          }}>
            <div style={{padding:"10px 14px",borderBottom:"1px solid var(--border)",
              fontWeight:700,fontSize:13,color:"var(--accent)",
              display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span>🔔 Notifications {unread > 0 && `(${unread})`}</span>
              <div style={{display:"flex",gap:6}}>
                <button style={{...S.btnSm,fontSize:10,padding:"2px 8px"}}
                  onClick={()=>{setTab("messenger");setOpen(false);}}>
                  💬 Chat
                </button>
                <button style={{...S.btnSm,fontSize:10,padding:"2px 8px"}}
                  onClick={()=>{setTab("tasks");setOpen(false);}}>
                  📋 Tasks
                </button>
              </div>
            </div>

            {notifs.length === 0 ? (
              <div style={{padding:20,textAlign:"center",color:"var(--text-dim)",fontSize:12}}>
                ✓ Koi notification nahi
              </div>
            ) : notifs.map(n => (
              <div key={n.id} style={{
                padding:"10px 14px",
                borderBottom:"1px solid var(--border)",
                cursor:"pointer",
                background: n.type==="alert" ? "#e74c3c08" :
                            n.type==="approval" ? "#f39c1208" : "transparent",
              }}
                onClick={() => {
                  if (n.type==="message") markMsgRead(n.data.id);
                  handleAction(n);
                }}>
                <div style={{display:"flex",justifyContent:"space-between",
                  gap:8,alignItems:"flex-start"}}>
                  <div style={{flex:1}}>
                    <div style={{fontSize:13,fontWeight:600}}>
                      {n.icon} {n.title}
                    </div>
                    {n.sub && (
                      <div style={{fontSize:11,color:"var(--text-dim)",marginTop:2}}>
                        {n.sub}
                      </div>
                    )}
                    <div style={{fontSize:10,color:"var(--text-dim)",marginTop:2}}>
                      {n.time ? new Date(n.time).toLocaleString("en-IN",{hour:"2-digit",minute:"2-digit",day:"2-digit",month:"short"}) : ""}
                    </div>
                  </div>
                  {n.type==="approval" && n.approveKey==="fieldMBEntries" && (
                    <button
                      style={{...S.btnPrimary,background:"#27ae60",
                        padding:"4px 10px",fontSize:11,flexShrink:0,whiteSpace:"nowrap"}}
                      onClick={e=>{e.stopPropagation();handleAction(n);}}>
                      ✓ Approve
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// MESSENGER MODULE
// ════════════════════════════════════════════════════════════════════════════
function MessengerModule({ state, upd }) {
  const me = state.currentUser || {};
  const users = (state.users||[]).filter(u=>u.id!==me.id);
  const messages = state.messages || [];

  const [selUser, setSelUser] = useState(null);
  const [text, setText] = useState("");
  const msgEndRef = useRef(null);

  // Get conversation between me and selUser
  const convo = selUser ? messages.filter(m =>
    (m.fromId===me.id && m.toId===selUser.id) ||
    (m.fromId===selUser.id && m.toId===me.id)
  ).sort((a,b)=>(a.sentAt||"").localeCompare(b.sentAt||"")) : [];

  // Auto-scroll to bottom
  useEffect(() => {
    if (msgEndRef.current) {
      msgEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [convo.length]);

  // Mark msgs as read when conversation opens
  useEffect(() => {
    if (!selUser) return;
    const unread = messages.filter(m =>
      m.fromId===selUser.id && m.toId===me.id && !(m.readBy||[]).includes(me.id)
    );
    if (unread.length > 0) {
      upd({
        messages: messages.map(m =>
          unread.find(u=>u.id===m.id)
            ? {...m, readBy:[...new Set([...(m.readBy||[]),me.id])]}
            : m
        )
      });
    }
  }, [selUser?.id]);

  const sendMsg = () => {
    if (!text.trim() || !selUser) return;
    const msg = {
      id: uid(),
      fromId: me.id,
      fromName: me.name||me.username,
      toId: selUser.id,
      toName: selUser.name,
      text: text.trim(),
      sentAt: new Date().toISOString(),
      readBy: [me.id],
    };
    upd({ messages: [...messages, msg] });
    setText("");
  };

  // Unread count per user
  const unreadFrom = {};
  messages.forEach(m => {
    if (m.toId===me.id && !(m.readBy||[]).includes(me.id)) {
      unreadFrom[m.fromId] = (unreadFrom[m.fromId]||0)+1;
    }
  });

  // Sort users by last message time
  const lastMsgTime = {};
  messages.forEach(m=>{
    const otherId = m.fromId===me.id ? m.toId : m.fromId;
    if (!lastMsgTime[otherId] || m.sentAt > lastMsgTime[otherId]) {
      lastMsgTime[otherId] = m.sentAt;
    }
  });
  const sortedUsers = [...users].sort((a,b)=>
    (lastMsgTime[b.id]||"").localeCompare(lastMsgTime[a.id]||"")
  );

  return (
    <div style={{display:"flex",gap:0,height:"calc(100vh - 120px)",
      border:"1px solid var(--border)",borderRadius:10,overflow:"hidden"}}>

      {/* User list — left panel */}
      <div style={{
        width:selUser ? "0" : "100%",
        maxWidth:280,
        borderRight:"1px solid var(--border)",
        overflowY:"auto",
        flexShrink:0,
        transition:"width 0.2s",
        display: selUser && window.innerWidth < 600 ? "none" : "block",
      }}>
        <div style={{padding:"10px 12px",borderBottom:"1px solid var(--border)",
          fontWeight:700,fontSize:13,color:"var(--accent)"}}>
          💬 Messages
        </div>
        {sortedUsers.length===0 ? (
          <div style={{padding:20,fontSize:12,color:"var(--text-dim)",textAlign:"center"}}>
            Koi user nahi
          </div>
        ) : sortedUsers.map(u=>{
          const unreads = unreadFrom[u.id]||0;
          const lastMsg = messages.filter(m=>
            (m.fromId===u.id&&m.toId===me.id)||(m.fromId===me.id&&m.toId===u.id)
          ).sort((a,b)=>b.sentAt.localeCompare(a.sentAt))[0];
          return (
            <div key={u.id}
              onClick={()=>setSelUser(u)}
              style={{
                padding:"10px 14px",cursor:"pointer",
                background: selUser?.id===u.id ? "var(--accent)22" : "transparent",
                borderBottom:"1px solid var(--border)",
                display:"flex",gap:10,alignItems:"center",
              }}>
              <div style={{
                width:36,height:36,borderRadius:"50%",flexShrink:0,
                background:`hsl(${u.name?.charCodeAt(0)*7%360},50%,30%)`,
                display:"flex",alignItems:"center",justifyContent:"center",
                fontWeight:700,fontSize:14,color:"#fff",
              }}>
                {(u.name||"?")[0].toUpperCase()}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div style={{fontWeight:unreads>0?700:500,fontSize:13,
                    overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                    {u.name}
                  </div>
                  {unreads>0 && (
                    <span style={{background:"#e74c3c",color:"#fff",
                      borderRadius:"50%",minWidth:18,height:18,
                      fontSize:10,fontWeight:900,display:"flex",
                      alignItems:"center",justifyContent:"center",padding:"0 3px"}}>
                      {unreads}
                    </span>
                  )}
                </div>
                <div style={{fontSize:10,color:"var(--text-dim)",
                  overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                  {USER_ROLES[u.role]?.label||u.role}
                  {lastMsg ? ` • ${(lastMsg.text||"").slice(0,25)}` : ""}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Conversation — right panel */}
      {selUser ? (
        <div style={{flex:1,display:"flex",flexDirection:"column",minWidth:0}}>
          {/* Header */}
          <div style={{padding:"10px 14px",borderBottom:"1px solid var(--border)",
            display:"flex",gap:8,alignItems:"center",background:"var(--bg-card)"}}>
            <button style={{...S.btnSecondary,padding:"4px 8px",fontSize:12}}
              onClick={()=>setSelUser(null)}>←</button>
            <div style={{width:32,height:32,borderRadius:"50%",
              background:`hsl(${selUser.name?.charCodeAt(0)*7%360},50%,30%)`,
              display:"flex",alignItems:"center",justifyContent:"center",
              fontWeight:700,fontSize:13,color:"#fff",flexShrink:0}}>
              {(selUser.name||"?")[0].toUpperCase()}
            </div>
            <div>
              <div style={{fontWeight:700,fontSize:13}}>{selUser.name}</div>
              <div style={{fontSize:10,color:"var(--text-dim)"}}>
                {USER_ROLES[selUser.role]?.label||selUser.role}
              </div>
            </div>
          </div>

          {/* Messages */}
          <div style={{flex:1,overflowY:"auto",padding:12,display:"flex",
            flexDirection:"column",gap:6}}>
            {convo.length===0 ? (
              <div style={{textAlign:"center",color:"var(--text-dim)",
                fontSize:12,marginTop:40}}>
                Abhi koi message nahi — pehla message bhejein!
              </div>
            ) : convo.map(m=>{
              const isMine = m.fromId===me.id;
              return (
                <div key={m.id} style={{
                  display:"flex",
                  justifyContent: isMine ? "flex-end" : "flex-start",
                }}>
                  <div style={{
                    maxWidth:"75%",
                    background: isMine ? "var(--accent)" : "var(--bg-input)",
                    color: isMine ? "#fff" : "var(--text-main)",
                    borderRadius: isMine
                      ? "12px 12px 4px 12px"
                      : "12px 12px 12px 4px",
                    padding:"8px 12px",
                    fontSize:13,
                    wordBreak:"break-word",
                  }}>
                    {m.text}
                    <div style={{fontSize:9,opacity:0.6,marginTop:3,
                      textAlign: isMine ? "right" : "left"}}>
                      {m.sentAt ? new Date(m.sentAt).toLocaleTimeString("en-IN",
                        {hour:"2-digit",minute:"2-digit"}) : ""}
                      {isMine && (m.readBy||[]).includes(selUser.id) && " ✓✓"}
                    </div>
                  </div>
                </div>
              );
            })}
            <div ref={msgEndRef}/>
          </div>

          {/* Input */}
          <div style={{padding:"10px 12px",borderTop:"1px solid var(--border)",
            display:"flex",gap:8,background:"var(--bg-card)"}}>
            <input style={{...S.input,flex:1,fontSize:13}}
              value={text}
              onChange={e=>setText(e.target.value)}
              onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();sendMsg();}}}
              placeholder="Message likhein... (Enter = Send)" />
            <button style={{...S.btnPrimary,padding:"8px 14px",
              fontSize:16,flexShrink:0}}
              onClick={sendMsg}>➤</button>
          </div>
        </div>
      ) : (
        <div style={{flex:1,display:"flex",alignItems:"center",
          justifyContent:"center",color:"var(--text-dim)",fontSize:13,
          display: window.innerWidth < 600 ? "none" : "flex"}}>
          ← Kisi user ko select karein
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// TASK SCHEDULER MODULE
// ════════════════════════════════════════════════════════════════════════════
function TaskSchedulerModule({ state, upd }) {
  const me = state.currentUser || {};
  const users = state.users || [];
  const tasks = state.tasks || [];

  // My reportees = users who report to me
  const myReportees = users.filter(u=>u.reportingTo===me.id||u.reportingTo===me.name);
  const isSenior = EQUIP_SENIOR_ROLES.includes(me.role) || me.isMaster;
  // Seniors can assign to anyone
  const assignableTo = isSenior
    ? users
    : myReportees;

  const [tab, setTab]   = useState("mytasks");
  const [form, setForm] = useState(null);
  const [filter, setFilter] = useState("all");

  // Tasks assigned TO me
  const myTasks = tasks.filter(t=>t.assignedToId===me.id);
  // Tasks assigned BY me
  const assignedByMe = tasks.filter(t=>t.assignedById===me.id);

  const savTask = (d) => {
    const task = {
      ...d,
      id: uid(),
      status: "pending",
      assignedById: me.id,
      assignedByName: me.name||me.username,
      createdAt: new Date().toISOString(),
    };

    // Material Issue Requests from task
    const newMatReqs = (d.materialList||[])
      .filter(m=>m.name&&m.qty>0)
      .map(m=>({
        id: uid(),
        projectId: d.projectId,
        projectName: d.projectName||"",
        date: d.dueDate||today(),
        itemName: m.name,
        qty: m.qty,
        unit: m.unit||"Bags",
        requestedBy: d.assignedToName||me.name,
        requestedAt: new Date().toISOString(),
        approvedVia: "task",
        taskId: task.id,
        status: "pending_issue",
      }));

    // Auto-allot machinery from Equipment Demand system
    const newAllocs = (d.machineryList||[])
      .filter(m=>m.equipmentId&&m.date)
      .map(m=>{
        const eq = (state.equipmentMaster||[]).find(e=>e.id===m.equipmentId);
        return {
          id: uid(),
          demandId: task.id,
          equipmentId: m.equipmentId,
          equipmentName: m.name||eq?.name||"",
          projectId: d.projectId,
          projectName: d.projectName||"",
          date: m.date||d.dueDate||today(),
          startTime: m.startTime||"09:00",
          endTime: m.endTime||"18:00",
          requestedBy: d.assignedToName||me.name,
          requestedById: d.assignedToId,
          purpose: d.title,
          status: "scheduled",
          source: "task",
          taskId: task.id,
          createdAt: new Date().toISOString(),
        };
      });

    const updState = { tasks: [...tasks, task] };
    if (newMatReqs.length>0)
      updState.materialIssueRequests = [...(state.materialIssueRequests||[]), ...newMatReqs];
    if (newAllocs.length>0)
      updState.equipmentAllocs = [...(state.equipmentAllocs||[]), ...newAllocs];

    upd(updState);
    setForm(null);
  };

  const updateStatus = (id, status, remark="") => {
    upd({
      tasks: tasks.map(t => t.id===id
        ? {...t, status, completedAt: status==="done"?new Date().toISOString():t.completedAt,
            completionRemark: remark||t.completionRemark}
        : t
      )
    });
  };

  const STATUS_COLOR = {
    pending:"#f39c12", in_progress:"#2980b9",
    done:"#27ae60", cancelled:"#e74c3c"
  };

  const TaskCard = ({task, showAssignee=false}) => {
    const [remarkInput, setRemarkInput] = useState("");
    const [showRemark, setShowRemark] = useState(false);
    const sc = STATUS_COLOR[task.status]||"#888";
    const isMyTask = task.assignedToId===me.id;
    return (
      <div style={{...S.card,marginBottom:8,borderLeft:`4px solid ${sc}`}}>
        <div style={{display:"flex",justifyContent:"space-between",
          flexWrap:"wrap",gap:6}}>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,fontSize:13}}>
              {task.title}
            </div>
            {task.description && (
              <div style={{fontSize:12,color:"var(--text-dim)",marginTop:2}}>
                {task.description}
              </div>
            )}
            <div style={{fontSize:11,color:"var(--text-dim)",marginTop:4,
              display:"flex",gap:8,flexWrap:"wrap"}}>
              {showAssignee && <span>👤 {task.assignedToName}</span>}
              <span>📅 Due: {task.dueDate||"—"}</span>
              <span>⚡ {task.priority||"Normal"}</span>
              {task.projectName && <span>🏗 {task.projectName}</span>}
              {task.stageName && <span>🏠 {task.stageName}</span>}
            </div>
            {/* Stage Items */}
            {(task.taskItems||[]).length > 0 && (
              <div style={{marginTop:6,background:"var(--bg-input)",
                borderRadius:6,padding:"6px 8px"}}>
                <div style={{fontSize:10,fontWeight:700,color:"var(--text-dim)",
                  marginBottom:4}}>📋 Kaam ke Items:</div>
                {(task.taskItems||[]).map((it,i)=>(
                  <div key={i} style={{display:"flex",justifyContent:"space-between",
                    fontSize:11,padding:"2px 0",
                    borderBottom:i<task.taskItems.length-1?"1px solid var(--border)":"none"}}>
                    <span style={{color:"var(--text-main)"}}>{it.name||"—"}</span>
                    <span style={{color:"var(--accent)",fontWeight:600,whiteSpace:"nowrap"}}>
                      {it.targetQty||it.plannedQty||0} {it.unit||""}
                    </span>
                  </div>
                ))}
              </div>
            )}
            {task.completionRemark && (
              <div style={{fontSize:11,color:"#27ae60",marginTop:4,fontStyle:"italic"}}>
                ✓ {task.completionRemark}
              </div>
            )}
            {/* Resource summary */}
            {((task.materialList||[]).length>0||(task.labourList||[]).length>0||(task.machineryList||[]).length>0) && (
              <div style={{marginTop:6,display:"flex",gap:6,flexWrap:"wrap"}}>
                {(task.materialList||[]).length>0 && (
                  <span style={{fontSize:10,background:"#27ae6018",color:"#27ae60",
                    padding:"2px 7px",borderRadius:8,border:"1px solid #27ae6033"}}>
                    🧱 {(task.materialList||[]).length} material
                  </span>
                )}
                {(task.labourList||[]).length>0 && (
                  <span style={{fontSize:10,background:"#8e44ad18",color:"#8e44ad",
                    padding:"2px 7px",borderRadius:8,border:"1px solid #8e44ad33"}}>
                    👷 {(task.labourList||[]).reduce((s,l)=>s+(l.nos||1),0)} labour
                  </span>
                )}
                {(task.machineryList||[]).length>0 && (
                  <span style={{fontSize:10,background:"#e67e2218",color:"#e67e22",
                    padding:"2px 7px",borderRadius:8,border:"1px solid #e67e2233"}}>
                    🚜 {(task.machineryList||[]).map(m=>m.name).filter(Boolean).join(", ")||`${(task.machineryList||[]).length} machinery`}
                  </span>
                )}
              </div>
            )}
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:4,alignItems:"flex-end"}}>
            <span style={{fontSize:10,background:sc+"22",color:sc,
              padding:"2px 8px",borderRadius:10,fontWeight:700,whiteSpace:"nowrap"}}>
              {task.status==="pending"?"⏳ Pending":
               task.status==="in_progress"?"🔄 In Progress":
               task.status==="done"?"✅ Done":"✗ Cancelled"}
            </span>
          </div>
        </div>
        {/* Actions for assignee */}
        {isMyTask && task.status!=="done" && task.status!=="cancelled" && (
          <div style={{marginTop:8,display:"flex",gap:6,flexWrap:"wrap"}}>
            {task.status==="pending" && (
              <button style={{...S.btnSm,background:"#2980b9",padding:"4px 10px",fontSize:11}}
                onClick={()=>updateStatus(task.id,"in_progress")}>
                ▶ Start
              </button>
            )}
            <button style={{...S.btnSm,background:"#27ae60",padding:"4px 10px",fontSize:11}}
              onClick={()=>setShowRemark(!showRemark)}>
              ✓ Done
            </button>
            {showRemark && (
              <div style={{width:"100%",display:"flex",gap:6,marginTop:4}}>
                <input style={{...S.input,flex:1,fontSize:12}}
                  value={remarkInput}
                  onChange={e=>setRemarkInput(e.target.value)}
                  placeholder="Completion remark..." />
                <button style={{...S.btnPrimary,background:"#27ae60",padding:"5px 10px"}}
                  onClick={()=>{
                    updateStatus(task.id,"done",remarkInput);
                    setShowRemark(false);
                  }}>Save</button>
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",
        alignItems:"center",marginBottom:12,flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:16,fontWeight:800,color:"var(--accent)"}}>
          📋 Task Scheduler
        </div>
        {assignableTo.length>0 && (
          <button style={{...S.btnPrimary,padding:"7px 16px"}}
            onClick={()=>setForm({})}>
            + New Task
          </button>
        )}
      </div>

      {/* Tabs */}
      <div style={{...S.tabs,marginBottom:12}}>
        {[
          {id:"mytasks", label:`📥 Mujhe Mila (${myTasks.filter(t=>t.status==="pending").length})`},
          {id:"assigned", label:"📤 Maine Diya"},
          {id:"all", label:"📊 Sab", hide: !isSenior},
        ].filter(t=>!t.hide).map(t=>(
          <button key={t.id}
            style={{...S.tabBtn,
              background:tab===t.id?"var(--accent)":"var(--bg-input)",
              color:tab===t.id?"#fff":"var(--text-muted)"}}
            onClick={()=>setTab(t.id)}>
            {t.label}
          </button>
        ))}
      </div>

      {/* New Task Form */}
      {form && (
        <TaskForm
          assignableTo={assignableTo}
          projects={state.projects||[]}
          me={me}
          state={state}
          onSave={savTask}
          onCancel={()=>setForm(null)}
        />
      )}

      {/* My Tasks */}
      {tab==="mytasks" && (
        <div>
          {myTasks.length===0 ? (
            <div style={{...S.empty}}>
              <div style={{fontSize:36}}>📋</div>
              <div>Koi task nahi</div>
            </div>
          ) : myTasks.slice().reverse().map(t=>(
            <TaskCard key={t.id} task={t} />
          ))}
        </div>
      )}

      {/* Assigned by me */}
      {tab==="assigned" && (
        <div>
          {assignedByMe.length===0 ? (
            <div style={{...S.empty}}>
              <div>Aapne abhi koi task assign nahi kiya</div>
            </div>
          ) : assignedByMe.slice().reverse().map(t=>(
            <TaskCard key={t.id} task={t} showAssignee={true} />
          ))}
        </div>
      )}

      {/* All tasks — senior only */}
      {tab==="all" && isSenior && (
        <div>
          {tasks.slice().reverse().map(t=>(
            <TaskCard key={t.id} task={t} showAssignee={true} />
          ))}
        </div>
      )}
    </div>
  );
}

// ── Task Form ─────────────────────────────────────────────────────────────────
function TaskForm({ assignableTo, projects, me, state, onSave, onCancel }) {
  const [f, setF] = useState({
    title:"", description:"",
    assignedToId:"", assignedToName:"",
    dueDate:"", priority:"Normal",
    projectId:"", projectName:"",
    materialList: [],
    labourList: [],
    machineryList: [],
  });
  const upF = p => setF(s=>({...s,...p}));

  const matMaster   = (state?.materialMaster&&state.materialMaster.length>0) ? state.materialMaster : [];
  const equipMaster = (state?.equipmentMaster&&state.equipmentMaster.length>0) ? state.equipmentMaster : [];
  const labourMaster= state?.manpowerMaster||[];
  const matNames    = [...new Set(matMaster.map(m=>m.name).filter(Boolean))].sort();
  const UNITS       = ["Bags","Cft","Cum","Sqft","Sqm","Kg","MT","Nos","Ltr","RFT","Set","Trip"];

  // Stock map for balance display
  const stockMap = {};
  (state?.inventory||[]).forEach(it=>{
    const k=(it.name||"").toLowerCase();
    if(!stockMap[k]) stockMap[k]={name:it.name,unit:it.unit||"",balance:0};
    stockMap[k].balance+=(it.qty||0);
  });
  (state?.materialIssues||[]).forEach(iss=>{
    const k=(iss.material||"").toLowerCase();
    if(stockMap[k]) stockMap[k].balance-=(iss.qty||0);
  });

  const addMat  = () => upF({materialList:[...f.materialList, {id:uid(),name:"",unit:"Bags",qty:0}]});
  const updMat  = (id,p) => upF({materialList:f.materialList.map(m=>m.id===id?{...m,...p}:m)});
  const remMat  = (id) => upF({materialList:f.materialList.filter(m=>m.id!==id)});

  const addLab  = () => upF({labourList:[...f.labourList, {id:uid(),name:"",type:"",nos:1,timeIn:"09:00",timeOut:"18:00"}]});
  const updLab  = (id,p) => upF({labourList:f.labourList.map(l=>l.id===id?{...l,...p}:l)});
  const remLab  = (id) => upF({labourList:f.labourList.filter(l=>l.id!==id)});

  const addMach = () => upF({machineryList:[...f.machineryList,{id:uid(),equipmentId:"",name:"",date:f.dueDate||today(),startTime:"09:00",endTime:"18:00"}]});
  const updMach = (id,p) => upF({machineryList:f.machineryList.map(m=>m.id===id?{...m,...p}:m)});
  const remMach = (id) => upF({machineryList:f.machineryList.filter(m=>m.id!==id)});

  const submit = () => {
    if (!f.title.trim()) { alert("Task title likhein।"); return; }
    if (!f.assignedToId)  { alert("Kisi ko assign karein।"); return; }
    onSave(f);
  };

  const secHead = (color, label) => (
    <div style={{fontWeight:700,color,fontSize:12,marginBottom:6,marginTop:10}}>{label}</div>
  );
  const thS = (color) => ({...S.th,padding:"4px 8px",fontSize:11,background:color+"22",color});
  const tdS = {...S.td,padding:"3px 5px"};

  return (
    <div style={{...S.card,marginBottom:12,border:"1px solid var(--accent)44"}}>
      <div style={{fontWeight:700,color:"var(--accent)",marginBottom:10}}>📋 Naya Task</div>

      {/* ── Basic Info ── */}
      <div style={{display:"grid",gap:8,marginBottom:8}}>
        <div>
          <label style={S.label}>Task Title *</label>
          <input style={S.input} value={f.title}
            onChange={e=>upF({title:e.target.value})}
            placeholder="Kaam ka naam..." />
        </div>
        <div>
          <label style={S.label}>Description</label>
          <textarea style={{...S.input,minHeight:44,resize:"vertical"}}
            value={f.description}
            onChange={e=>upF({description:e.target.value})}
            placeholder="Kaam ki detail..." />
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          <div>
            <label style={S.label}>Assign To *</label>
            <select style={S.select} value={f.assignedToId}
              onChange={e=>{
                const u=assignableTo.find(x=>x.id===e.target.value);
                upF({assignedToId:e.target.value,assignedToName:u?.name||""});
              }}>
              <option value="">-- Select --</option>
              {assignableTo.map(u=>(
                <option key={u.id} value={u.id}>
                  {u.name} ({USER_ROLES[u.role]?.label||u.role})
                </option>
              ))}
            </select>
          </div>
          <div>
            <label style={S.label}>Priority</label>
            <select style={S.select} value={f.priority}
              onChange={e=>upF({priority:e.target.value})}>
              {["Low","Normal","High","Urgent"].map(p=>(
                <option key={p}>{p}</option>
              ))}
            </select>
          </div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          <div>
            <label style={S.label}>Due Date</label>
            <input type="date" style={S.input} value={f.dueDate}
              onChange={e=>upF({dueDate:e.target.value})} />
          </div>
          <div>
            <label style={S.label}>Project</label>
            <select style={S.select} value={f.projectId}
              onChange={e=>{
                const p=projects.find(x=>x.id===e.target.value);
                upF({projectId:e.target.value,projectName:p?.name||"",
                  stageId:"",stageName:"",taskItems:[]});
              }}>
              <option value="">-- Optional --</option>
              {projects.map(p=>(
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Stage select — only if project selected */}
        {f.projectId && (() => {
          const selProj = projects.find(p=>p.id===f.projectId);
          const substages = selProj?.substages || [];
          const selStage = substages.find(s=>s.id===f.stageId);
          const stageItems = selStage?.items || [];

          return (
            <div style={{display:"grid",gap:8}}>
              <div>
                <label style={S.label}>Stage / Floor (optional)</label>
                <select style={S.select} value={f.stageId||""}
                  onChange={e=>{
                    const ss=substages.find(s=>s.id===e.target.value);
                    upF({stageId:e.target.value,stageName:ss?.name||"",taskItems:[]});
                  }}>
                  <option value="">-- Stage select karein --</option>
                  {substages.map(s=>(
                    <option key={s.id} value={s.id}>
                      {s.name} {s.status==="done"?"✅":"🔄"}
                    </option>
                  ))}
                </select>
              </div>

              {/* Stage items with quantities */}
              {f.stageId && stageItems.length > 0 && (
                <div>
                  <label style={S.label}>
                    Stage ke Items (jo kaam karna hai wo select karein)
                  </label>
                  <div style={{background:"var(--bg-input)",borderRadius:8,
                    padding:8,maxHeight:220,overflowY:"auto"}}>
                    {stageItems.map(it=>{
                      const checked = (f.taskItems||[]).find(x=>x.id===it.id);
                      return (
                        <div key={it.id} style={{
                          display:"flex",alignItems:"center",gap:8,
                          padding:"5px 4px",borderBottom:"1px solid var(--border)"
                        }}>
                          <input type="checkbox"
                            checked={!!checked}
                            onChange={()=>{
                              const cur = f.taskItems||[];
                              if(checked){
                                upF({taskItems:cur.filter(x=>x.id!==it.id)});
                              } else {
                                upF({taskItems:[...cur,{
                                  id:it.id,
                                  name:it.name||it.description||"",
                                  unit:it.unit||it.uom||"",
                                  plannedQty:it.qty||0,
                                  targetQty:it.qty||0,
                                }]});
                              }
                            }}
                            style={{flexShrink:0}}
                          />
                          <div style={{flex:1,fontSize:12,
                            color:checked?"var(--text-main)":"var(--text-dim)"}}>
                            {it.name||it.description||"—"}
                          </div>
                          <div style={{fontSize:11,color:"var(--text-dim)",
                            whiteSpace:"nowrap"}}>
                            {it.qty||0} {it.unit||it.uom||""}
                          </div>
                          {checked && (
                            <div style={{display:"flex",alignItems:"center",gap:4}}>
                              <span style={{fontSize:10,color:"var(--text-dim)"}}>Target:</span>
                              <input type="number" min={0} step="any"
                                style={{...S.input,width:64,padding:"2px 4px",fontSize:11}}
                                value={checked.targetQty||0}
                                onChange={e=>{
                                  upF({taskItems:(f.taskItems||[]).map(x=>
                                    x.id===it.id?{...x,targetQty:+e.target.value}:x
                                  )});
                                }}
                              />
                              <span style={{fontSize:10,color:"var(--text-dim)"}}>
                                {it.unit||it.uom||""}
                              </span>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                  {(f.taskItems||[]).length > 0 && (
                    <div style={{fontSize:11,color:"#27ae60",marginTop:4}}>
                      ✓ {(f.taskItems||[]).length} items selected
                    </div>
                  )}
                </div>
              )}

              {f.stageId && stageItems.length === 0 && (
                <div style={{fontSize:11,color:"var(--text-dim)",
                  background:"var(--bg-input)",borderRadius:6,padding:"6px 10px"}}>
                  Is stage mein koi items nahi hain
                </div>
              )}
            </div>
          );
        })()}
      </div>

      {/* ── Material List ── */}
      {secHead("#27ae60","🧱 Material Chahiye (Issue Request jayegi Inventory mein)")}
      {f.materialList.length > 0 && (
        <div style={{overflowX:"auto",marginBottom:6}}>
          <table style={{...S.table,fontSize:12,minWidth:420}}>
            <thead><tr>
              <th style={thS("#27ae60")}>Material</th>
              <th style={{...thS("#27ae60"),width:65}}>Unit</th>
              <th style={{...thS("#27ae60"),width:75}}>Qty</th>
              <th style={{...thS("#27ae60"),width:90}}>Stock</th>
              <th style={{...thS("#27ae60"),width:32}}></th>
            </tr></thead>
            <tbody>
              {f.materialList.map(m=>{
                const stk = stockMap[(m.name||"").toLowerCase()];
                const low = stk && stk.balance < (m.qty||0);
                return (
                  <tr key={m.id} style={{...S.tr,background:low?"#1a0a0a":""}}>
                    <td style={tdS}>
                      <input list={`tmat-${matNames.length}`}
                        style={{...S.input,fontSize:11,padding:"3px 5px",minWidth:120}}
                        value={m.name} placeholder="Material..."
                        onChange={e=>{
                          const mm=matMaster.find(x=>x.name===e.target.value);
                          updMat(m.id,{name:e.target.value,unit:mm?.unit||m.unit||"Bags"});
                        }}/>
                      <datalist id={`tmat-${matNames.length}`}>
                        {matNames.map(n=><option key={n} value={n}/>)}
                      </datalist>
                    </td>
                    <td style={tdS}>
                      <select style={{...S.select,fontSize:11,padding:"2px 4px",width:60}}
                        value={m.unit||"Bags"}
                        onChange={e=>updMat(m.id,{unit:e.target.value})}>
                        {UNITS.map(u=><option key={u}>{u}</option>)}
                      </select>
                    </td>
                    <td style={tdS}>
                      <input type="number" min={0}
                        style={{...S.input,fontSize:11,padding:"3px 5px",width:66}}
                        value={m.qty||""} onChange={e=>updMat(m.id,{qty:+e.target.value})}/>
                    </td>
                    <td style={{...tdS,fontSize:10,color:low?"#e74c3c":stk?"#27ae60":"#888",fontWeight:600}}>
                      {stk?`${stk.balance.toFixed(1)} ${stk.unit}`:"—"}
                      {low&&<span style={{display:"block",fontSize:9,color:"#e74c3c"}}>Kam!</span>}
                    </td>
                    <td style={tdS}>
                      <button style={{...S.btnSm,background:"#2a0d0d",color:"#e74c3c",padding:"2px 5px",fontSize:10}}
                        onClick={()=>remMat(m.id)}>✕</button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
      <button style={{...S.btnSm,background:"#0a1a00",color:"#27ae60",border:"1px solid #27ae60",fontSize:11}}
        onClick={addMat}>＋ Material Add</button>

      {/* ── Labour List ── */}
      {secHead("#8e44ad","👷 Labour Chahiye")}
      {f.labourList.length > 0 && (
        <div style={{overflowX:"auto",marginBottom:6}}>
          <table style={{...S.table,fontSize:12,minWidth:440}}>
            <thead><tr>
              <th style={thS("#8e44ad")}>Name</th>
              <th style={thS("#8e44ad")}>Type/Role</th>
              <th style={{...thS("#8e44ad"),width:46}}>Nos</th>
              <th style={{...thS("#8e44ad"),width:70}}>Time In</th>
              <th style={{...thS("#8e44ad"),width:70}}>Time Out</th>
              <th style={{...thS("#8e44ad"),width:32}}></th>
            </tr></thead>
            <tbody>
              {f.labourList.map(l=>(
                <tr key={l.id} style={S.tr}>
                  <td style={tdS}>
                    <input list={`tlab-${labourMaster.length}`}
                      style={{...S.input,fontSize:11,padding:"3px 5px",minWidth:110}}
                      value={l.name} placeholder="Naam..."
                      onChange={e=>updLab(l.id,{name:e.target.value})}/>
                    <datalist id={`tlab-${labourMaster.length}`}>
                      {labourMaster.map(x=><option key={x.id} value={x.name}/>)}
                    </datalist>
                  </td>
                  <td style={tdS}>
                    <input style={{...S.input,fontSize:11,padding:"3px 5px",width:90}}
                      value={l.type} placeholder="Mason/Helper..."
                      onChange={e=>updLab(l.id,{type:e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <input type="number" min={1}
                      style={{...S.input,fontSize:11,padding:"3px 5px",width:40}}
                      value={l.nos||1} onChange={e=>updLab(l.id,{nos:+e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <input type="time"
                      style={{...S.input,fontSize:11,padding:"2px 4px",width:68}}
                      value={l.timeIn||"09:00"}
                      onChange={e=>updLab(l.id,{timeIn:e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <input type="time"
                      style={{...S.input,fontSize:11,padding:"2px 4px",width:68}}
                      value={l.timeOut||"18:00"}
                      onChange={e=>updLab(l.id,{timeOut:e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <button style={{...S.btnSm,background:"#2a0d0d",color:"#e74c3c",padding:"2px 5px",fontSize:10}}
                      onClick={()=>remLab(l.id)}>✕</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <button style={{...S.btnSm,background:"#0a0a1a",color:"#8e44ad",border:"1px solid #8e44ad",fontSize:11}}
        onClick={addLab}>＋ Labour Add</button>

      {/* ── Machinery List ── */}
      {secHead("#e67e22","🚜 Machinery Chahiye (Auto-allot hogi Equipment Demand se)")}
      {f.machineryList.length > 0 && (
        <div style={{overflowX:"auto",marginBottom:6}}>
          <table style={{...S.table,fontSize:12,minWidth:480}}>
            <thead><tr>
              <th style={thS("#e67e22")}>Equipment</th>
              <th style={{...thS("#e67e22"),width:90}}>Date</th>
              <th style={{...thS("#e67e22"),width:68}}>Start</th>
              <th style={{...thS("#e67e22"),width:68}}>End</th>
              <th style={{...thS("#e67e22"),width:32}}></th>
            </tr></thead>
            <tbody>
              {f.machineryList.map(m=>(
                <tr key={m.id} style={S.tr}>
                  <td style={tdS}>
                    <select style={{...S.select,fontSize:11,padding:"3px 5px",minWidth:140}}
                      value={m.equipmentId||""}
                      onChange={e=>{
                        const eq=equipMaster.find(x=>x.id===e.target.value);
                        updMach(m.id,{equipmentId:e.target.value,name:eq?.name||eq?.type||""});
                      }}>
                      <option value="">-- Select --</option>
                      {equipMaster.map(eq=>(
                        <option key={eq.id} value={eq.id}>
                          {eq.name||eq.type} ({eq.code||""})
                        </option>
                      ))}
                    </select>
                  </td>
                  <td style={tdS}>
                    <input type="date"
                      style={{...S.input,fontSize:11,padding:"3px 5px",width:110}}
                      value={m.date||f.dueDate||today()}
                      onChange={e=>updMach(m.id,{date:e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <input type="time"
                      style={{...S.input,fontSize:11,padding:"2px 4px",width:66}}
                      value={m.startTime||"09:00"}
                      onChange={e=>updMach(m.id,{startTime:e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <input type="time"
                      style={{...S.input,fontSize:11,padding:"2px 4px",width:66}}
                      value={m.endTime||"18:00"}
                      onChange={e=>updMach(m.id,{endTime:e.target.value})}/>
                  </td>
                  <td style={tdS}>
                    <button style={{...S.btnSm,background:"#2a0d0d",color:"#e74c3c",padding:"2px 5px",fontSize:10}}
                      onClick={()=>remMach(m.id)}>✕</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <button style={{...S.btnSm,background:"#1a0e00",color:"#e67e22",border:"1px solid #e67e22",fontSize:11}}
        onClick={addMach}>＋ Machinery Add</button>

      {/* ── Buttons ── */}
      <div style={{display:"flex",gap:8,marginTop:12,justifyContent:"flex-end"}}>
        <button style={{...S.btnSecondary,padding:"7px 14px"}}
          onClick={onCancel}>Cancel</button>
        <button style={{...S.btnPrimary,padding:"7px 16px"}}
          onClick={submit}>📤 Assign Task</button>
      </div>
    </div>
  );
}


function Header({ state, upd, setTab, theme, setTheme, onLogout, fbStatus, companyName }) {
  const u = state.currentUser;
  const role = USER_ROLES[u?.role];
  const [menuOpen, setMenuOpen] = useState(false);

  // Short role label for mobile
  const roleShort = {
    "Master Admin":"M.Admin", "Managing Director":"MD", "Director":"Dir",
    "CEO / Owner":"CEO", "Project Director":"PD", "HR Manager":"HR",
    "Site Engineer":"Engr", "Project Manager":"PM", "Accountant":"Acct",
  }[role?.label] || (role?.label||"").slice(0,6);

  return (
    <header style={{
      ...S.header,
      padding:"0 8px",
      minHeight:52,
    }}>
      {/* Logo — left side */}
      <div style={{display:"flex",alignItems:"center",gap:4,flex:1,minWidth:0,overflow:"hidden"}}>
        <span style={{fontSize:18,flexShrink:0}}>🏗</span>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontWeight:800,color:"var(--accent)",
            lineHeight:1.2,wordBreak:"break-word",
            fontSize: companyName && companyName.length > 28 ? 9
                    : companyName && companyName.length > 20 ? 10
                    : companyName && companyName.length > 13 ? 11 : 13}}
            title={companyName}>
            {companyName || "VinayakBuildTrack"}
          </div>
          {u?.name && (
            <div style={{fontSize:10,color:"var(--text-dim)",whiteSpace:"nowrap",
              overflow:"hidden",textOverflow:"ellipsis"}}>
              {u.name}
            </div>
          )}
        </div>
      </div>

      {/* Right side */}
      <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>

        {/* Firebase status — always visible dot */}
        <div style={{display:"flex",alignItems:"center",gap:3,fontSize:9,
          color:fbStatus==="connected"?"#27ae60":fbStatus==="offline"?"#e74c3c":"#f39c12",
          whiteSpace:"nowrap",flexShrink:0}} title={fbStatus}>
          <span style={{width:7,height:7,borderRadius:"50%",
            background:fbStatus==="connected"?"#27ae60":fbStatus==="offline"?"#e74c3c":"#f39c12",
            display:"inline-block",flexShrink:0}}/>
        </div>
        {/* Project select — desktop only */}
        {(state.projects||[]).length > 0 && (
          <select className="vbt-hide-mobile"
            style={{...S.projSelect,maxWidth:130,fontSize:11}}
            value={state.activeProject||""}
            onChange={e=>upd({activeProject:e.target.value})}>
            <option value="">Project...</option>
            {(state.projects||[]).map(p=>(
              <option key={p.id} value={p.id}>{p.name}</option>
            ))}
          </select>
        )}

        {/* Role badge — always visible, compact */}
        <span style={{
          background:role?.color||"#888", color:"#fff",
          borderRadius:6, padding:"3px 7px", fontSize:10, fontWeight:700,
          whiteSpace:"nowrap", flexShrink:0,
        }}>
          {roleShort}
        </span>

        {/* 🔔 Notification Bell */}
        <NotificationBell state={state} upd={upd} setTab={setTab} />
        <div style={{position:"relative",zIndex:99999,flexShrink:0}}>
          <button style={{
            background:"var(--bg-input)",border:"1px solid var(--border)",
            borderRadius:6,padding:"5px 10px",fontSize:18,cursor:"pointer",
            color:"var(--text-main)",lineHeight:1,
          }}
            onClick={()=>setMenuOpen(!menuOpen)}>⋮</button>

          {menuOpen && (<>
            <div onClick={()=>setMenuOpen(false)}
              style={{position:"fixed",inset:0,zIndex:99998}}/>
            <div style={{
              position:"fixed",right:8,top:52,
              background:"var(--bg-card)",
              border:"1px solid var(--border)",borderRadius:10,padding:10,
              minWidth:220,zIndex:99999,
              boxShadow:"0 6px 24px rgba(0,0,0,0.5)",
            }}>
              {/* User info */}
              <div style={{fontSize:12,fontWeight:700,padding:"4px 6px",
                borderBottom:"1px solid var(--border)",marginBottom:8,
                color:"var(--text-main)"}}>
                👤 {u?.name}
                <div style={{fontSize:10,color:"var(--text-dim)",fontWeight:400}}>
                  {role?.label} • {new Date().toLocaleDateString("en-IN")}
                </div>
              </div>

              {/* Project select — mobile only */}
              {(state.projects||[]).length > 0 && (
                <div style={{marginBottom:8}}>
                  <div style={{fontSize:10,color:"var(--text-dim)",marginBottom:3}}>
                    Active Project
                  </div>
                  <select style={{...S.select,fontSize:12}}
                    value={state.activeProject||""}
                    onChange={e=>{upd({activeProject:e.target.value});setMenuOpen(false);}}>
                    <option value="">-- Select Project --</option>
                    {(state.projects||[]).map(p=>(
                      <option key={p.id} value={p.id}>{p.name}</option>
                    ))}
                  </select>
                </div>
              )}

              {/* Backup */}
              <button style={{...S.btnSecondary,width:"100%",marginBottom:6,
                fontSize:12,textAlign:"left",padding:"8px 10px"}}
                onClick={()=>{
                  setMenuOpen(false);
                  const data=JSON.stringify({...state,exportedAt:new Date().toISOString()});
                  const a=document.createElement("a");
                  a.href="data:application/json;charset=utf-8,"+encodeURIComponent(data);
                  a.download="VBT_Backup_"+today()+".json";
                  a.click();
                }}>💾 Backup Data</button>

              {/* Theme picker */}
              <div style={{marginBottom:6,padding:"4px 0"}}>
                <div style={{fontSize:10,color:"var(--text-dim)",marginBottom:4}}>Theme</div>
                <ThemePicker currentTheme={theme} onChange={(t)=>{setTheme(t);}} />
              </div>

              {/* Logout */}
              <button style={{...S.btnPrimary,background:"#e74c3c",width:"100%",
                fontSize:12,padding:"9px 10px",marginTop:4}}
                onClick={()=>{setMenuOpen(false);onLogout();}}>
                🚪 Logout
              </button>
            </div>
          </>)}
        </div>

        {/* Desktop only: Backup + Logout buttons */}
        <button className="vbt-hide-mobile"
          style={{...S.btnPrimary,background:"#27ae60",padding:"5px 10px",fontSize:11}}
          onClick={()=>{
            const data=JSON.stringify({...state,exportedAt:new Date().toISOString()});
            const a=document.createElement("a");
            a.href="data:application/json;charset=utf-8,"+encodeURIComponent(data);
            a.download="VBT_Backup_"+today()+".json";
            a.click();
          }}>💾</button>
        <button className="vbt-hide-mobile"
          style={{...S.btnSecondary,padding:"5px 10px",fontSize:11}}
          onClick={onLogout}>Logout</button>
      </div>

      <style>{`
        @media (max-width: 768px) {
          .vbt-hide-mobile { display: none !important; }
        }
      `}</style>
    </header>
  );
}
