function Sidebar({ activeTab, setTab, rights }) {
  const [col, setCol] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const navItems = NAV.filter(n => (rights||[]).includes(n.id));

  // Mobile: bottom nav shows top 5 items + "More" button
  const topNav    = navItems.slice(0, 4);
  const moreNav   = navItems.slice(4);

  return (
    <>
      {/* ── DESKTOP SIDEBAR ── */}
      <aside className="vbt-desktop-sidebar" style={{
        ...S.sidebar, width: col ? 52 : 190,
        display: "flex", flexDirection: "column",
      }}>
        <button style={S.collapseBtn} onClick={() => setCol(!col)}>
          {col ? "▶" : "◀"}
        </button>
        {navItems.map(n => (
          <button key={n.id} title={n.label}
            style={{...S.navBtn,
              background: activeTab===n.id ? "var(--sidebar-active)" : "transparent",
              color: activeTab===n.id ? "#fff" : "var(--text-muted)",
            }}
            onClick={() => setTab(n.id)}>
            <span style={{fontSize:16}}>{n.icon}</span>
            {!col && <span style={{marginLeft:8,fontSize:12}}>{n.label}</span>}
          </button>
        ))}
      </aside>

      {/* ── MOBILE BOTTOM NAV ── */}
      <nav className="vbt-mobile-nav" style={{
        position:"fixed", bottom:0, left:0, right:0, zIndex:1000,
        background:"var(--bg-sidebar)", borderTop:"2px solid var(--accent)",
        display:"flex", alignItems:"stretch",
        boxShadow:"0 -2px 12px rgba(0,0,0,0.3)",
      }}>
        {topNav.map(n => (
          <button key={n.id} onClick={() => { setTab(n.id); setMobileOpen(false); }}
            style={{
              flex:1, display:"flex", flexDirection:"column",
              alignItems:"center", justifyContent:"center",
              padding:"6px 2px 8px", border:"none", cursor:"pointer",
              background: activeTab===n.id ? "var(--accent)" : "transparent",
              color: activeTab===n.id ? "#fff" : "var(--text-muted)",
              fontSize:10, fontWeight:600, gap:2,
              borderRight:"1px solid var(--border)",
              minWidth:0,
            }}>
            <span style={{fontSize:18}}>{n.icon}</span>
            <span style={{fontSize:9,overflow:"hidden",textOverflow:"ellipsis",
              whiteSpace:"nowrap",maxWidth:60}}>{n.label}</span>
          </button>
        ))}
        {moreNav.length > 0 && (
          <button onClick={() => setMobileOpen(!mobileOpen)}
            style={{
              flex:1, display:"flex", flexDirection:"column",
              alignItems:"center", justifyContent:"center",
              padding:"6px 2px 8px", border:"none", cursor:"pointer",
              background: mobileOpen ? "var(--accent)" : "transparent",
              color: mobileOpen ? "#fff" : "var(--text-muted)",
              fontSize:10, fontWeight:600, gap:2,
            }}>
            <span style={{fontSize:18}}>☰</span>
            <span style={{fontSize:9}}>More</span>
          </button>
        )}
      </nav>

      {/* ── MOBILE SLIDE-UP MENU ── */}
      {mobileOpen && (
        <div className="vbt-mobile-nav" style={{
          position:"fixed", bottom:56, left:0, right:0, zIndex:999,
          background:"var(--bg-sidebar)", borderTop:"1px solid var(--border)",
          display:"grid", gridTemplateColumns:"repeat(4,1fr)",
          padding:8, gap:6,
          boxShadow:"0 -4px 20px rgba(0,0,0,0.4)",
          maxHeight:"50vh", overflowY:"auto",
        }}>
          {moreNav.map(n => (
            <button key={n.id} onClick={() => { setTab(n.id); setMobileOpen(false); }}
              style={{
                display:"flex", flexDirection:"column",
                alignItems:"center", justifyContent:"center",
                padding:"10px 4px", border:"1px solid var(--border)",
                borderRadius:8, cursor:"pointer",
                background: activeTab===n.id ? "var(--accent)" : "var(--bg-input)",
                color: activeTab===n.id ? "#fff" : "var(--text-muted)",
                fontSize:10, fontWeight:600, gap:4,
              }}>
              <span style={{fontSize:20}}>{n.icon}</span>
              <span style={{fontSize:9,textAlign:"center",lineHeight:1.2}}>{n.label}</span>
            </button>
          ))}
        </div>
      )}

      {/* ── CSS for show/hide ── */}
      <style>{`
        @media (max-width: 768px) {
          .vbt-desktop-sidebar { display: none !important; }
          .vbt-mobile-nav { display: flex !important; }
        }
        @media (min-width: 769px) {
          .vbt-desktop-sidebar { display: flex !important; }
          .vbt-mobile-nav { display: none !important; }
        }
      `}</style>
    </>
  );
}
// ─── DASHBOARD ─────────────────────────────────────────────────────────────────

function Dashboard({ state, upd, setTab }) {
  const proj = (state.projects||[]).find((p) => p.id === state.activeProject);
  const todaySpent = (state.dailyLogs||[]).filter((l) => l.date === today()).reduce((s, l) => s + (l.totalAmount || 0), 0);
  // ── Derived from approved progress ──────────────────────────────────────
  const allProgress = state.projectProgress || [];
  const approvedEntries = allProgress.filter(e => e.status === "approved");
  const pendingApproval = allProgress.filter(e => !e.status || e.status === "pending");
  const projProgress = proj ? approvedEntries.filter(e => e.projectId === proj.id) : [];
  const todayMuster = (state.musterRoll || []).filter(m =>
    m.type === "attendance" && m.date === today() && m.status !== "A");
  const totalMatConsumed = approvedEntries.reduce((s, e) =>
    s + (e.materialConsumption || []).filter(m => m.qty > 0).length, 0);
  const autoBills = (state.workBills || []).filter(b => b.source === "progress_auto");
  const autoClientBills = (state.clientBills || []).filter(b => b.source === "progress_auto");
  return (
    <div>
      <STitle>Dashboard</STitle>
      <div style={S.cardGrid}>
        <StatCard icon="🏢" label="Projects" value={(state.projects||[]).length} color="#e67e22" />
        <StatCard icon="✅" label="Active" value={(state.projects||[]).filter((p) => p.status === "active").length} color="#27ae60" />
        <StatCard icon="💰" label="Total Budget" value={INR((state.projects||[]).reduce((s, p) => s + (p.budget || 0), 0))} color="#2980b9" />
        <StatCard icon="📅" label="Today Spent" value={INR(todaySpent)} color="#c0392b" />
        <StatCard icon="📦" label="Inventory Items" value={(state.inventory||[]).length} color="#16a085" />
        <StatCard icon="📋" label="Pending Indents" value={(state.indents||[]).filter((i) => i.status === "pending").length} color="#8e44ad" />
      </div>
      {/* ── Pending Approvals Alert ── */}
      {pendingApproval.length > 0 && (
        <div style={{background:"var(--bg-card)",border:"2px solid #f39c12",borderRadius:8,padding:12,marginTop:12,display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
          <div>
            <span style={{color:"#f39c12",fontWeight:700,fontSize:14}}>⏳ {pendingApproval.length} Progress Entries Pending Approval</span>
            <div style={{color:"#aaa",fontSize:12,marginTop:2}}>Approve होने पर MusterRoll, Accounts, Inventory, Bills सब update होंगे</div>
          </div>
          <button style={{...S.btnSm,background:"#f39c12",color:"#000",fontWeight:700}} onClick={()=>setTab("progress")}>
            Review Now →
          </button>
        </div>)}
      {/* ── Live Progress Stats ── */}
      <div style={{...S.cardGrid, marginTop:12}}>
        <StatCard icon="📊" label="Approved Entries" value={approvedEntries.length} color="#27ae60" />
        <StatCard icon="👷" label="Today on Site" value={`${todayMuster.length} Labour`} color="#e67e22" />
        <StatCard icon="🧾" label="Auto Sub-contractor Bills" value={autoBills.length} color="#8e44ad" />
        <StatCard icon="📑" label="Auto Client Bills" value={autoClientBills.length} color="#2980b9" />
      </div>
      {proj && (
        <div style={S.card}>
          <STitle>{proj.name} — Overview</STitle>
          <div style={{ ...S.row, flexWrap: "wrap", gap: 20, marginTop: 8 }}>
            <span>Client: <b>{proj.client}</b></span>
            <span>Budget: <b style={{ color: "#e67e22" }}>{INR(proj.budget)}</b></span>
            <span>Start: <b>{proj.startDate}</b></span>
            <span>End: <b>{proj.endDate}</b></span>
          </div>
          {/* ── Project financials from approved progress ── */}
          {projProgress.length > 0 && (() => {
            const labourCost = projProgress.reduce((s, e) => {
              const mr = state.masterRates;
              return s + [
                ...(e.companyLabour||[]).map(l=>({type:l.type,count:l.count})),
                ...(e.contractorLabour||[]).map(l=>({type:l.type,count:l.count})),
              ].reduce((ss, l) => {
                const rate = mr?.manpower?.find(m=>m.label?.toLowerCase()===l.type?.toLowerCase())?.rate || 500;
                return ss + rate * (l.count||0);
              }, 0);
            }, 0);
            const matCost = projProgress.reduce((s, e) =>
              s + (e.materialConsumption||[]).filter(m=>m.qty>0).reduce((ss, m) => {
                const rate = state.masterRates?.materials?.find(r=>r.name?.toLowerCase().includes(m.material?.toLowerCase().split(" ")[0]))?.rate || 0;
                return ss + m.qty * rate;
              }, 0), 0);
            return (
              <div style={{display:"flex",gap:12,marginTop:10,flexWrap:"wrap"}}>
                <div style={{background:"#0d1a0d",border:"1px solid #27ae6033",borderRadius:6,padding:"8px 14px"}}>
                  <div style={{fontSize:11,color:"#27ae60"}}>Labour Cost (approved)</div>
                  <div style={{fontWeight:700,color:"#fff"}}>{INR(labourCost)}</div>
                </div>
                <div style={{background:"#1a0d0d",border:"1px solid #e74c3c33",borderRadius:6,padding:"8px 14px"}}>
                  <div style={{fontSize:11,color:"#e74c3c"}}>Material Cost (approved)</div>
                  <div style={{fontWeight:700,color:"#fff"}}>{INR(matCost)}</div>
                </div>
                <div style={{background:"#0d0d1a",border:"1px solid #2980b933",borderRadius:6,padding:"8px 14px"}}>
                  <div style={{fontSize:11,color:"#2980b9"}}>Progress Entries</div>
                  <div style={{fontWeight:700,color:"#fff"}}>{projProgress.length} approved</div>
                </div>
              </div>
            );
          })()}
          <ProgressBar pct={getProjPct(proj)} label={`${getProjPct(proj)}% Complete`} style={{ marginTop: 12 }} />
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 12 }}>
            {(proj.substages || []).map((ss) => (
              <span key={ss.id} style={{ ...S.chip,
                background: ss.status === "done" ? "#27ae60" : ss.status === "ongoing" ? "#e67e22" : "#333",
                position: "relative"}}>
                {ss.status === "done" ? "✓ " : ss.status === "ongoing" ? "▶ " : ""}{ss.name}
              </span>))}
          </div>
        </div>)}
      {!proj && (state.projects||[]).length === 0 && (
        <div style={S.empty}>
          <div style={{ fontSize: 60 }}><span>🏗</span></div>
          <div style={{ fontSize: 18, color: "#e67e22", marginTop: 12 }}>Welcome to VinayakBuildTrack</div>
          <button style={{ ...S.btnPrimary, marginTop: 16 }} onClick={() => setTab("projects")}>+ Create First Project</button>
        </div>)}
    </div>
  );
}
// ─── MASTER RATES ─────────────────────────────────────────────────────────────

function MasterRates({ state, upd }) {
  const [tab, setTab] = useState("manpower");
  const [matForm, setMatForm] = useState(null);
  const mr = state.masterRates;
  const updManpowerRate = (key, rate) => {
    upd({ masterRates: { ...mr, manpower: (mr.manpower||[]).map((m) => m.key === key ? { ...m, rate: +rate } : m) } });};
  const saveMat = (mat) => {
    const mats = mat.id
      ? (mr.materials||[]).map((m) => m.id === mat.id ? mat : m)
      : [...(mr.materials||[]), { ...mat, id: uid() }];
    upd({ masterRates: { ...mr, materials: mats } });
    setMatForm(null);};
  const delMat = (id) => upd({ masterRates: { ...mr, materials: (mr.materials||[]).filter((m) => m.id !== id) } });
  return (
    <div>
      <STitle>Master Rates Setup</STitle>
      <div style={{ fontSize: 12, color: "#888", marginBottom: 8 }}>
        यहाँ material और manpower के default rates set करें। Daily log और indent में automatically use होंगे।
        Material की average rate automatically update होगी जब GRN/Receipt होगा।
      </div>
      <div style={{ fontSize: 11, background: "#1a2a1a", border: "1px solid #27ae60", borderRadius: 6, padding: "7px 14px", marginBottom: 12, color: "#7dcea0" }}>
        📊 <b>Rate Source:</b> Bhopal / Madhya Pradesh Market — March 2026
          |  Cement: todaypricerates.com/MP
          |  TMT Steel: civilsite.in (₹57,000–63,000/MT)
          |  Sand/Aggregate: Bhopal market avg
          |  <span style={{color:"#f39c12"}}>⚠ Rates approximate — edit karo apne local market ke hisaab se</span>
      </div>
      <div style={S.tabs}>
        {["manpower", "materials"].map((t) => (
          <button key={t} style={{ ...S.tabBtn, background: tab === t ? "#e67e22" : "#2a2a2a" }} onClick={() => setTab(t)}>
            {t === "manpower" ? "👷 Manpower Rates" : "🧱 Material Rates"}
          </button>))}
      </div>
      {tab === "manpower" && (
        <div style={S.card}>
          <div style={{ fontSize: 12, color: "#888", marginBottom: 12 }}>Daily rate per person (₹/day) — monthly rate for watchman/supervisor</div>
          <table style={S.table}>
            <thead><tr>{["Role", "Rate per Day (₹)", "Monthly (30 days)"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
            <tbody>
              {(mr.manpower||[]).map((m) => (
                <tr key={m.key} style={S.tr}>
                  <td style={S.td}><b>{m.label}</b></td>
                  <td style={S.td}>
                    <input style={{ ...S.input, width: 120 }} type="number" value={m.rate}
                      onChange={(e) => updManpowerRate(m.key, e.target.value)} />
                  </td>
                  <td style={{ ...S.td, color: "#e67e22" }}>{INR(m.rate * 30)}</td>
                </tr>))}
            </tbody>
          </table>
        </div>)}
      {tab === "materials" && (
        <div style={S.card}>
          <div style={S.rowBetween}>
            <div style={{ fontSize: 12, color: "#888" }}>Material rates — GRN के बाद average rate auto-update होती है</div>
            <button style={S.btnPrimary} onClick={() => setMatForm({})}>+ Add Material</button>
          </div>
          {matForm && <MatRateForm data={matForm} onSave={saveMat} onCancel={() => setMatForm(null)} />}
          <table style={{ ...S.table, marginTop: 12 }}>
            <thead><tr>{["Material", "Unit", "Rate (₹)", "Avg Rate", "Actions"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
            <tbody>
              {(mr.materials||[]).map((m) => (
                <tr key={m.id} style={S.tr}>
                  <td style={S.td}><b>{m.name}</b></td>
                  <td style={S.td}>{m.unit}</td>
                  <td style={S.td}>
                    <input style={{ ...S.input, width: 100 }} type="number" value={m.rate}
                      onChange={(e) => upd({ masterRates: { ...mr, materials: (mr.materials||[]).map((x) => x.id === m.id ? { ...x, rate: +e.target.value } : x) } })} />
                  </td>
                  <td style={{ ...S.td, color: "#e67e22" }}>{m.avgRate ? INR(m.avgRate) : "—"}</td>
                  <td style={S.td}>
                    <button style={S.btnSm} onClick={() => setMatForm(m)}>Edit</button>
                    <button style={{ ...S.btnSm, background: "#c0392b", marginLeft: 4 }} onClick={() => delMat(m.id)}>Del</button>
                  </td>
                </tr>))}
            </tbody>
          </table>
        </div>)}
    </div>
  );
}

function MatRateForm({ data, onSave, onCancel }) {
  const [f, setF] = useState({ name: "", unit: "Bags", rate: 0, ...data });
  return (
    <div style={{ ...S.formBox, marginTop: 12 }}>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12 }}>
        <LI label="Material Name" value={f.name} onChange={(v) => setF({ ...f, name: v })} />
        <div>
          <label style={S.label}>Unit</label>
          <select style={S.select} value={f.unit} onChange={(e) => setF({ ...f, unit: e.target.value })}>
            {MATERIAL_UNITS.map((u) => <option key={u}>{u}</option>)}
          </select>
        </div>
        <LI label="Rate (₹)" type="number" value={f.rate} onChange={(v) => setF({ ...f, rate: +v })} />
      </div>
      <div style={{ ...S.row, gap: 8, marginTop: 10 }}>
        <button style={S.btnPrimary} onClick={() => f.name && onSave(f)}>Save</button>
        <button style={S.btnSecondary} onClick={onCancel}>Cancel</button>
      </div>
    </div>
  );
}
