// ─── GRIEVANCE / WHISTLE BLOWER SUBMIT FORM ──────────────────────────────────
function GrievanceSubmitForm({ me, users, type, onSave, onCancel }) {
  const isW = type === "whistle";
  const [title, setTitle] = useState("");
  const [desc,  setDesc]  = useState("");
  const [aType, setAType] = useState(isW ? "person" : "contractor");
  const [aName, setAName] = useState("");
  const [aId,   setAId]   = useState("");
  const [anon,  setAnon]  = useState(false);
  const [urg,   setUrg]   = useState("normal");

  const staff = (users||[]).filter(u => u.id !== me.id);
  const opts  = isW
    ? [["person","Koi Vyakti"],["department","Department"],["process","Process/System"],["other","Anya"]]
    : [["contractor","Sub-contractor"],["labour","Labour"],["staff","Staff Member"],["management","Management"],["other","Anya"]];

  const go = () => {
    if (!title.trim()) { alert("Title daalen।"); return; }
    if (!desc.trim())  { alert("Description daalen।"); return; }
    onSave({ title, description:desc, againstType:aType, againstName:aName, againstId:aId, anonymous:anon, urgency:urg });
  };

  const borderColor = isW ? "#e74c3c" : "#e67e22";
  const titleText   = isW ? "Whistle Blower Report" : "Grievance / Complaint";
  const btnBg       = isW ? "#7b241c" : undefined;

  return (
    <div style={{...S.card, marginBottom:14, border:"1px solid "+borderColor+"44"}}>
      <div style={{fontWeight:700, marginBottom:14, fontSize:14, color:borderColor}}>
        {titleText}
      </div>

      {isW && (
        <label style={{display:"flex", alignItems:"center", gap:8, marginBottom:14,
          cursor:"pointer", background:"#e74c3c11", padding:"8px 12px",
          borderRadius:8, border:"1px solid #e74c3c33"}}>
          <input type="checkbox" checked={anon} onChange={e => setAnon(e.target.checked)} />
          <div>
            <div style={{fontWeight:700, color:"#e74c3c", fontSize:13}}>Anonymous submit</div>
            <div style={{fontSize:11, color:"var(--text-dim)"}}>Aapka naam nahi dikhega</div>
          </div>
        </label>
      )}

      <div style={{marginBottom:10}}>
        <label style={S.label}>Title *</label>
        <input style={S.input} value={title} onChange={e => setTitle(e.target.value)} placeholder="Vishay likhein..." />
      </div>

      <div style={{display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))", gap:10, marginBottom:10}}>
        <div>
          <label style={S.label}>{isW ? "Kiske Khilaf" : "Kiske Khilaf"}</label>
          <select style={S.select} value={aType}
            onChange={e => { setAType(e.target.value); setAId(""); setAName(""); }}>
            {opts.map(([v,l]) => <option key={v} value={v}>{l}</option>)}
          </select>
        </div>
        {aType === "staff" && !isW && (
          <div>
            <label style={S.label}>Staff Member</label>
            <select style={S.select} value={aId}
              onChange={e => { const u=staff.find(x=>x.id===e.target.value); setAId(e.target.value); setAName(u?u.name:""); }}>
              <option value="">-- Select --</option>
              {staff.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
            </select>
          </div>
        )}
        {(aType==="other"||aType==="person"||aType==="department"||aType==="process") && (
          <div>
            <label style={S.label}>Naam / Vivaran</label>
            <input style={S.input} value={aName} onChange={e => setAName(e.target.value)} placeholder="Naam likhein..." />
          </div>
        )}
        <div>
          <label style={S.label}>Urgency</label>
          <select style={S.select} value={urg} onChange={e => setUrg(e.target.value)}>
            <option value="normal">Normal</option>
            <option value="urgent">Urgent</option>
            <option value="critical">Critical</option>
          </select>
        </div>
      </div>

      <div style={{marginBottom:12}}>
        <label style={S.label}>Description *</label>
        <textarea style={{...S.input, minHeight:80, resize:"vertical"}}
          value={desc} onChange={e => setDesc(e.target.value)}
          placeholder="Detail mein likhein..."></textarea>
      </div>

      {isW && (
        <div style={{fontSize:11, color:"var(--text-dim)", background:"var(--bg-input)",
          borderRadius:6, padding:"8px 12px", marginBottom:12}}>
          Strictly confidential — sirf Admin/MD/Director/CEO dekh sakenge.
        </div>
      )}

      <div style={{display:"flex", gap:8}}>
        <button style={{...S.btnPrimary, background:btnBg}} onClick={go}>Submit</button>
        <button style={S.btnSecondary} onClick={onCancel}>Cancel</button>
      </div>
    </div>
  );
}


function SelfServiceModule({ state, upd }) {
  const me         = state.currentUser || {};
  const users      = state.users || [];
  const projects   = state.projects || [];
  const attendance = state.hrAttendance || [];
  const leaveReqs  = state.hrLeave || [];
  const grievances = state.hrGrievances || [];
  const whistles   = state.whistleBlower || [];

  const [tab,       setTab]      = useState("attendance");
  const [attForm,   setAttForm]  = useState(null);
  const [leaveForm, setLeaveForm]= useState(null);
  const [grvForm,   setGrvForm]  = useState(false);
  const [wbForm,    setWbForm]   = useState(false);

  const myAtt      = attendance.filter(a => a.userId === me.id);
  const myLeaves   = leaveReqs.filter(l => l.submittedBy === me.id);
  const todayAtt   = myAtt.filter(a => a.date === today());
  const myRecord   = users.find(u => u.id === me.id) || me;
  const myGrvs     = grievances.filter(g => g.submittedBy === me.id);
  const myWhistles = whistles.filter(w => w.submittedBy === me.id);
  const updMe      = (patch) => upd(patch);

  const myTeam = (users||[]).filter(u => u.reportingTo === me.id);
  const isSenior = myTeam.length > 0;

  const TABS = [
    { id:"attendance",   label:"Attendance" },
    { id:"leaves",       label:"My Leaves" },
    ...(isSenior ? [{ id:"team_leaves", label:"Team Leaves" }] : []),
    { id:"grievance",    label:"Grievance" },
    { id:"whistle",      label:"Whistle Blower" },
    { id:"profile",      label:"My Profile" },
  ];

  return (
    <div>
      <div style={{fontSize:18,fontWeight:800,color:"var(--accent)",marginBottom:14}}>
        My HR — {me.name||"Employee"}
      </div>

      <div style={S.tabs}>
        {TABS.map(t=>(
          <button key={t.id}
            style={{...S.tabBtn,
              background: tab===t.id ? "var(--accent)" : "var(--bg-input)",
              color: tab===t.id ? "#fff" : "var(--text-muted)",
              border: "1px solid " + (tab===t.id ? "var(--accent)" : "var(--border)")}}
            onClick={()=>setTab(t.id)}>
            {t.label}
          </button>
        ))}
      </div>

      {tab==="attendance" && (
        <div>
          <div style={{...S.card, marginBottom:14, border:"2px solid var(--accent)44"}}>
            <div style={{fontWeight:700,color:"var(--accent)",marginBottom:10,fontSize:14}}>
              Aaj ki Attendance — {today()}
            </div>
            {attForm ? (
              <SelfAttendanceForm
                me={me} projects={projects} existing={todayAtt[0]||null}
                onSave={(d)=>{
                  const entry = {
                    ...d, id: todayAtt[0]?.id||uid(),
                    userId:me.id, userName:me.name,
                    date:today(), createdAt:new Date().toISOString(),
                    submittedBy:me.id, status:"pending"
                  };
                  const others = attendance.filter(a=>!(a.userId===me.id&&a.date===today()));
                  updMe({hrAttendance:[...others, entry]});
                  setAttForm(null);
                }}
                onCancel={()=>setAttForm(null)}
              />
            ) : (
              <div style={{display:"flex",alignItems:"center",gap:14,flexWrap:"wrap"}}>
                <div style={{flex:1}}>
                  {todayAtt.length>0 ? (
                    <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
                      <Tag color={todayAtt[0].status==="approved"?"#27ae60":todayAtt[0].status==="rejected"?"#e74c3c":"#f39c12"}>
                        {todayAtt[0].status==="approved"?"Approved":todayAtt[0].status==="rejected"?"Rejected":"Pending"}
                      </Tag>
                      <span style={{fontSize:12,color:"var(--text-muted)"}}>
                        {todayAtt[0].attendanceStatus||"P"}
                        {todayAtt[0].inTime ? " | In: "+todayAtt[0].inTime : ""}
                        {todayAtt[0].outTime ? " | Out: "+todayAtt[0].outTime : ""}
                      </span>
                    </div>
                  ) : (
                    <span style={{fontSize:12,color:"#f39c12",fontWeight:600}}>
                      Aaj ki attendance abhi nahi dali
                    </span>
                  )}
                </div>
                <button style={{...S.btnPrimary,padding:"9px 20px",fontSize:13}}
                  onClick={()=>setAttForm(true)}>
                  {todayAtt.length>0 ? "Update" : "Mark Attendance"}
                </button>
              </div>
            )}
          </div>
          <div style={S.card}>
            <div style={{fontWeight:700,color:"var(--text-muted)",marginBottom:8}}>
              Meri Attendance History
            </div>
            <div style={{overflowX:"auto"}}>
              <table style={S.table}>
                <thead><tr>
                  {["Date","In","Out","Project","P/H/A","Status"].map(h=>(
                    <th key={h} style={S.th}>{h}</th>
                  ))}
                </tr></thead>
                <tbody>
                  {[...myAtt].sort((a,b)=>(b.date||"").localeCompare(a.date||"")).map(a=>{
                    const proj=(projects||[]).find(p=>p.id===a.projectId);
                    return (
                      <tr key={a.id} style={S.tr}>
                        <td style={{...S.td,fontWeight:600}}>{a.date}</td>
                        <td style={{...S.td,color:"#27ae60"}}>{a.inTime||"—"}</td>
                        <td style={{...S.td,color:"#e67e22"}}>{a.outTime||"—"}</td>
                        <td style={{...S.td,fontSize:11}}>{proj?.name||"—"}</td>
                        <td style={S.td}>
                          <Tag color={a.attendanceStatus==="A"?"#e74c3c":a.attendanceStatus==="H"?"#f39c12":"#27ae60"} small>
                            {a.attendanceStatus||"P"}
                          </Tag>
                        </td>
                        <td style={S.td}>
                          <Tag color={a.status==="approved"?"#27ae60":a.status==="rejected"?"#e74c3c":"#888"} small>
                            {a.status}
                          </Tag>
                          {a.status==="pending"&&(
                            <button style={{...S.btnSm,background:"#333",fontSize:9,marginLeft:4}}
                              onClick={()=>updMe({hrAttendance:attendance.filter(x=>x.id!==a.id)})}>
                              X
                            </button>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
              {myAtt.length===0&&<Empty text="Koi attendance record nahi." />}
            </div>
          </div>
        </div>
      )}

      {tab==="leaves" && (
        <div>
          <div style={{marginBottom:12}}>
            <button style={S.btnPrimary} onClick={()=>setLeaveForm(true)}>
              Apply Leave
            </button>
          </div>
          {leaveForm && (
            <LeaveApplyForm
              me={me} users={users}
              onSave={(d)=>{
                const days = d.fromDate&&d.toDate
                  ? Math.max(1,Math.round((new Date(d.toDate)-new Date(d.fromDate))/(86400000))+1)
                  : 1;
                const myRec = (users||[]).find(u=>u.id===me.id);
                const reportingTo = myRec?.reportingTo||null;
                const rPerson = (users||[]).find(u=>u.id===reportingTo);
                updMe({hrLeave:[...leaveReqs,{
                  ...d, id:uid(), days,
                  submittedBy:me.id, submittedByName:me.name,
                  createdAt:new Date().toISOString(), status:"pending",
                  reportingTo, reportingName:rPerson?.name||null,
                  seniorAction:null, seniorActionBy:null, seniorActionAt:null,
                  hrAction:null, hrActionBy:null, hrActionAt:null, hrNote:"",
                }]});
                setLeaveForm(null);
              }}
              onCancel={()=>setLeaveForm(null)}
            />
          )}
          <div style={S.card}>
            <div style={{overflowX:"auto"}}>
              <table style={S.table}>
                <thead><tr>
                  {["Type","From","To","Days","Reason","Senior","HR","Action"].map(h=>(
                    <th key={h} style={S.th}>{h}</th>
                  ))}
                </tr></thead>
                <tbody>
                  {[...myLeaves].sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||"")).map(l=>(
                    <tr key={l.id} style={S.tr}>
                      <td style={S.td}><Tag color="#2980b9" small>{(l.leaveType||"").toUpperCase()}</Tag></td>
                      <td style={S.td}>{l.fromDate}</td>
                      <td style={S.td}>{l.toDate}</td>
                      <td style={{...S.td,fontWeight:700,color:"#e67e22"}}>{l.days||1}</td>
                      <td style={{...S.td,fontSize:11,maxWidth:120}}>{l.reason}</td>
                      <td style={S.td}>
                        <Tag color={l.status==="senior_approved"?"#27ae60":l.status==="senior_rejected"?"#e74c3c":"#888"} small>
                          {l.status==="senior_approved"?"Approved":l.status==="senior_rejected"?"Rejected":"Pending"}
                        </Tag>
                      </td>
                      <td style={S.td}>
                        <Tag color={(l.status==="hr_approved"||l.status==="approved")?"#27ae60":l.status==="rejected"?"#e74c3c":"#888"} small>
                          {(l.status==="hr_approved"||l.status==="approved")?"Approved":l.status==="rejected"?"Rejected":"Pending"}
                        </Tag>
                        {l.hrNote&&<div style={{fontSize:10,color:"#888"}}>{l.hrNote}</div>}
                      </td>
                      <td style={S.td}>
                        {l.status==="pending"&&(
                          <button style={{...S.btnSm,background:"#333",fontSize:10}}
                            onClick={()=>updMe({hrLeave:leaveReqs.filter(x=>x.id!==l.id)})}>
                            Withdraw
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {myLeaves.length===0&&<Empty text="Koi leave request nahi." />}
            </div>
          </div>
        </div>
      )}

      {tab==="grievance" && (
        <div>
          <div style={{...S.card,marginBottom:12,border:"1px solid #e67e2244"}}>
            <div style={{fontSize:12,color:"var(--text-muted)"}}>
              Grievance / Complaint — Kisi bhi samasya ya shikayat darj karein.
              Aapki complaint Company Admin, HR Manager, MD/Director ko dikhai degi.
            </div>
          </div>
          {grvForm ? (
            <GrievanceSubmitForm me={me} users={users} type="grievance"
              onSave={(d)=>{
                updMe({hrGrievances:[...(state.hrGrievances||[]), {
                  ...d, id:uid(), submittedBy:me.id, submittedByName:me.name,
                  createdAt:new Date().toISOString(), status:"open",
                  type:"grievance", resolution:"", resolvedBy:"", resolvedAt:""
                }]});
                setGrvForm(false);
              }}
              onCancel={()=>setGrvForm(false)}
            />
          ) : (
            <button style={{...S.btnPrimary,marginBottom:14}} onClick={()=>setGrvForm(true)}>
              File Grievance
            </button>
          )}
          <div style={S.card}>
            <div style={{fontWeight:700,color:"var(--text-muted)",marginBottom:8}}>Meri Complaints</div>
            {myGrvs.length===0 ? <Empty text="Koi grievance nahi." /> :
              [...myGrvs].sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||"")).map(g=>(
                <div key={g.id} style={{background:"var(--bg-input)",borderRadius:8,
                  padding:"10px 14px",marginBottom:8,border:"1px solid var(--border)"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:6}}>
                    <div>
                      <div style={{fontWeight:700,fontSize:13}}>{g.title}</div>
                      <div style={{fontSize:11,color:"var(--text-dim)",marginTop:2}}>
                        Against: {g.againstName||"—"} | {g.createdAt?.slice(0,10)||"—"}
                      </div>
                      <div style={{fontSize:12,color:"var(--text-muted)",marginTop:4}}>{g.description}</div>
                    </div>
                    <Tag color={g.status==="resolved"?"#27ae60":g.status==="in_progress"?"#f39c12":"#e67e22"}>
                      {g.status==="resolved"?"Resolved":g.status==="in_progress"?"In Progress":"Open"}
                    </Tag>
                  </div>
                  {g.resolution&&(
                    <div style={{marginTop:8,fontSize:12,color:"#27ae60",background:"#27ae6011",
                      padding:"6px 10px",borderRadius:6}}>
                      Resolution: {g.resolution} — {g.resolvedBy}
                    </div>
                  )}
                </div>
              ))
            }
          </div>
        </div>
      )}

      {tab==="whistle" && (
        <div>
          <div style={{...S.card,marginBottom:12,border:"1px solid #e74c3c44"}}>
            <div style={{fontSize:12,color:"var(--text-muted)"}}>
              Whistle Blower — Ghalat kaam, bhrashtachar report karein.
              STRICTLY CONFIDENTIAL — Sirf Admin/MD/Director/CEO ko dikhega. HR ko nahi.
              Aap Anonymous reh sakte hain.
            </div>
          </div>
          {wbForm ? (
            <GrievanceSubmitForm me={me} users={users} type="whistle"
              onSave={(d)=>{
                updMe({whistleBlower:[...(state.whistleBlower||[]), {
                  ...d, id:uid(),
                  submittedBy: d.anonymous ? "anonymous" : me.id,
                  submittedByName: d.anonymous ? "Anonymous" : me.name,
                  createdAt:new Date().toISOString(), status:"open",
                  type:"whistle", resolution:"", resolvedBy:"", resolvedAt:""
                }]});
                setWbForm(false);
              }}
              onCancel={()=>setWbForm(false)}
            />
          ) : (
            <button style={{...S.btnPrimary,marginBottom:14,background:"#7b241c"}}
              onClick={()=>setWbForm(true)}>
              File Whistle Blower Report
            </button>
          )}
          <div style={S.card}>
            <div style={{fontWeight:700,color:"var(--text-muted)",marginBottom:8}}>Meri Reports</div>
            {myWhistles.length===0 ? <Empty text="Koi whistle blower report nahi." /> :
              [...myWhistles].sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||"")).map(w=>(
                <div key={w.id} style={{background:"var(--bg-input)",borderRadius:8,
                  padding:"10px 14px",marginBottom:8,border:"1px solid #e74c3c33"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:6}}>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:700,fontSize:13}}>{w.title}</div>
                      <div style={{fontSize:11,color:"var(--text-dim)",marginTop:2}}>
                        {w.createdAt?.slice(0,10)||"—"}
                        {w.anonymous && <span style={{color:"#888",marginLeft:8}}>Anonymous</span>}
                      </div>
                      <div style={{fontSize:12,color:"var(--text-muted)",marginTop:4}}>{w.description}</div>
                    </div>
                    <Tag color={w.status==="resolved"?"#27ae60":w.status==="in_progress"?"#f39c12":"#e74c3c"}>
                      {w.status==="resolved"?"Resolved":w.status==="in_progress"?"In Progress":"Open"}
                    </Tag>
                  </div>
                  {w.resolution&&(
                    <div style={{marginTop:8,fontSize:12,color:"#27ae60",background:"#27ae6011",
                      padding:"6px 10px",borderRadius:6}}>
                      Resolution: {w.resolution}
                    </div>
                  )}
                </div>
              ))
            }
          </div>
        </div>
      )}


      {tab==="team_leaves" && isSenior && (
        <div>
          <div style={{...S.card, marginBottom:12, border:"1px solid var(--accent)44"}}>
            <div style={{fontWeight:700, color:"var(--accent)", marginBottom:4}}>
              Team Leave Requests
            </div>
            <div style={{fontSize:12, color:"var(--text-dim)"}}>
              Aapki team ke pending leave requests — aap Level 1 approve ya reject kar sakte hain.
              Final approval HR karega.
            </div>
          </div>

          {(()=>{
            const TL = () => {
              const [filter, setFilter] = useState("pending");
              const leaveReqs = state.hrLeave || [];
              const teamIds = myTeam.map(u => u.id);
              const teamLeaves = leaveReqs.filter(l => teamIds.includes(l.submittedBy));
              const filtered = filter === "all" ? teamLeaves
                : teamLeaves.filter(l => {
                    if (filter === "pending") return l.status === "pending";
                    if (filter === "approved") return l.status === "senior_approved" || l.status === "hr_approved" || l.status === "approved";
                    if (filter === "rejected") return l.status === "senior_rejected" || l.status === "rejected";
                    return true;
                  });

              return (
                <div>
                  <div style={{display:"flex", gap:6, marginBottom:12, flexWrap:"wrap"}}>
                    {[
                      ["all",      "All ("+teamLeaves.length+")"],
                      ["pending",  "Pending ("+teamLeaves.filter(l=>l.status==="pending").length+")"],
                      ["approved", "Approved"],
                      ["rejected", "Rejected"],
                    ].map(([v,label]) => (
                      <button key={v} onClick={()=>setFilter(v)}
                        style={{...S.tabBtn, fontSize:11,
                          background: filter===v ? "var(--accent)" : "var(--bg-input)",
                          color: filter===v ? "#fff" : "var(--text-muted)",
                          border: "1px solid "+(filter===v?"var(--accent)":"var(--border)")}}>
                        {label}
                      </button>
                    ))}
                  </div>

                  {filtered.length === 0 ? (
                    <div style={{textAlign:"center", padding:32, color:"var(--text-dim)", fontSize:13}}>
                      Koi leave request nahi.
                    </div>
                  ) : (
                    filtered.sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||"")).map(l => {
                      const isPending = l.status === "pending";
                      const statusColor = l.status==="senior_approved"||l.status==="hr_approved"||l.status==="approved" ? "#27ae60"
                        : l.status==="senior_rejected"||l.status==="rejected" ? "#e74c3c" : "#f39c12";
                      const statusLabel = l.status==="senior_approved" ? "Sr. Approved"
                        : l.status==="hr_approved"||l.status==="approved" ? "HR Approved"
                        : l.status==="senior_rejected" ? "Sr. Rejected"
                        : l.status==="rejected" ? "HR Rejected" : "Pending";

                      return (
                        <div key={l.id} style={{...S.card, marginBottom:10,
                          border:"1px solid "+(isPending?"var(--accent)44":"var(--border)")}}>
                          <div style={{display:"flex", justifyContent:"space-between",
                            alignItems:"flex-start", flexWrap:"wrap", gap:8}}>
                            <div style={{flex:1}}>
                              <div style={{display:"flex", gap:8, alignItems:"center", flexWrap:"wrap", marginBottom:4}}>
                                <span style={{fontWeight:700, fontSize:13}}>{l.submittedByName||"—"}</span>
                                <Tag color="#2980b9" small>{(l.leaveType||"").toUpperCase()}</Tag>
                                {l.urgent && <Tag color="#e74c3c" small>URGENT</Tag>}
                              </div>
                              <div style={{fontSize:12, color:"var(--text-muted)", marginBottom:4}}>
                                {l.fromDate} to {l.toDate}
                                <span style={{fontWeight:700, color:"#e67e22", marginLeft:8}}>{l.days||1} days</span>
                              </div>
                              <div style={{fontSize:12, color:"var(--text-dim)"}}>{l.reason}</div>
                            </div>
                            <div style={{display:"flex", flexDirection:"column", gap:6, alignItems:"flex-end"}}>
                              <Tag color={statusColor} small>{statusLabel}</Tag>
                              {isPending && (
                                <div style={{display:"flex", gap:6}}>
                                  <button
                                    style={{...S.btnSm, background:"#1a3a1a", color:"#27ae60", fontSize:11, padding:"5px 12px"}}
                                    onClick={()=>{
                                      upd({hrLeave:(state.hrLeave||[]).map(x=>x.id===l.id ? {
                                        ...x, status:"senior_approved",
                                        seniorActionBy:me.name, seniorActionAt:today()
                                      } : x)});
                                    }}>
                                    Approve
                                  </button>
                                  <button
                                    style={{...S.btnSm, background:"#3a1a1a", color:"#e74c3c", fontSize:11, padding:"5px 12px"}}
                                    onClick={()=>{
                                      upd({hrLeave:(state.hrLeave||[]).map(x=>x.id===l.id ? {
                                        ...x, status:"senior_rejected",
                                        seniorActionBy:me.name, seniorActionAt:today()
                                      } : x)});
                                    }}>
                                    Reject
                                  </button>
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              );
            };
            return <TL />;
          })()}
        </div>
      )}


      {tab==="profile" && (
        <div>
          <div style={{...S.card,marginBottom:12}}>
            <div style={{fontWeight:700,color:"var(--accent)",marginBottom:12}}>My Details</div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:8,fontSize:12}}>
              {[
                ["Name",          myRecord.name||"—"],
                ["Username",      myRecord.username||"—"],
                ["Role",          USER_ROLES[myRecord.role]?.label||myRecord.role||"—"],
                ["Department",    myRecord.department||"—"],
                ["Phone",         myRecord.phone||"—"],
                ["Email",         myRecord.email||"—"],
                ["Joining Date",  myRecord.joiningDate||"—"],
              ].map(([k,v])=>(
                <div key={k} style={{background:"var(--bg-input)",borderRadius:6,padding:"6px 10px"}}>
                  <div style={{fontSize:10,color:"var(--text-dim)"}}>{k}</div>
                  <div style={{fontWeight:600,color:"var(--text-main)",marginTop:2}}>{v}</div>
                </div>
              ))}
            </div>
          </div>
          <div style={S.card}>
            <div style={{fontWeight:700,color:"var(--accent)",marginBottom:4}}>EPF / ESIC Details</div>
            <div style={{fontSize:11,color:"#f39c12",marginBottom:12,background:"#f39c1211",
              padding:"6px 10px",borderRadius:6}}>
              Read-only — Badlne ke liye HR se sampark karein.
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:8,fontSize:12}}>
              {[
                ["EPF UAN",          myRecord.epfUan||"—"],
                ["EPF Member ID",    myRecord.epfMemberId||"—"],
                ["EPF Joining Date", myRecord.pfJoiningDate||"—"],
                ["ESIC IP No.",      myRecord.esicIpNo||"—"],
                ["ESIC Dispensary",  myRecord.esicDispensary||"—"],
                ["ESIC Joining Date",myRecord.esicJoiningDate||"—"],
                ["PAN No.",          myRecord.panNo||"—"],
                ["Bank Account",     myRecord.bankAccount?"****"+myRecord.bankAccount.slice(-4):"—"],
                ["Bank IFSC",        myRecord.bankIfsc||"—"],
              ].map(([k,v])=>(
                <div key={k} style={{background:"var(--bg-input)",borderRadius:6,padding:"6px 10px"}}>
                  <div style={{fontSize:10,color:"var(--text-dim)"}}>{k}</div>
                  <div style={{fontWeight:600,color:v==="—"?"#666":"var(--text-main)",marginTop:2}}>{v}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}



function DepartmentManager({ departments, onAdd, onRemove }) {
  const [newDept, setNewDept] = useState("");
  const [search,  setSearch]  = useState("");

  const filtered = (departments||[]).filter(d =>
    !search || d.toLowerCase().includes(search.toLowerCase())
  );

  const handleAdd = () => {
    const name = newDept.trim();
    if (!name) { alert("Department naam daalen।"); return; }
    if ((departments||[]).some(d => d.toLowerCase() === name.toLowerCase())) {
      alert("Yeh department pehle se exist karta hai।"); return;
    }
    onAdd && onAdd(name);
    setNewDept("");
  };

  return (
    <div>
      <div style={{...S.card, marginBottom:14}}>
        <div style={{fontWeight:700, color:"var(--accent)", marginBottom:4, fontSize:14}}>
          🏗 Department Management
        </div>
        <div style={{fontSize:12, color:"var(--text-dim)", marginBottom:14}}>
          Yahan add kiye gaye departments saari companies ke employee forms mein automatically dikhenge।
          Abhi <b style={{color:"var(--accent)"}}>{(departments||[]).length}</b> departments hain।
        </div>

        {/* Add new */}
        <div style={{display:"flex", gap:8, marginBottom:16, flexWrap:"wrap"}}>
          <input
            style={{...S.input, flex:1, maxWidth:320}}
            value={newDept}
            onChange={e=>setNewDept(e.target.value)}
            onKeyDown={e=>e.key==="Enter"&&handleAdd()}
            placeholder="Naya department naam..." />
          <button style={{...S.btnPrimary, padding:"8px 20px"}} onClick={handleAdd}>
            ➕ Add Department
          </button>
        </div>

        {/* Search */}
        <input
          style={{...S.input, marginBottom:12, maxWidth:280}}
          value={search}
          onChange={e=>setSearch(e.target.value)}
          placeholder="🔍 Search..." />

        {/* List */}
        <div style={{display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))", gap:8}}>
          {filtered.map((dept, i) => {
            const isDefault = DEFAULT_DEPARTMENTS.includes(dept);
            return (
              <div key={dept} style={{
                display:"flex", alignItems:"center", justifyContent:"space-between",
                background:"var(--bg-input)", borderRadius:8,
                padding:"8px 12px",
                border:`1px solid ${isDefault?"var(--border)":"var(--accent)44"}`,
              }}>
                <div>
                  <span style={{fontSize:13, fontWeight:600, color:"var(--text-main)"}}>{dept}</span>
                  {!isDefault && (
                    <span style={{fontSize:10, color:"var(--accent)", marginLeft:6,
                      background:"var(--accent)22", padding:"1px 6px", borderRadius:4}}>
                      Custom
                    </span>
                  )}
                </div>
                <button
                  style={{...S.btnSm, background:"#c0392b22", color:"#e74c3c",
                    border:"1px solid #e74c3c44", fontSize:11, padding:"3px 8px"}}
                  title="Delete department"
                  onClick={()=>{
                    if(_isWeb&&!window.confirm(`"${dept}" department delete karein?

Purane employees ka department change nahi hoga।`)) return;
                    onRemove && onRemove(dept);
                  }}>
                  🗑
                </button>
              </div>
            );
          })}
        </div>

        {filtered.length === 0 && (
          <div style={{textAlign:"center", padding:24, color:"var(--text-dim)", fontSize:12}}>
            Koi department nahi mila।
          </div>
        )}

        <div style={{marginTop:14, fontSize:11, color:"var(--text-dim)",
          background:"var(--bg-input)", borderRadius:6, padding:"8px 12px"}}>
          💡 <b>Note:</b> Default departments (system ke saath aate hain) delete bhi ho sakte hain।
          Departments globally save hote hain — saari companies mein dikhengte।
        </div>
      </div>
    </div>
  );
}


function LeaveApplyForm({ me, users, onSave, onCancel }) {
  const [lf, setLf] = useState({
    leaveType:"casual", fromDate:today(), toDate:today(),
    reason:"", urgent:false, note:""
  });

  const days = lf.fromDate&&lf.toDate
    ? Math.max(1, Math.round((new Date(lf.toDate)-new Date(lf.fromDate))/(86400000))+1)
    : 1;

  // Find reporting official name to show
  const myRecord = (users||[]).find(u=>u.id===me.id);
  const reportingPerson = (users||[]).find(u=>u.id===myRecord?.reportingTo);

  const submit = () => {
    if(!lf.reason.trim()){ alert("Karan/Reason daalna zaroori hai।"); return; }
    if(lf.toDate < lf.fromDate){ alert("To date, From date se pehle nahi ho sakti।"); return; }
    onSave({...lf, days});
  };

  return (
    <div style={{...S.card, marginBottom:14, border:"1px solid var(--accent)44"}}>
      <div style={{fontWeight:700, color:"var(--accent)", marginBottom:14, fontSize:14}}>
        🏖 Leave Request
      </div>

      {reportingPerson && (
        <div style={{background:"var(--bg-input)",borderRadius:8,padding:"8px 12px",
          marginBottom:12,fontSize:12,color:"var(--text-muted)"}}>
          📋 Aapki request pehle <b style={{color:"var(--accent)"}}>{reportingPerson.name}</b> ({USER_ROLES[reportingPerson.role]?.label||reportingPerson.role}) ke paas jayegi, phir HR approve karega।
        </div>
      )}
      {!reportingPerson && (
        <div style={{background:"var(--bg-input)",borderRadius:8,padding:"8px 12px",
          marginBottom:12,fontSize:12,color:"var(--text-muted)"}}>
          📋 Koi reporting official set nahi — request seedha HR ke paas jayegi।
        </div>
      )}

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:10,marginBottom:10}}>
        <div>
          <label style={S.label}>Leave Type *</label>
          <select style={S.select} value={lf.leaveType}
            onChange={e=>setLf({...lf,leaveType:e.target.value})}>
            {[["casual","Casual Leave"],["sick","Sick Leave"],["earned","Earned Leave"],
              ["emergency","Emergency Leave"],["maternity","Maternity Leave"],
              ["paternity","Paternity Leave"],["unpaid","Unpaid Leave"]
            ].map(([v,lab])=><option key={v} value={v}>{lab}</option>)}
          </select>
        </div>
        <div>
          <label style={S.label}>From Date *</label>
          <input type="date" style={S.input} value={lf.fromDate}
            onChange={e=>setLf({...lf,fromDate:e.target.value})} />
        </div>
        <div>
          <label style={S.label}>To Date *</label>
          <input type="date" style={S.input} value={lf.toDate}
            onChange={e=>setLf({...lf,toDate:e.target.value})} />
        </div>
        <div style={{display:"flex",alignItems:"flex-end",paddingBottom:4}}>
          <span style={{fontSize:16,fontWeight:800,color:"#e67e22"}}>{days}</span>
          <span style={{fontSize:12,color:"var(--text-muted)",marginLeft:4}}>days</span>
        </div>
      </div>

      <div style={{marginBottom:10}}>
        <label style={S.label}>Reason / Karan *</label>
        <input style={S.input} value={lf.reason}
          onChange={e=>setLf({...lf,reason:e.target.value})}
          placeholder="Leave ka karan likhein..." />
      </div>
      <div style={{marginBottom:12}}>
        <label style={S.label}>Additional Note</label>
        <input style={S.input} value={lf.note}
          onChange={e=>setLf({...lf,note:e.target.value})}
          placeholder="Koi extra information..." />
      </div>

      <label style={{display:"flex",alignItems:"center",gap:8,marginBottom:14,cursor:"pointer"}}>
        <input type="checkbox" checked={lf.urgent}
          onChange={e=>setLf({...lf,urgent:e.target.checked})} />
        <span style={{fontSize:13,color:"#e74c3c",fontWeight:600}}>🚨 Urgent Leave</span>
        <span style={{fontSize:11,color:"var(--text-dim)"}}>(Urgent mein jaldi approve karna hoga)</span>
      </label>

      <div style={{display:"flex",gap:8}}>
        <button style={{...S.btnPrimary,padding:"9px 22px"}} onClick={submit}>
          📤 Submit Request
        </button>
        <button style={{...S.btnSecondary,padding:"9px 14px"}} onClick={onCancel}>
          Cancel
        </button>
      </div>
    </div>
  );
}


function SelfAttendanceForm({ me, projects, existing, onSave, onCancel }) {
  const [status, setStatus]     = useState(existing?.attendanceStatus||"P");
  const [inTime, setInTime]     = useState(existing?.inTime||"09:00");
  const [outTime, setOutTime]   = useState(existing?.outTime||"");
  const [projectId, setProjectId] = useState(existing?.projectId||"");
  const [note, setNote]         = useState(existing?.note||"");

  const statusOpts = [
    {val:"P", label:"Present",    color:"#27ae60"},
    {val:"H", label:"Half Day",   color:"#f39c12"},
    {val:"A", label:"Absent",     color:"#e74c3c"},
    {val:"L", label:"Leave",      color:"#8e44ad"},
    {val:"WO",label:"Week Off",   color:"#2980b9"},
    {val:"HD",label:"Holiday",    color:"#16a085"},
  ];

  const save = () => {
    onSave({ attendanceStatus:status, inTime, outTime, projectId, note });
  };

  return (
    <div style={{background:"var(--bg-input)",borderRadius:10,padding:"14px 16px",border:"1px solid var(--accent)44"}}>
      <div style={{fontWeight:700,color:"var(--accent)",marginBottom:12}}>✅ Attendance Mark Karein</div>

      {/* Status buttons */}
      <div style={{marginBottom:14}}>
        <label style={S.label}>Aaj ka Status *</label>
        <div style={{display:"flex",gap:8,flexWrap:"wrap",marginTop:6}}>
          {statusOpts.map(opt=>(
            <button key={opt.val}
              onClick={()=>setStatus(opt.val)}
              style={{
                padding:"8px 16px", borderRadius:8, border:`2px solid ${opt.color}`,
                background: status===opt.val ? opt.color : "transparent",
                color: status===opt.val ? "#fff" : opt.color,
                fontWeight:700, cursor:"pointer", fontSize:12,
                transition:"all 0.15s"
              }}>
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:10,marginBottom:12}}>
        {(status==="P"||status==="H") && <>
          <div>
            <label style={S.label}>In Time</label>
            <input type="time" style={S.input} value={inTime}
              onChange={e=>setInTime(e.target.value)} />
          </div>
          <div>
            <label style={S.label}>Out Time</label>
            <input type="time" style={S.input} value={outTime}
              onChange={e=>setOutTime(e.target.value)} />
          </div>
        </>}
        <div>
          <label style={S.label}>Project (optional)</label>
          <select style={S.select} value={projectId} onChange={e=>setProjectId(e.target.value)}>
            <option value="">-- Select --</option>
            {(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>
        <div>
          <label style={S.label}>Note</label>
          <input style={S.input} value={note} onChange={e=>setNote(e.target.value)}
            placeholder="Optional note..." />
        </div>
      </div>

      <div style={{display:"flex",gap:8}}>
        <button style={{...S.btnPrimary,padding:"8px 20px"}} onClick={save}>
          💾 Submit
        </button>
        <button style={{...S.btnSecondary,padding:"8px 14px"}} onClick={onCancel}>
          Cancel
        </button>
      </div>
      <div style={{fontSize:10,color:"var(--text-dim)",marginTop:8}}>
        ℹ️ Submit hone ke baad HR approve/reject karega।
      </div>
    </div>
  );
}

// ─── STAFF ATTENDANCE FORM (HR adds/edits attendance for any employee) ───────
function StaffAttendanceForm({ users, projects, me, editData, onSave, onCancel }) {
  const isEdit = !!(editData?._editId);
  const [userId, setUserId]       = useState(editData?.userId||"");
  const [status, setStatus]       = useState(editData?.attendanceStatus||"P");
  const [inTime, setInTime]       = useState(editData?.inTime||"09:00");
  const [outTime, setOutTime]     = useState(editData?.outTime||"17:00");
  const [projectId, setProjectId] = useState(editData?.projectId||"");
  const [date, setDate]           = useState(editData?.date||today());
  const [note, setNote]           = useState(editData?.note||"");

  const selUser = (users||[]).find(u=>u.id===userId);
  const save = () => {
    if(!userId){ alert("Employee select karein।"); return; }
    onSave({
      _editId: editData?._editId||null,
      userId, userName: editData?.userName||selUser?.name||"",
      attendanceStatus:status, inTime, outTime,
      projectId, date, note
    });
  };

  return (
    <div>
      <div style={{fontWeight:700,color:"var(--accent)",marginBottom:12}}>
        {isEdit?"✏️ Edit Attendance":"+ Attendance Entry"}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(170px,1fr))",gap:10,marginBottom:12}}>
        <div>
          <label style={S.label}>Employee *</label>
          {isEdit ? (
            <div style={{...S.input,color:"var(--text-muted)",fontSize:12}}>
              {editData?.userName||selUser?.name||"—"}
            </div>
          ) : (
            <select style={S.select} value={userId} onChange={e=>setUserId(e.target.value)}>
              <option value="">-- Select --</option>
              {(users||[]).map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
            </select>
          )}
        </div>
        <div>
          <label style={S.label}>Date *</label>
          <input type="date" style={S.input} value={date} onChange={e=>setDate(e.target.value)} />
        </div>
        <div>
          <label style={S.label}>Status *</label>
          <select style={S.select} value={status} onChange={e=>setStatus(e.target.value)}>
            {[["P","Present"],["H","Half Day"],["A","Absent"],["L","Leave"],["WO","Week Off"],["HD","Holiday"]].map(([v,l])=>(
              <option key={v} value={v}>{l}</option>
            ))}
          </select>
        </div>
        <div>
          <label style={S.label}>In Time</label>
          <input type="time" style={S.input} value={inTime} onChange={e=>setInTime(e.target.value)} />
        </div>
        <div>
          <label style={S.label}>Out Time</label>
          <input type="time" style={S.input} value={outTime} onChange={e=>setOutTime(e.target.value)} />
        </div>
        <div>
          <label style={S.label}>Project</label>
          <select style={S.select} value={projectId} onChange={e=>setProjectId(e.target.value)}>
            <option value="">-- None --</option>
            {(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>
        <div>
          <label style={S.label}>Note</label>
          <input style={S.input} value={note} onChange={e=>setNote(e.target.value)}
            placeholder="Optional note..." />
        </div>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button style={{...S.btnPrimary,padding:"8px 20px"}} onClick={save}>
          💾 {isEdit?"Update":"Save"}
        </button>
        <button style={{...S.btnSecondary,padding:"8px 14px"}} onClick={onCancel}>Cancel</button>
      </div>
    </div>
  );
}



// ─── COMPLIANCE TAB (EPF/ESIC) — extracted from IIFE to fix hooks violation ──
function EPFESICDepForm({ saveDeposit, contractors, onClose }) {
  const [df,setDf] = useState({
    challanType:"EPF",month:"",year:new Date().getFullYear()+"",
    wagesTotal:0,epfEmployee:0,epfEmployer:0,eps:0,edli:0,adminCharges:0,
    esicEmployee:0,esicEmployer:0,totalDeposited:0,
    challanNo:"",depositDate:today(),bank:"",
    forType:"company",contractorId:"",remarks:""
  });
  const autoCalcEpf = (wages) => {
    const w=+wages||0;
    setDf(d=>({...d,wagesTotal:w,
      epfEmployee:Math.round(w*0.12),epfEmployer:Math.round(w*0.0367),
      eps:Math.round(w*0.0833),edli:Math.round(w*0.005),
      adminCharges:Math.round(w*0.005),
      totalDeposited:Math.round(w*0.12)+Math.round(w*0.0367)+Math.round(w*0.0833)+Math.round(w*0.005)+Math.round(w*0.005)
    }));
  };
  const autoCalcEsic = (wages) => {
    const w=+wages||0;
    setDf(d=>({...d,wagesTotal:w,
      esicEmployee:Math.round(w*0.0075),esicEmployer:Math.round(w*0.0325),
      totalDeposited:Math.round(w*0.0075)+Math.round(w*0.0325)
    }));
  };
  const MONTHS=["January","February","March","April","May","June","July","August","September","October","November","December"];
  return (
    <div style={S.formBox}>
      <div style={S.formTitle}>🏛 EPF / ESIC Challan Entry</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:10,marginBottom:12}}>
        <div>
          <label style={S.label}>Challan Type</label>
          <select style={S.select} value={df.challanType} onChange={e=>setDf({...df,challanType:e.target.value})}>
            <option>EPF</option><option>ESIC</option><option>Both</option>
          </select>
        </div>
        <div>
          <label style={S.label}>For</label>
          <select style={S.select} value={df.forType} onChange={e=>setDf({...df,forType:e.target.value})}>
            <option value="company">Company / Direct</option>
            <option value="contractor">Sub-contractor</option>
          </select>
        </div>
        {df.forType==="contractor"&&(
          <div>
            <label style={S.label}>Sub-contractor</label>
            <select style={S.select} value={df.contractorId} onChange={e=>setDf({...df,contractorId:e.target.value})}>
              <option value="">— Select —</option>
              {contractors.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
        )}
        <div>
          <label style={S.label}>Month</label>
          <select style={S.select} value={df.month} onChange={e=>setDf({...df,month:e.target.value})}>
            <option value="">— Select —</option>
            {MONTHS.map(m=><option key={m}>{m}</option>)}
          </select>
        </div>
        <LI label="Year" value={df.year} onChange={v=>setDf({...df,year:v})} />
        <LI label="Challan No." value={df.challanNo} onChange={v=>setDf({...df,challanNo:v})} />
        <LI label="Deposit Date" type="date" value={df.depositDate} onChange={v=>setDf({...df,depositDate:v})} />
        <LI label="Bank" value={df.bank} onChange={v=>setDf({...df,bank:v})} />
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
        <div>
          <div style={{fontSize:12,fontWeight:700,color:"#2980b9",marginBottom:6}}>Auto Calculate</div>
          <div style={{display:"flex",gap:6}}>
            <LI label="Gross Wages (₹)" type="number" value={df.wagesTotal||""} onChange={v=>{ if(df.challanType!=="ESIC") autoCalcEpf(v); else autoCalcEsic(v); }} />
          </div>
        </div>
        <div>
          <div style={{fontSize:11,color:"#666",marginBottom:4}}>EPF: Employee 12% + Employer 13.15% | ESIC: Emp 0.75% + Emplr 3.25%</div>
        </div>
      </div>
      {(df.challanType==="EPF"||df.challanType==="Both")&&(
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))",gap:8,marginBottom:8}}>
          <LI label="EPF Employee (12%)" type="number" value={df.epfEmployee||""} onChange={v=>setDf({...df,epfEmployee:+v})} />
          <LI label="EPF Employer (3.67%)" type="number" value={df.epfEmployer||""} onChange={v=>setDf({...df,epfEmployer:+v})} />
          <LI label="EPS (8.33%)" type="number" value={df.eps||""} onChange={v=>setDf({...df,eps:+v})} />
          <LI label="EDLI (0.5%)" type="number" value={df.edli||""} onChange={v=>setDf({...df,edli:+v})} />
          <LI label="Admin Charges" type="number" value={df.adminCharges||""} onChange={v=>setDf({...df,adminCharges:+v})} />
        </div>
      )}
      {(df.challanType==="ESIC"||df.challanType==="Both")&&(
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))",gap:8,marginBottom:8}}>
          <LI label="ESIC Employee (0.75%)" type="number" value={df.esicEmployee||""} onChange={v=>setDf({...df,esicEmployee:+v})} />
          <LI label="ESIC Employer (3.25%)" type="number" value={df.esicEmployer||""} onChange={v=>setDf({...df,esicEmployer:+v})} />
        </div>
      )}
      <div style={{background:"#111",borderRadius:6,padding:"8px 12px",display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
        <span style={{fontSize:12,color:"#aaa",flex:1}}>Total Deposited (₹)</span>
        <input type="number" style={{...S.input,width:140,fontWeight:700,fontSize:14,color:"#27ae60"}}
          value={df.totalDeposited||""} onChange={e=>setDf({...df,totalDeposited:+e.target.value})} />
      </div>
      <LI label="Remarks" value={df.remarks||""} onChange={v=>setDf({...df,remarks:v})} />
      <div style={{display:"flex",gap:8,marginTop:10}}>
        <button style={{...S.btnPrimary,background:"#2980b9"}}
          onClick={()=>df.month&&df.totalDeposited>0&&(saveDeposit(df),onClose())}>
          Save Deposit Record
        </button>
        <button style={S.btnSecondary} onClick={onClose}>Cancel</button>
      </div>
    </div>
  );
}

function ComplianceTab({ state, users, updHR, me, contractors }) {
  const deposits    = state.epfEsicDeposits || [];
  const allLabour   = state.manpowerMaster  || [];
  const allEmps     = users || [];

  const empWithEpf  = allEmps.filter(u=>u.epfUan).length;
  const labWithEpf  = allLabour.filter(l=>l.epfUan).length;
  const empWithEsic = allEmps.filter(u=>u.esicIpNo).length;
  const labWithEsic = allLabour.filter(l=>l.esicIpNo).length;

  const [depForm, setDepForm] = useState(null);
  const [depTab,  setDepTab]  = useState("summary");

  const saveDeposit = (d) => {
    updHR({epfEsicDeposits:[...deposits,{...d,id:uid(),createdAt:today(),createdBy:me.name}]});
  };

  return (
    <div>
      {/* KPI Strip */}
      <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
        {[
          {icon:"🏛",label:"Emp w/ EPF",val:empWithEpf,color:"#2980b9"},
          {icon:"🏥",label:"Emp w/ ESIC",val:empWithEsic,color:"#8e44ad"},
          {icon:"👷",label:"Labour w/ EPF",val:labWithEpf,color:"#27ae60"},
          {icon:"💊",label:"Labour w/ ESIC",val:labWithEsic,color:"#e67e22"},
          {icon:"📋",label:"Deposit Records",val:deposits.length,color:"#e74c3c"},
        ].map(c=>(
          <div key={c.label} style={{flex:"1 1 100px",background:"#111",border:"1px solid #2a2a2a",
            borderRadius:8,padding:"8px 12px",minWidth:90}}>
            <div style={{fontSize:11,color:"#666"}}>{c.icon} {c.label}</div>
            <div style={{fontSize:20,fontWeight:800,color:c.color,marginTop:2}}>{c.val}</div>
          </div>
        ))}
      </div>

      {/* Deposit Form */}
      {depForm && (
        <EPFESICDepForm
          saveDeposit={saveDeposit}
          contractors={contractors||[]}
          onClose={()=>setDepForm(null)}
        />
      )}

      {/* Sub-tabs */}
      <div style={S.tabs}>
        {["summary","deposits","epf_register","esic_register"].map(t=>(
          <button key={t} style={{...S.tabBtn,background:depTab===t?"#2980b9":"#2a2a2a"}}
            onClick={()=>setDepTab(t)}>
            {t==="summary"?"📊 Summary":t==="deposits"?"💳 Challan Records":t==="epf_register"?"🏛 EPF Register":"🏥 ESIC Register"}
          </button>
        ))}
      </div>

      {!depForm && depTab==="summary" && (
        <div>
          <div style={{...S.rowBetween,marginBottom:8}}>
            <div style={{fontSize:13,fontWeight:700,color:"var(--text-main)"}}>EPF / ESIC Overview</div>
            <button style={{...S.btnPrimary,background:"#2980b9"}} onClick={()=>setDepForm(true)}>
              + New Challan Entry
            </button>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <div style={{...S.card,border:"1px solid #2980b933"}}>
              <div style={{fontSize:12,fontWeight:700,color:"#2980b9",marginBottom:8}}>🏛 EPF Status</div>
              <div style={{fontSize:12,color:"var(--text-dim)"}}>Employees registered: <b style={{color:"#2980b9"}}>{empWithEpf}</b></div>
              <div style={{fontSize:12,color:"var(--text-dim)"}}>Labour registered: <b style={{color:"#2980b9"}}>{labWithEpf}</b></div>
              <div style={{fontSize:11,color:"#666",marginTop:6}}>Rate: Employee 12% + Employer 13.15%</div>
            </div>
            <div style={{...S.card,border:"1px solid #8e44ad33"}}>
              <div style={{fontSize:12,fontWeight:700,color:"#8e44ad",marginBottom:8}}>🏥 ESIC Status</div>
              <div style={{fontSize:12,color:"var(--text-dim)"}}>Employees registered: <b style={{color:"#8e44ad"}}>{empWithEsic}</b></div>
              <div style={{fontSize:12,color:"var(--text-dim)"}}>Labour registered: <b style={{color:"#8e44ad"}}>{labWithEsic}</b></div>
              <div style={{fontSize:11,color:"#666",marginTop:6}}>Rate: Employee 0.75% + Employer 3.25%</div>
            </div>
          </div>
        </div>
      )}

      {depTab==="deposits" && (
        <div>
          <div style={S.rowBetween}>
            <div style={{fontSize:13,fontWeight:700}}>Challan Deposit Records</div>
            <button style={{...S.btnPrimary,background:"#2980b9"}} onClick={()=>setDepForm(true)}>+ New Entry</button>
          </div>
          <div style={{overflowX:"auto",marginTop:8}}>
            <table style={S.table}>
              <thead><tr>
                {["Month/Year","Type","Challan No","Deposit Date","Bank","Total (₹)","By"].map(h=>(
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {deposits.length===0&&(
                  <tr><td colSpan={7} style={{...S.td,textAlign:"center",color:"#555",padding:20}}>
                    Koi deposit record nahi hai
                  </td></tr>
                )}
                {deposits.map(d=>(
                  <tr key={d.id} style={S.tr}>
                    <td style={S.td}>{d.month} {d.year}</td>
                    <td style={S.td}><Tag color="#2980b9" small>{d.challanType}</Tag></td>
                    <td style={{...S.td,fontWeight:700}}>{d.challanNo||"—"}</td>
                    <td style={S.td}>{d.depositDate}</td>
                    <td style={S.td}>{d.bank||"—"}</td>
                    <td style={{...S.td,color:"#27ae60",fontWeight:700}}>{INR(d.totalDeposited)}</td>
                    <td style={{...S.td,fontSize:11}}>{d.createdBy}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {depTab==="epf_register" && (
        <div>
          <div style={{fontSize:13,fontWeight:700,marginBottom:8}}>EPF Registered Members</div>
          <table style={S.table}>
            <thead><tr>
              {["Name","Type","UAN No","Member ID","PF Joining"].map(h=><th key={h} style={S.th}>{h}</th>)}
            </tr></thead>
            <tbody>
              {[...allEmps.filter(u=>u.epfUan).map(u=>({...u,_type:"Staff"})),
                ...allLabour.filter(l=>l.epfUan).map(l=>({...l,_type:"Labour"}))
              ].map(u=>(
                <tr key={u.id} style={S.tr}>
                  <td style={{...S.td,fontWeight:700}}>{u.name}</td>
                  <td style={S.td}><Tag color="#2980b9" small>{u._type}</Tag></td>
                  <td style={S.td}>{u.epfUan}</td>
                  <td style={S.td}>{u.epfMemberId||"—"}</td>
                  <td style={S.td}>{u.pfJoiningDate||"—"}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {depTab==="esic_register" && (
        <div>
          <div style={{fontSize:13,fontWeight:700,marginBottom:8}}>ESIC Registered Members</div>
          <table style={S.table}>
            <thead><tr>
              {["Name","Type","IP No","Dispensary","ESIC Joining"].map(h=><th key={h} style={S.th}>{h}</th>)}
            </tr></thead>
            <tbody>
              {[...allEmps.filter(u=>u.esicIpNo).map(u=>({...u,_type:"Staff"})),
                ...allLabour.filter(l=>l.esicIpNo).map(l=>({...l,_type:"Labour"}))
              ].map(u=>(
                <tr key={u.id} style={S.tr}>
                  <td style={{...S.td,fontWeight:700}}>{u.name}</td>
                  <td style={S.td}><Tag color="#8e44ad" small>{u._type}</Tag></td>
                  <td style={S.td}>{u.esicIpNo}</td>
                  <td style={S.td}>{u.esicDispensary||"—"}</td>
                  <td style={S.td}>{u.esicJoiningDate||"—"}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function UserManagement({ state, upd, globalDepartments, addGlobalDepartment, removeGlobalDepartment }) {
  // ─── HR Module ────────────────────────────────────────────────────
  const [tab,        setTab]        = useState("employees");
  const [empForm,    setEmpForm]    = useState(null);
  const [attForm,    setAttForm]    = useState(null);
  const [leaveForm,  setLeaveForm]  = useState(null);
  const [grvForm,    setGrvForm]    = useState(null);
  const [penForm,    setPenForm]    = useState(null);
  const [myPwd,      setMyPwd]      = useState(null);
  const [searchQ,    setSearchQ]    = useState("");

  const me          = state.currentUser || {};
  const ADMIN_ROLES = ["master_admin","managing_director","director","ceo","project_director","it_admin"];
  const isMaster    = me.isMaster || ADMIN_ROLES.includes(me.role);
  const isHR        = isMaster || me.role==="hr_manager" || me.role==="hr_executive" || me.role==="hr_assistant";
  const users       = state.users || [];
  const projects    = state.projects || [];
  const attendance  = state.hrAttendance || [];
  const leaveReqs   = state.hrLeave || [];
  const grievances  = state.hrGrievances || [];
  const penalties   = state.hrPenalties || [];

  // ── helpers ──────────────────────────────────────────────────────
  const updHR = (patch) => upd(patch);
  const myTeam = isHR ? users : users.filter(u=>u.reportingTo===me.id || u.id===me.id);

  const MODULE_LIST = [
    {id:"dashboard",      label:"Dashboard"},
    {id:"projects",       label:"Projects"},
    {id:"clients",        label:"Clients"},
    {id:"contractors",    label:"Sub-contractors"},
    {id:"suppliers",      label:"Suppliers"},
    {id:"workorders",     label:"Work Orders"},
    {id:"schedule",       label:"Schedule"},
    {id:"execution",      label:"Execution"},
    {id:"material",       label:"Materials"},
    {id:"manpower",       label:"Manpower"},
    {id:"musterroll",     label:"Muster Roll"},
    {id:"resources",      label:"Equipment"},
    {id:"accounts",       label:"Accounts"},
    {id:"indent",         label:"Indent"},
    {id:"procurement",    label:"Procurement"},
    {id:"purchaseorder",  label:"Purchase Orders"},
    {id:"grn",            label:"GRN"},
    {id:"inventory",      label:"Inventory"},
    {id:"dailyprogress",  label:"Daily Progress"},
    {id:"fieldmb",        label:"Field Entry (MB)"},
    {id:"measurementbook",label:"Measurement Book"},
    {id:"itemmaster",     label:"Item Master"},
    {id:"matmaster",      label:"Material Master"},
    {id:"master",         label:"Rate Master"},
    {id:"users",          label:"HR Module"},
    {id:"attendance_self",label:"My Attendance"},
    {id:"create_project", label:"Create Project ⚡"},
    {id:"create_client",  label:"Create Client ⚡"},
    {id:"create_proposal",label:"Create Proposal ⚡"},
  ];

  const APPROVAL_MODULES = [
    {id:"indent_approve",     label:"Indent Approval"},
    {id:"grn_approve",        label:"GRN Approval"},
    {id:"progress_approve",   label:"Progress Approval"},
    {id:"field_mb_approve",   label:"Field MB Approval"},
    {id:"material_issue_approve", label:"Material Issue Approval"},
    {id:"leave_approve",      label:"Leave Approval"},
    {id:"attendance_approve", label:"Attendance Approval"},
    {id:"bill_approve",       label:"Bill Approval"},
    {id:"payment_approve",    label:"Payment Approval"},
    {id:"procurement_approve",label:"Procurement Approval"},
  ];

  const ROLE_LIST = [
    // Top Management
    {id:"managing_director",   label:"Managing Director"},
    {id:"director",            label:"Director"},
    {id:"ceo",                 label:"CEO / Owner"},
    {id:"project_director",    label:"Project Director"},
    // Project Management
    {id:"project_manager",       label:"Project Manager"},
    {id:"deputy_project_manager",label:"Deputy Project Manager"},
    {id:"project_coordinator",   label:"Project Coordinator"},
    {id:"operations_manager",    label:"Operations Manager"},
    {id:"planning_engineer",     label:"Planning Engineer"},
    {id:"contract_manager",      label:"Contract Manager"},
    // Engineering
    {id:"chief_engineer",      label:"Chief Engineer"},
    {id:"civil_engineer",      label:"Civil Engineer"},
    {id:"project_engineer",    label:"Project Engineer"},
    {id:"site_engineer",       label:"Site Engineer"},
    {id:"junior_engineer",     label:"Junior Engineer (JE)"},
    {id:"structural_engineer", label:"Structural Engineer"},
    {id:"electrical_engineer", label:"Electrical Engineer"},
    {id:"mechanical_engineer", label:"Mechanical Engineer"},
    {id:"quality_engineer",    label:"Quality Engineer / QC"},
    {id:"safety_officer",      label:"Safety Officer / HSE"},
    {id:"billing_engineer",    label:"Billing Engineer"},
    {id:"estimator",           label:"Estimator / BOQ Engineer"},
    {id:"autocad_engineer",    label:"AutoCAD / Draftsman"},
    // Site
    {id:"site_supervisor",  label:"Site Supervisor"},
    {id:"supervisor",       label:"Supervisor / Mistri"},
    {id:"foreman",          label:"Foreman"},
    // Procurement & Store
    {id:"procurement_manager", label:"Procurement Manager"},
    {id:"store_manager",       label:"Store Manager / Store Keeper"},
    {id:"purchase_officer",    label:"Purchase Officer"},
    // Accounts & Finance
    {id:"accounts_manager", label:"Accounts Manager"},
    {id:"accountant",       label:"Accountant"},
    // HR & Admin
    {id:"hr_manager",   label:"HR Manager"},
    {id:"hr_executive", label:"HR Executive"},
    {id:"admin_officer",label:"Admin Officer"},
    // Labour & Field
    {id:"labour_contractor", label:"Labour Contractor"},
    {id:"machine_operator",  label:"Machine Operator"},
    {id:"driver",            label:"Driver / Transport"},
    // IT & Other
    {id:"it_admin",   label:"IT Admin / ERP Admin"},
    {id:"intern",     label:"Intern / Trainee"},
    {id:"consultant", label:"Consultant / Advisor"},
  ];

  const genPwd = () => Math.random().toString(36).slice(2,8).toUpperCase();

  // ── Save Employee ─────────────────────────────────────────────────
  const saveEmployee = (d) => {
    const isNew = !d.id;
    if (isNew) {
      const exists = users.find(u=>u.username===d.username);
      if (exists) { alert("Username already exists!"); return; }
      const newUser = {...d, id:uid(), createdAt:today(),
        password: d.password||genPwd(), rights: d.rights||[], approvalRights: d.approvalRights||[]};
      updHR({users:[...users, newUser]});
    } else {
      updHR({users: users.map(u=>u.id===d.id?{...u,...d}:u)});
    }
    setEmpForm(null);
  };

  const deleteEmployee = (id) => {
    if(_isWeb && !window.confirm("Delete this employee?")) return;
    updHR({users: users.filter(u=>u.id!==id)});
  };

  // ── Attendance ────────────────────────────────────────────────────
  const saveAttendance = (d) => {
    const entry = {...d, id:uid(), createdAt:new Date().toISOString(),
      submittedBy:me.id, status:"pending"};
    updHR({hrAttendance:[...attendance, entry]});
    setAttForm(null);
  };

  const approveAtt = (id) => {
    updHR({hrAttendance: attendance.map(a=>a.id===id
      ?{...a,status:"approved",approvedBy:me.name,approvedAt:today()}:a)});
  };
  const rejectAtt = (id) => {
    updHR({hrAttendance: attendance.map(a=>a.id===id
      ?{...a,status:"rejected",rejectedBy:me.name}:a)});
  };

  // ── Leave ─────────────────────────────────────────────────────────
  const saveLeave = (d) => {
    updHR({hrLeave:[...leaveReqs,{...d,id:uid(),submittedBy:me.id,
      submittedByName:me.name,createdAt:today(),status:"pending"}]});
    setLeaveForm(null);
  };
  const approveLeave = (id,action) => {
    updHR({hrLeave: leaveReqs.map(l=>l.id===id
      ?{...l,status:action,actionBy:me.name,actionAt:today()}:l)});
  };

  // ── Grievance ─────────────────────────────────────────────────────
  const saveGrievance = (d) => {
    updHR({hrGrievances:[...grievances,{...d,id:uid(),
      submittedBy:me.id,submittedByName:me.name,createdAt:today(),status:"open"}]});
    setGrvForm(null);
  };
  const resolveGrievance = (id,resolution) => {
    updHR({hrGrievances: grievances.map(g=>g.id===id
      ?{...g,status:"resolved",resolution,resolvedBy:me.name,resolvedAt:today()}:g)});
  };

  // ── Penalty ───────────────────────────────────────────────────────
  const savePenalty = (d) => {
    updHR({hrPenalties:[...penalties,{...d,id:uid(),
      imposedBy:me.id,imposedByName:me.name,createdAt:today(),status:"active"}]});
    setPenForm(null);
  };

  const TAB_LIST = [
    {id:"employees",  icon:"👤", label:"Employees"},
    {id:"attendance", icon:"🕐", label:"Attendance"},
    {id:"leaves",     icon:"🏖", label:"Leave Requests"},
    {id:"grievances", icon:"📢", label:"Grievances"},
    {id:"penalties",  icon:"⚠️", label:"Penalties"},
    {id:"compliance", icon:"🏛", label:"EPF / ESIC"},
    ...(isHR?[{id:"departments",icon:"🏗",label:"Departments"}]:[]),
    ...(isMaster?[{id:"whistleblower",icon:"🔔",label:"Whistle Blower"}]:[]),
    ...(me.id?[{id:"myprofile", icon:"🪪", label:"My Profile"}]:[]),
  ];

  // ──────────────────────────────────────────────────────────────────
  // EMPLOYEE FORM
  // ──────────────────────────────────────────────────────────────────
  const EmployeeForm = ({initial, onSave, onCancel}) => {
    const isNew = !initial?.id;
    const [f, setF] = useState({
      name:"", username:"", password:"", role:"project_engineer",
      designation:"", department:"", phone:"", email:"",
      reportingTo:"", projects:[], rights:["attendance_self","myprofile_self",], approvalRights:[],
      joiningDate:today(), salary:0, address:"", docs:[],
      ...initial
    });
    const [showPwd, setShowPwd] = useState(false);
    const seniors = users.filter(u=>u.id!==f.id);

    const toggleRight = (id) => {
      const r = f.rights||[];
      setF({...f, rights: r.includes(id)?r.filter(x=>x!==id):[...r,id]});
    };
    const toggleApproval = (id) => {
      const r = f.approvalRights||[];
      setF({...f, approvalRights: r.includes(id)?r.filter(x=>x!==id):[...r,id]});
    };
    const toggleProject = (pid) => {
      const r = f.projects||[];
      setF({...f, projects: r.includes(pid)?r.filter(x=>x!==pid):[...r,pid]});
    };

    return (
      <div style={S.formBox}>
        <div style={S.formTitle}>{isNew?"👤 New Employee Register":"✏️ Edit Employee"}</div>

        {/* Basic Info */}
        <div style={{fontWeight:700,color:"#e67e22",fontSize:12,marginBottom:8}}>📋 Basic Information</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(170px,1fr))",gap:10,marginBottom:14}}>
          <LI label="Full Name *" value={f.name} onChange={v=>setF({...f,name:v})} />
          <LI label="Username *" value={f.username} onChange={v=>setF({...f,username:v.replace(/\s/g,"")})} />
          <div>
            <label style={S.label}>Password {isNew?"(auto-gen if blank)":""}</label>
            <div style={{display:"flex",gap:4}}>
              <input type={showPwd?"text":"password"} style={{...S.input,flex:1}}
                value={f.password||""} onChange={e=>setF({...f,password:e.target.value})} placeholder={isNew?"Leave blank to auto-gen":""} />
              <button style={{...S.btnSm,padding:"4px 8px"}} onClick={()=>setShowPwd(!showPwd)}>{showPwd?"🙈":"👁"}</button>
              <button style={{...S.btnSm,background:"#1a2a0d",color:"#27ae60",padding:"4px 8px"}}
                onClick={()=>setF({...f,password:genPwd()})}>Gen</button>
            </div>
          </div>
          <div>
            <label style={S.label}>Role / Designation *</label>
            <select style={S.select} value={f.role} onChange={e=>setF({...f,role:e.target.value})}>
              {ROLE_LIST.map(r=><option key={r.id} value={r.id}>{r.label}</option>)}
            </select>
          </div>
          <div>
            <label style={S.label}>Department</label>
            <select style={S.select} value={f.department||""}
              onChange={e=>{
                if(e.target.value==="__add__"){
                  const name = _isWeb ? window.prompt("Naya department naam daalen:","") : "";
                  if(name&&name.trim()){
                    addGlobalDepartment && addGlobalDepartment(name.trim());
                    setF({...f, department: name.trim()});
                  }
                } else {
                  setF({...f, department: e.target.value});
                }
              }}>
              <option value="">-- Select Department --</option>
              {(globalDepartments||DEFAULT_DEPARTMENTS).map(d=>(
                <option key={d} value={d}>{d}</option>
              ))}
              <option value="__add__">➕ Naya Department Add Karein...</option>
            </select>
          </div>
          <LI label="Phone" value={f.phone||""} onChange={v=>setF({...f,phone:v})} />
          <LI label="Email" value={f.email||""} onChange={v=>setF({...f,email:v})} />
          <LI label="Joining Date" type="date" value={f.joiningDate||today()} onChange={v=>setF({...f,joiningDate:v})} />
          <LI label="Monthly Salary (₹)" type="number" value={f.salary||""} onChange={v=>setF({...f,salary:+v})} />
          <LI label="PAN No." value={f.panNo||""} onChange={v=>setF({...f,panNo:v.toUpperCase().replace(/[^A-Z0-9]/g,"")})} />
          <div>
            <label style={S.label}>Reports To</label>
            <select style={S.select} value={f.reportingTo||""} onChange={e=>setF({...f,reportingTo:e.target.value})}>
              <option value="">— None —</option>
              {seniors.map(u=><option key={u.id} value={u.id}>{u.name} ({u.role})</option>)}
            </select>
          </div>
          <LI label="Address" value={f.address||""} onChange={v=>setF({...f,address:v})} />
        </div>

        {/* Project Allotment */}
        <div style={{fontWeight:700,color:"#2980b9",fontSize:12,marginBottom:6}}>🏢 Project Allotment</div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:14}}>
          {projects.map(p=>(
            <label key={p.id} style={{display:"flex",alignItems:"center",gap:5,
              background:(f.projects||[]).includes(p.id)?"#0a1520":"#111",
              border:`1px solid ${(f.projects||[]).includes(p.id)?"#2980b9":"#333"}`,
              borderRadius:6,padding:"4px 10px",cursor:"pointer",fontSize:12,color:"#ccc"}}>
              <input type="checkbox" checked={(f.projects||[]).includes(p.id)} onChange={()=>toggleProject(p.id)} />
              {p.name}
            </label>
          ))}
          {projects.length===0&&<span style={{fontSize:11,color:"#555"}}>No projects yet</span>}
        </div>

        {/* Module Access Rights */}
        <div style={{fontWeight:700,color:"#8e44ad",fontSize:12,marginBottom:6}}>🔐 Module Access Rights</div>
        <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:10}}>
          <button style={{...S.btnSm,background:"#1a0a2a",color:"#8e44ad",border:"1px solid #8e44ad",fontSize:10}}
            onClick={()=>setF({...f,rights:MODULE_LIST.map(m=>m.id)})}>Select All</button>
          <button style={{...S.btnSm,background:"#1a0a2a",color:"#888",fontSize:10}}
            onClick={()=>setF({...f,rights:["attendance_self","myprofile_self",]})}>Clear All</button>
        </div>
        <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:14}}>
          {MODULE_LIST.map(m=>(
            <label key={m.id} style={{display:"flex",alignItems:"center",gap:4,
              background:(f.rights||[]).includes(m.id)?"#1a0a2a":"#0d0d0d",
              border:`1px solid ${(f.rights||[]).includes(m.id)?"#8e44ad":"#222"}`,
              borderRadius:5,padding:"3px 9px",cursor:"pointer",fontSize:11,color:"#ccc"}}>
              <input type="checkbox" checked={(f.rights||[]).includes(m.id)} onChange={()=>toggleRight(m.id)} />
              {m.label}
            </label>
          ))}
        </div>

        {/* Approval Rights */}
        <div style={{fontWeight:700,color:"#27ae60",fontSize:12,marginBottom:6}}>✅ Approval Rights</div>
        <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:14}}>
          {APPROVAL_MODULES.map(m=>(
            <label key={m.id} style={{display:"flex",alignItems:"center",gap:4,
              background:(f.approvalRights||[]).includes(m.id)?"#0a1a0a":"#0d0d0d",
              border:`1px solid ${(f.approvalRights||[]).includes(m.id)?"#27ae60":"#222"}`,
              borderRadius:5,padding:"3px 9px",cursor:"pointer",fontSize:11,color:"#ccc"}}>
              <input type="checkbox" checked={(f.approvalRights||[]).includes(m.id)} onChange={()=>toggleApproval(m.id)} />
              {m.label}
            </label>
          ))}
        </div>

        {/* ── Driver-specific: Machines ── */}
        {f.role === "driver" && (
          <div style={{background:"#0a1a0a",border:"1px solid #27ae60",
            borderRadius:8,padding:14,marginBottom:14}}>
            <div style={{fontWeight:700,color:"#27ae60",fontSize:12,marginBottom:10}}>
              🚜 Driver — Machine Details
            </div>
            <div style={{marginBottom:8}}>
              <label style={S.label}>License Number</label>
              <input style={S.input} value={f.licenseNo||""}
                onChange={e=>setF({...f,licenseNo:e.target.value})}
                placeholder="DL-XXXXXXXX..." />
            </div>
            <div style={{marginBottom:8}}>
              <label style={S.label}>License Expiry</label>
              <input type="date" style={S.input} value={f.licenseExpiry||""}
                onChange={e=>setF({...f,licenseExpiry:e.target.value})} />
            </div>
            <div>
              <label style={S.label}>
                Kaunsi Machines Chala Sakta Hai
                <span style={{fontSize:10,color:"#888",marginLeft:4}}>(multiple select)</span>
              </label>
              <div style={{display:"flex",gap:5,flexWrap:"wrap",marginTop:4}}>
                {[
                  "JCB / Excavator","Grader","Compactor / Roller",
                  "Dumper / Tipper","Transit Mixer","Loader",
                  "Tower Crane","Mobile Crane","Bulldozer",
                  "Generator","Water Tanker","Concrete Pump",
                  "Paver","Motor Grader","Tractor",
                ].map(machine=>{
                  const sel = (f.canOperate||[]).includes(machine);
                  return (
                    <label key={machine} style={{
                      display:"flex",alignItems:"center",gap:4,
                      background:sel?"#0a3a0a":"#0d0d0d",
                      border:`1px solid ${sel?"#27ae60":"#222"}`,
                      borderRadius:5,padding:"3px 8px",
                      cursor:"pointer",fontSize:11,color:"#ccc"
                    }}>
                      <input type="checkbox" checked={sel}
                        onChange={()=>{
                          const cur = f.canOperate||[];
                          setF({...f,
                            canOperate: sel
                              ? cur.filter(x=>x!==machine)
                              : [...cur, machine]
                          });
                        }} />
                      {machine}
                    </label>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {/* ── Statutory Compliance ── */}
        <div style={{background:"#0a1020",border:"1px solid #2980b9",borderRadius:8,padding:14,marginBottom:14}}>
          <div style={{fontWeight:700,color:"#2980b9",fontSize:12,marginBottom:10}}>🏛 Statutory Compliance (EPF / ESIC)</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:10,marginBottom:10}}>
            <LI label="EPF UAN No." value={f.epfUan||""} onChange={v=>setF({...f,epfUan:v})} />
            <LI label="EPF Member ID" value={f.epfMemberId||""} onChange={v=>setF({...f,epfMemberId:v})} />
            <LI label="ESIC IP No." value={f.esicIpNo||""} onChange={v=>setF({...f,esicIpNo:v})} />
            <LI label="ESIC Dispensary" value={f.esicDispensary||""} onChange={v=>setF({...f,esicDispensary:v})} />
            <LI label="PF Joining Date" type="date" value={f.pfJoiningDate||""} onChange={v=>setF({...f,pfJoiningDate:v})} />
            <LI label="ESIC Joining Date" type="date" value={f.esicJoiningDate||""} onChange={v=>setF({...f,esicJoiningDate:v})} />
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:8,
            background:"#060d1a",borderRadius:6,padding:10,marginBottom:8}}>
            <div style={{fontSize:11,color:"#888",gridColumn:"1/-1",marginBottom:4,fontWeight:600}}>Monthly Contribution (auto-calc basis)</div>
            <LI label="Basic Salary (₹)" type="number" value={f.basicSalary||""} onChange={v=>setF({...f,basicSalary:+v})} />
            <div style={{padding:"6px 0"}}>
              <div style={{fontSize:11,color:"#888"}}>EPF Employee (12%)</div>
              <div style={{fontSize:13,fontWeight:700,color:"#2980b9"}}>₹{Math.round((f.basicSalary||0)*0.12).toLocaleString("en-IN")}</div>
            </div>
            <div style={{padding:"6px 0"}}>
              <div style={{fontSize:11,color:"#888"}}>EPF Employer (13.15%)</div>
              <div style={{fontSize:13,fontWeight:700,color:"#27ae60"}}>₹{Math.round((f.basicSalary||0)*0.1315).toLocaleString("en-IN")}</div>
            </div>
            <div style={{padding:"6px 0"}}>
              <div style={{fontSize:11,color:"#888"}}>ESIC Employee (0.75%) — if gross ≤₹21,000</div>
              <div style={{fontSize:13,fontWeight:700,color:"#8e44ad"}}>₹{(f.salary||0)<=21000?Math.round((f.salary||0)*0.0075).toLocaleString("en-IN"):"Exempt"}</div>
            </div>
            <div style={{padding:"6px 0"}}>
              <div style={{fontSize:11,color:"#888"}}>ESIC Employer (3.25%)</div>
              <div style={{fontSize:13,fontWeight:700,color:"#e67e22"}}>₹{(f.salary||0)<=21000?Math.round((f.salary||0)*0.0325).toLocaleString("en-IN"):"Exempt"}</div>
            </div>
          </div>
        </div>

        {/* ── Bank Account Details ── */}
        <div style={{background:"#0a1508",border:"1px solid #27ae60",borderRadius:8,padding:14,marginBottom:14}}>
          <div style={{fontWeight:700,color:"#27ae60",fontSize:12,marginBottom:10}}>🏦 Bank Account Details</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:10}}>
            <LI label="Account Holder Name" value={f.bankName||""} onChange={v=>setF({...f,bankName:v})} />
            <LI label="Bank Name" value={f.bankBranch||""} onChange={v=>setF({...f,bankBranch:v})} />
            <LI label="Account Number" value={f.bankAccount||""} onChange={v=>setF({...f,bankAccount:v})} />
            <LI label="IFSC Code" value={f.bankIfsc||""} onChange={v=>setF({...f,bankIfsc:v.toUpperCase()})} />
            <LI label="Branch Name" value={f.bankBranchName||""} onChange={v=>setF({...f,bankBranchName:v})} />
            <div>
              <label style={S.label}>Salary Mode</label>
              <select style={S.select} value={f.salaryMode||"Cash"} onChange={e=>setF({...f,salaryMode:e.target.value})}>
                {["Cash","Bank Transfer","Cheque","UPI"].map(m=><option key={m}>{m}</option>)}
              </select>
            </div>
          </div>
        </div>

           {/* ── Photo Upload ── */}
      <div style={{marginTop:12,marginBottom:10}}>
        <div style={{fontSize:12,fontWeight:700,color:"#2980b9",marginBottom:8}}>📷 Labour Photo</div>
        <div style={{display:"flex",alignItems:"center",gap:16}}>
          {f.photo ? (
            <div style={{position:"relative"}}>
              <img src={f.photo} alt="Labour" style={{width:70,height:90,objectFit:"cover",borderRadius:4,border:"2px solid #2980b9",filter:"grayscale(100%)"}} />
              <button style={{position:"absolute",top:-6,right:-6,background:"#c0392b",color:"#fff",border:"none",borderRadius:"50%",width:18,height:18,fontSize:10,cursor:"pointer"}} onClick={()=>setF({...f,photo:""})}>x</button>
            </div>
          ):(
            <div style={{width:70,height:90,background:"#1a1a1a",border:"2px dashed #444",borderRadius:4,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,color:"#666",textAlign:"center"}}>No Photo</div>
          )}
          <label style={{...S.btnSm,background:"#1a2a3a",color:"#2980b9",border:"1px solid #2980b9",cursor:"pointer",padding:"6px 14px"}}>
            {f.photo?"Change Photo":"Upload Photo"}
            <input type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
              const file=e.target.files[0]; if(!file) return;
              const reader=new FileReader();
              reader.onload=ev=>setF({...f,photo:ev.target.result});
              reader.readAsDataURL(file); e.target.value="";
            }} />
          </label>
        </div>
      </div>
         {/* ── Document Upload ── */}
        <div style={{background:"#0f0a00",border:"1px solid #e67e2244",borderRadius:8,padding:14,marginBottom:14}}>
          <div style={{fontWeight:700,color:"var(--accent)",fontSize:12,marginBottom:10}}>📎 Document Upload</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))",gap:10}}>
            <DocUpload label="🪪 Aadhaar Card (PDF/Image)" value={(f.docs||[]).filter(d=>d.docType==="aadhaar")}
              onChange={v=>setF({...f,docs:[...(f.docs||[]).filter(d=>d.docType!=="aadhaar"),...v.map(x=>({...x,docType:"aadhaar"}))]})}
              maxFiles={2} />
            <DocUpload label="🗂 PAN Card (PDF/Image)" value={(f.docs||[]).filter(d=>d.docType==="pan")}
              onChange={v=>setF({...f,docs:[...(f.docs||[]).filter(d=>d.docType!=="pan"),...v.map(x=>({...x,docType:"pan"}))]})}
              maxFiles={2} />
            <DocUpload label="📜 Other Documents" value={(f.docs||[]).filter(d=>d.docType==="other")}
              onChange={v=>setF({...f,docs:[...(f.docs||[]).filter(d=>d.docType!=="other"),...v.map(x=>({...x,docType:"other"}))]})}
              maxFiles={3} />
          </div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:6}}>
          <button style={{...S.btnPrimary,background:"#27ae60"}} onClick={()=>f.name&&f.username&&onSave(f)}>
            {isNew?"✅ Register Employee":"💾 Save Changes"}
          </button>
          <button style={S.btnSecondary} onClick={onCancel}>Cancel</button>
        </div>
      </div>
    );
  };

  // ──────────────────────────────────────────────────────────────────
  // TODAY ATTENDANCE FORM
  // ──────────────────────────────────────────────────────────────────
  const AttendanceForm = ({onSave, onCancel}) => {
    const [f, setF] = useState({
      userId: me.id||"", userName: me.name||"",
      date: today(), inTime: "", outTime:"", remarks:"",
      projectId: (me.projects||[])[0]||""
    });
    return (
      <div style={S.formBox}>
        <div style={S.formTitle}>🕐 Mark Attendance</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:10,marginBottom:12}}>
          {isHR&&(
            <div>
              <label style={S.label}>Employee</label>
              <select style={S.select} value={f.userId} onChange={e=>{
                const u=users.find(x=>x.id===e.target.value);
                setF({...f,userId:e.target.value,userName:u?.name||""});}}>
                {users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
              </select>
            </div>
          )}
          <LI label="Date" type="date" value={f.date} onChange={v=>setF({...f,date:v})} />
          <LI label="In Time" type="time" value={f.inTime} onChange={v=>setF({...f,inTime:v})} />
          <LI label="Out Time" type="time" value={f.outTime} onChange={v=>setF({...f,outTime:v})} />
          <div>
            <label style={S.label}>Project</label>
            <select style={S.select} value={f.projectId} onChange={e=>setF({...f,projectId:e.target.value})}>
              <option value="">— Select —</option>
              {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
          <LI label="Remarks" value={f.remarks} onChange={v=>setF({...f,remarks:v})} />
        </div>
        <div style={{display:"flex",gap:8}}>
          <button style={{...S.btnPrimary,background:"#27ae60"}} onClick={()=>onSave(f)}>✅ Submit Attendance</button>
          <button style={S.btnSecondary} onClick={onCancel}>Cancel</button>
        </div>
      </div>
    );
  };

  // ──────────────────────────────────────────────────────────────────
  // MAIN RENDER
  // ──────────────────────────────────────────────────────────────────
  const filteredUsers = users.filter(u=>
    u.name?.toLowerCase().includes(searchQ.toLowerCase()) ||
    u.username?.toLowerCase().includes(searchQ.toLowerCase()) ||
    u.role?.toLowerCase().includes(searchQ.toLowerCase())
  );

  const todayAtt = attendance.filter(a=>a.date===today()&&a.userId===me.id);
  const myPendingLeaves = leaveReqs.filter(l=>l.submittedBy===me.id&&l.status==="pending").length;
  const teamPendingAtt  = attendance.filter(a=>a.status==="pending"&&(isHR||users.find(u=>u.id===a.userId&&u.reportingTo===me.id))).length;

  return (
    <div>
      <STitle>🏢 HR Module</STitle>
      <ImportExportBar label="Employees" cols={[{key:"name",label:"Name"},{key:"username",label:"Username"},{key:"role",label:"Role"},{key:"department",label:"Department"},{key:"phone",label:"Phone"},{key:"email",label:"Email"},{key:"joiningDate",label:"Joining Date"},{key:"basicSalary",label:"Basic Salary"},{key:"reportingTo",label:"Reports To"}]} data={users} onExport={()=>exportCSV(users,"Employees.csv",[{key:"name",label:"Name"},{key:"username",label:"Username"},{key:"role",label:"Role"},{key:"department",label:"Department"},{key:"phone",label:"Phone"},{key:"email",label:"Email"},{key:"joiningDate",label:"Joining Date"},{key:"basicSalary",label:"Basic Salary"},{key:"reportingTo",label:"Reports To"}])} onImport={(rows)=>upd({users:[...users,...rows.map(r=>({...r,id:uid(),rights:r.rights?JSON.parse(r.rights):[],password:r.password||genPwd(),basicSalary:+r.basicSalary||0}))]})} />

      {/* ── KPI Strip ── */}
      <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
        {[
          {icon:"👤",label:"Total Staff",val:users.length,color:"#2980b9"},
          {icon:"🕐",label:"Pending Attendance",val:teamPendingAtt,color:"#e67e22"},
          {icon:"🏖",label:"My Pending Leaves",val:myPendingLeaves,color:"#8e44ad"},
          {icon:"⚠️",label:"Active Penalties",val:penalties.filter(p=>p.status==="active").length,color:"#e74c3c"},
          {icon:"📢",label:"Open Grievances",val:grievances.filter(g=>g.status==="open").length,color:"#e67e22"},
        ].map(c=>(
          <div key={c.label} style={{flex:"1 1 100px",background:"#111",border:"1px solid #2a2a2a",
            borderRadius:10,padding:"10px 14px",minWidth:95}}>
            <div style={{fontSize:11,color:"#666"}}>{c.icon} {c.label}</div>
            <div style={{fontSize:"clamp(12px,3vw,20px)",fontWeight:800,color:c.color,marginTop:4}}>{c.val}</div>
          </div>
        ))}
      </div>

      {/* ── Tabs ── */}
      <div style={{display:"flex",gap:4,marginBottom:12,flexWrap:"wrap"}}>
        {TAB_LIST.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{...S.tabBtn, background:tab===t.id?"#e67e22":"#1a1a1a",
              color:tab===t.id?"#fff":"#aaa", border:`1px solid ${tab===t.id?"#e67e22":"#333"}`}}>
            {t.icon} {t.label}
          </button>
        ))}
      </div>

      {/* ══════════════════════════════════════════════════════════════
          TAB: EMPLOYEES
      ══════════════════════════════════════════════════════════════ */}
      {tab==="employees"&&(<>
        <div style={{display:"flex",gap:8,marginBottom:10,alignItems:"center",flexWrap:"wrap"}}>
          <input style={{...S.input,flex:1,maxWidth:280}} placeholder="🔍 Search by name / username / role..."
            value={searchQ} onChange={e=>setSearchQ(e.target.value)} />
          {isHR&&(
            <button style={S.btnPrimary} onClick={()=>setEmpForm({})}>＋ Register Employee</button>
          )}
        </div>
        {empForm!==null&&(
          <EmployeeForm
            initial={empForm.id?empForm:{}}
            onSave={saveEmployee}
            onCancel={()=>setEmpForm(null)}
          />
        )}
        <div style={S.card}>
          <div style={{overflowX:"auto"}}>
            <table style={S.table}>
              <thead><tr>
                {["Name","Username","Role / Designation","Reports To","Projects","Rights","Docs","Actions"].map(h=>(
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {filteredUsers.map(u=>{
                  const senior = users.find(x=>x.id===u.reportingTo);
                  const projNames = (u.projects||[]).map(pid=>projects.find(p=>p.id===pid)?.name||"").filter(Boolean);
                  return (
                    <tr key={u.id} style={S.tr}>
                      <td style={{...S.td,fontWeight:700}}>
                        <div>{u.name}</div>
                        <div style={{fontSize:10,color:"#888"}}>{u.phone||""}</div>
                      </td>
                      <td style={{...S.td,fontFamily:"monospace",fontSize:12,color:"#e67e22"}}>{u.username}</td>
                      <td style={S.td}>
                        <Tag color={USER_ROLES[u.role]?.color||"#888"} small>
                          {USER_ROLES[u.role]?.label||u.role||"Staff"}
                        </Tag>
                      </td>
                      <td style={{...S.td,fontSize:11,color:"#aaa"}}>{senior?.name||"—"}</td>
                      <td style={{...S.td,fontSize:10}}>
                        {projNames.length>0?projNames.map((n,i)=>(
                          <Tag key={i} color="#2980b9" small>{n}</Tag>
                        )):<span style={{color:"#555"}}>None</span>}
                      </td>
                      <td style={{...S.td,fontSize:10}}>
                        <span style={{color:"#8e44ad"}}>{(u.rights||[]).length} modules</span>
                        {(u.approvalRights||[]).length>0&&(
                          <span style={{color:"#27ae60",marginLeft:5}}>/ {(u.approvalRights||[]).length} approvals</span>
                        )}
                      </td>
                      <td style={{...S.td,fontSize:10}}>
                        {(u.docs||[]).length>0?(
                          <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>
                            {(u.docs||[]).map((d,i)=>(
                              <button key={i} type="button" title={d.name}
                                style={{background:d.docType==="aadhaar"?"#8e44ad22":d.docType==="pan"?"#f39c1222":"#2980b922",
                                  color:d.docType==="aadhaar"?"#8e44ad":d.docType==="pan"?"#f39c12":"#2980b9",
                                  border:"none",borderRadius:4,padding:"2px 6px",cursor:"pointer",fontSize:10,fontWeight:700}}
                                onClick={()=>{ if(!_isWeb){alert('Web browser mein kholen।');return;} const win=_isWeb?window.open():null; if(win){d.type==="application/pdf"?win.document.write(`<iframe src="${d.data}" style="width:100%;height:100%;border:none"></iframe>`):win.document.write(`<img src="${d.data}" style="max-width:100%;max-height:100vh;display:block;margin:auto">`);}}}>
                                {d.docType==="aadhaar"?"🪪":d.docType==="pan"?"🗂":"📄"} {d.docType}
                              </button>
                            ))}
                          </div>
                        ):<span style={{color:"#555"}}>—</span>}
                      </td>
                      <td style={S.td}>
                        <div style={{display:"flex",gap:4}}>
                          {isHR&&(
                            <button style={{...S.btnSm,background:"#1a2a0a",color:"#27ae60"}}
                              onClick={()=>setEmpForm(u)}>✏️</button>
                          )}
                          {isHR&&!u.isMaster&&(
                            <button style={{...S.btnSm,background:"#2a0d0d",color:"#e74c3c"}}
                              onClick={()=>deleteEmployee(u.id)}>🗑</button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            {filteredUsers.length===0&&<Empty text="Koi employee nahi. ＋ Register Employee se add karein।" />}
          </div>
        </div>
      </>)}

      {/* ══════════════════════════════════════════════════════════════
          TAB: ATTENDANCE
      ══════════════════════════════════════════════════════════════ */}
      {tab==="attendance"&&(<>
        {/* ── Employee Self-Service Attendance ── */}
        {!isHR && (
          <div style={{...S.card, marginBottom:14, border:"2px solid var(--accent)44"}}>
            <div style={{fontWeight:700, color:"var(--accent)", marginBottom:12, fontSize:14}}>
              🕐 Aaj ki Attendance — {today()}
            </div>
            {attForm ? (
              <SelfAttendanceForm
                me={me} projects={projects} existing={todayAtt[0]||null}
                onSave={(d)=>{
                  const entry = {
                    ...d, id: todayAtt[0]?.id||uid(),
                    userId: me.id, userName: me.name,
                    date: today(), createdAt: new Date().toISOString(),
                    submittedBy: me.id, status: "pending"
                  };
                  const others = (attendance||[]).filter(a=>!(a.userId===me.id&&a.date===today()));
                  updHR({hrAttendance:[...others, entry]});
                  setAttForm(null);
                }}
                onCancel={()=>setAttForm(null)}
              />
            ) : (
              <div style={{display:"flex", alignItems:"center", gap:14, flexWrap:"wrap"}}>
                <div style={{flex:1}}>
                  {todayAtt.length>0 ? (
                    <div style={{display:"flex", gap:8, alignItems:"center", flexWrap:"wrap"}}>
                      <Tag color={todayAtt[0].status==="approved"?"#27ae60":todayAtt[0].status==="rejected"?"#e74c3c":"#f39c12"}>
                        {todayAtt[0].status==="approved"?"✅ Approved":todayAtt[0].status==="rejected"?"❌ Rejected":"⏳ Pending"}
                      </Tag>
                      <span style={{fontSize:12,color:"var(--text-muted)"}}>
                        <b>{todayAtt[0].attendanceStatus||"P"}</b>
                        {todayAtt[0].inTime ? ` | In: ${todayAtt[0].inTime}` : ""}
                        {todayAtt[0].outTime ? ` | Out: ${todayAtt[0].outTime}` : ""}
                        {todayAtt[0].projectId ? ` | ${(projects||[]).find(p=>p.id===todayAtt[0].projectId)?.name||""}` : ""}
                      </span>
                    </div>
                  ) : (
                    <span style={{fontSize:12,color:"#f39c12",fontWeight:600}}>
                      ⚠️ Aaj ki attendance abhi nahi dali
                    </span>
                  )}
                </div>
                <button style={{...S.btnPrimary, padding:"9px 20px", fontSize:13}}
                  onClick={()=>setAttForm(true)}>
                  {todayAtt.length>0 ? "✏️ Update" : "✅ Mark Attendance"}
                </button>
              </div>
            )}
          </div>
        )}

        {/* ── HR: Add attendance for any employee ── */}
        {isHR && (
          <div style={{display:"flex",gap:8,marginBottom:10,flexWrap:"wrap",alignItems:"center"}}>
            <button style={S.btnPrimary} onClick={()=>setAttForm(true)}>
              + Add Attendance Entry
            </button>
            <span style={{fontSize:11,color:"var(--text-dim)"}}>
              {(attendance||[]).filter(a=>a.date===today()).length} entries aaj
            </span>
          </div>
        )}
        {isHR && attForm && (
          <div style={{...S.card, marginBottom:12}}>
            <StaffAttendanceForm
              users={users} projects={projects} me={me}
              editData={typeof attForm === 'object' ? attForm : null}
              onSave={(d)=>{
                if(d._editId) {
                  // Edit existing
                  updHR({hrAttendance:(attendance||[]).map(a=>a.id===d._editId
                    ? {...a, attendanceStatus:d.attendanceStatus, inTime:d.inTime,
                       outTime:d.outTime, projectId:d.projectId, date:d.date,
                       note:d.note, status:"approved", approvedBy:me.name}
                    : a)});
                } else {
                  // New entry
                  const entry = {...d, id:uid(), createdAt:new Date().toISOString(),
                    submittedBy:me.id, status:"approved", approvedBy:me.name};
                  updHR({hrAttendance:[...(attendance||[]), entry]});
                }
                setAttForm(null);
              }}
              onCancel={()=>setAttForm(null)}
            />
          </div>
        )}

        {/* ── Attendance Table ── */}
        <div style={S.card}>
          <div style={{fontWeight:700,color:"var(--text-muted)",marginBottom:8}}>
            {isHR?"📋 Sab Employees ki Attendance":"📋 Meri Attendance History"}
          </div>
          <div style={{overflowX:"auto"}}>
            <table style={S.table}>
              <thead><tr>
                {["Employee","Date","In","Out","Project","P/H/A","Status","Action"].map(h=>(
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {[...(isHR?attendance:(attendance||[]).filter(a=>a.userId===me.id))]
                  .sort((a,b)=>(b.date||"").localeCompare(a.date||""))
                  .map(a=>{
                  const emp = (users||[]).find(u=>u.id===a.userId);
                  const proj= (projects||[]).find(p=>p.id===a.projectId);
                  return (
                    <tr key={a.id} style={S.tr}>
                      <td style={{...S.td,fontWeight:600}}>{a.userName||emp?.name||"—"}</td>
                      <td style={S.td}>{a.date}</td>
                      <td style={{...S.td,color:"#27ae60",fontWeight:700}}>{a.inTime||"—"}</td>
                      <td style={{...S.td,color:"#e67e22"}}>{a.outTime||"—"}</td>
                      <td style={{...S.td,fontSize:11}}>{proj?.name||"—"}</td>
                      <td style={S.td}>
                        <Tag color={a.attendanceStatus==="A"?"#e74c3c":a.attendanceStatus==="H"?"#f39c12":"#27ae60"} small>
                          {a.attendanceStatus||"P"}
                        </Tag>
                      </td>
                      <td style={S.td}>
                        <Tag color={a.status==="approved"?"#27ae60":a.status==="rejected"?"#e74c3c":"#888"} small>
                          {a.status}
                        </Tag>
                      </td>
                      <td style={S.td}>
                        <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>
                          {/* HR: Approve/Reject pending entries */}
                          {a.status==="pending"&&isHR&&(
                            <>
                              <button style={{...S.btnSm,background:"#0d2a0d",color:"#27ae60"}}
                                onClick={()=>approveAtt(a.id)}>✅</button>
                              <button style={{...S.btnSm,background:"#2a0d0d",color:"#e74c3c"}}
                                onClick={()=>rejectAtt(a.id)}>✗</button>
                            </>
                          )}
                          {/* HR: Edit any entry */}
                          {isHR&&(
                            <button style={{...S.btnSm,background:"#2980b9",fontSize:10}}
                              onClick={()=>{
                                setAttForm({
                                  _editId: a.id,
                                  userId: a.userId,
                                  userName: a.userName,
                                  date: a.date,
                                  attendanceStatus: a.attendanceStatus||"P",
                                  inTime: a.inTime||"09:00",
                                  outTime: a.outTime||"",
                                  projectId: a.projectId||"",
                                  note: a.note||"",
                                });
                              }}>✏️</button>
                          )}
                          {/* HR: Delete any entry */}
                          {isHR&&(
                            <button style={{...S.btnSm,background:"#555",fontSize:10}}
                              onClick={()=>{
                                if(_isWeb&&!window.confirm("Delete karein?")) return;
                                updHR({hrAttendance:(attendance||[]).filter(x=>x.id!==a.id)});
                              }}>🗑</button>
                          )}
                          {/* Employee: Delete own pending entry */}
                          {!isHR&&a.userId===me.id&&a.status==="pending"&&(
                            <button style={{...S.btnSm,background:"#333",fontSize:10}}
                              onClick={()=>updHR({hrAttendance:(attendance||[]).filter(x=>x.id!==a.id)})}>🗑</button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            {(attendance||[]).length===0&&<Empty text="Koi attendance record nahi।" />}
          </div>
        </div>
      </>)}


      {/* ══════════════════════════════════════════════════════════════
          TAB: LEAVE REQUESTS  (2-Level Approval)
      ══════════════════════════════════════════════════════════════ */}
      {tab==="leaves"&&(<>

        {/* ── Apply Leave button ── */}
        <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap",alignItems:"center"}}>
          <button style={S.btnPrimary} onClick={()=>setLeaveForm(true)}>
            ＋ Apply Leave
          </button>
          {isHR && (
            <span style={{fontSize:11,color:"var(--text-dim)"}}>
              Pending: {(leaveReqs||[]).filter(l=>
                l.status==="pending" || l.status==="senior_approved"
              ).length} requests
            </span>
          )}
        </div>

        {/* ── Leave Application Form ── */}
        {leaveForm&&<LeaveApplyForm
          me={me} users={users}
          onSave={(d)=>{
            const days = d.fromDate&&d.toDate
              ? Math.max(1,Math.round((new Date(d.toDate)-new Date(d.fromDate))/(86400000))+1)
              : 1;
            // Find reporting official
            const myRecord = (users||[]).find(u=>u.id===me.id);
            const reportingTo = myRecord?.reportingTo||null;
            const reportingPerson = (users||[]).find(u=>u.id===reportingTo);
            updHR({hrLeave:[...(leaveReqs||[]),{
              ...d, id:uid(), days,
              submittedBy:me.id, submittedByName:me.name,
              createdAt:new Date().toISOString(),
              status:"pending",           // pending -> senior_approved -> hr_approved
              reportingTo:reportingTo,
              reportingName:reportingPerson?.name||null,
              seniorAction:null, seniorActionBy:null, seniorActionAt:null,
              hrAction:null, hrActionBy:null, hrActionAt:null,
              hrNote:"",
            }]});
            setLeaveForm(null);
          }}
          onCancel={()=>setLeaveForm(null)}
        />}

        {/* ── Leave Requests Table ── */}
        <div style={S.card}>
          {/* Filter tabs for HR */}
          {isHR&&(
            <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap"}}>
              {[
                {id:"all",     label:`All (${(leaveReqs||[]).length})`},
                {id:"pending", label:`⏳ Pending (${(leaveReqs||[]).filter(l=>l.status==="pending").length})`},
                {id:"senior_approved",label:`👔 Sr.Approved (${(leaveReqs||[]).filter(l=>l.status==="senior_approved").length})`},
                {id:"approved",label:`✅ Approved (${(leaveReqs||[]).filter(l=>l.status==="hr_approved"||l.status==="approved").length})`},
                {id:"rejected",label:`❌ Rejected (${(leaveReqs||[]).filter(l=>l.status==="rejected"||l.status==="senior_rejected").length})`},
              ].map(f=>(
                <button key={f.id}
                  style={{...S.tabBtn, fontSize:11,
                    background:"var(--bg-input)", color:"var(--text-muted)",
                    border:"1px solid var(--border)"}}
                  onClick={e=>{
                    // visual highlight only - filter done inline
                    document.querySelectorAll('.leaveFilterBtn').forEach(b=>b.style.background="var(--bg-input)");
                    e.target.style.background="var(--accent)";
                  }}
                  className="leaveFilterBtn">
                  {f.label}
                </button>
              ))}
            </div>
          )}
          <div style={{overflowX:"auto"}}>
            <table style={S.table}>
              <thead><tr>
                {["Employee","Type","From","To","Days","Reason","Urgent",
                  "Senior Approval","HR Approval","Action"].map(h=>(
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {[...(isHR?leaveReqs:(leaveReqs||[]).filter(l=>l.submittedBy===me.id))]
                  .sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||""))
                  .map(l=>{
                  // Is current user the reporting official for this leave?
                  const isSeniorForThis = !isHR && l.reportingTo===me.id;
                  // Final status display
                  const finalStatus = l.status==="hr_approved"||l.status==="approved"?"approved"
                    : l.status==="rejected"||l.status==="senior_rejected"?"rejected"
                    : l.status==="senior_approved"?"senior_approved"
                    : "pending";
                  return (
                    <tr key={l.id} style={{...S.tr,
                      background: l.urgent ? "rgba(231,76,60,0.06)" : ""}}>
                      <td style={{...S.td,fontWeight:600}}>
                        {l.submittedByName||"—"}
                        {l.urgent&&<Tag color="#e74c3c" small style={{marginLeft:4}}>🚨</Tag>}
                      </td>
                      <td style={S.td}>
                        <Tag color="#2980b9" small>{(l.leaveType||"").toUpperCase()}</Tag>
                      </td>
                      <td style={S.td}>{l.fromDate}</td>
                      <td style={S.td}>{l.toDate}</td>
                      <td style={{...S.td,fontWeight:700,color:"#e67e22"}}>{l.days||1}</td>
                      <td style={{...S.td,fontSize:11,maxWidth:140,wordBreak:"break-word"}}>{l.reason}</td>
                      <td style={S.td}>{l.urgent&&<Tag color="#e74c3c" small>🚨 URGENT</Tag>}</td>

                      {/* Senior Approval column */}
                      <td style={S.td}>
                        {l.status==="pending" ? (
                          <Tag color="#f39c12" small>⏳ Awaiting</Tag>
                        ) : l.status==="senior_approved" ? (
                          <div>
                            <Tag color="#27ae60" small>✅ Approved</Tag>
                            {l.seniorActionBy&&<div style={{fontSize:10,color:"var(--text-dim)"}}>{l.seniorActionBy}</div>}
                          </div>
                        ) : l.status==="senior_rejected" ? (
                          <div>
                            <Tag color="#e74c3c" small>❌ Rejected</Tag>
                            {l.seniorActionBy&&<div style={{fontSize:10,color:"var(--text-dim)"}}>{l.seniorActionBy}</div>}
                          </div>
                        ) : (l.status==="hr_approved"||l.status==="approved") ? (
                          <Tag color="#27ae60" small>✅ Done</Tag>
                        ) : l.status==="rejected" ? (
                          <Tag color="#e74c3c" small>—</Tag>
                        ) : (
                          <Tag color="#888" small>—</Tag>
                        )}
                      </td>

                      {/* HR Approval column */}
                      <td style={S.td}>
                        {(l.status==="hr_approved"||l.status==="approved") ? (
                          <div>
                            <Tag color="#27ae60" small>✅ Approved</Tag>
                            {l.hrActionBy&&<div style={{fontSize:10,color:"var(--text-dim)"}}>{l.hrActionBy}</div>}
                            {l.hrNote&&<div style={{fontSize:10,color:"#888"}}>{l.hrNote}</div>}
                          </div>
                        ) : l.status==="rejected" ? (
                          <div>
                            <Tag color="#e74c3c" small>❌ Rejected</Tag>
                            {l.hrActionBy&&<div style={{fontSize:10,color:"var(--text-dim)"}}>{l.hrActionBy}</div>}
                            {l.hrNote&&<div style={{fontSize:10,color:"#e74c3c"}}>{l.hrNote}</div>}
                          </div>
                        ) : (
                          <Tag color="#888" small>⏳ Pending</Tag>
                        )}
                      </td>

                      {/* Action column */}
                      <td style={S.td}>
                        <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>

                          {/* Senior/Reporting official action — Level 1 */}
                          {isSeniorForThis && l.status==="pending" && (
                            <>
                              <button style={{...S.btnSm,background:"#1a3a1a",color:"#27ae60",fontSize:10}}
                                onClick={()=>updHR({hrLeave:(leaveReqs||[]).map(x=>x.id===l.id?{
                                  ...x,status:"senior_approved",
                                  seniorActionBy:me.name, seniorActionAt:today()
                                }:x)})}>✅ Approve</button>
                              <button style={{...S.btnSm,background:"#3a1a1a",color:"#e74c3c",fontSize:10}}
                                onClick={()=>updHR({hrLeave:(leaveReqs||[]).map(x=>x.id===l.id?{
                                  ...x,status:"senior_rejected",
                                  seniorActionBy:me.name, seniorActionAt:today()
                                }:x)})}>✗ Reject</button>
                            </>
                          )}

                          {/* HR action — Level 2 (can override senior decision) */}
                          {isHR && (l.status==="pending"||l.status==="senior_approved"||l.status==="senior_rejected") && (
                            <>
                              <button style={{...S.btnSm,background:"#27ae60",fontSize:10}}
                                onClick={()=>{
                                  const note = _isWeb ? window.prompt("Note (optional):","") : "";
                                  updHR({hrLeave:(leaveReqs||[]).map(x=>x.id===l.id?{
                                    ...x, status:"hr_approved",
                                    hrActionBy:me.name, hrActionAt:today(),
                                    hrNote: note||""
                                  }:x)});
                                }}>✅ HR Approve</button>
                              <button style={{...S.btnSm,background:"#e74c3c",fontSize:10}}
                                onClick={()=>{
                                  const note = _isWeb ? window.prompt("Rejection reason:","") : "";
                                  updHR({hrLeave:(leaveReqs||[]).map(x=>x.id===l.id?{
                                    ...x, status:"rejected",
                                    hrActionBy:me.name, hrActionAt:today(),
                                    hrNote: note||"Rejected by HR"
                                  }:x)});
                                }}>✗ HR Reject</button>
                            </>
                          )}

                          {/* HR: Revoke approved leave */}
                          {isHR && (l.status==="hr_approved"||l.status==="approved") && (
                            <button style={{...S.btnSm,background:"#555",fontSize:10}}
                              onClick={()=>updHR({hrLeave:(leaveReqs||[]).map(x=>x.id===l.id?{
                                ...x,status:"rejected",hrNote:"Revoked by HR",
                                hrActionBy:me.name,hrActionAt:today()
                              }:x)})}>↩ Revoke</button>
                          )}

                          {/* Employee: withdraw pending leave */}
                          {l.submittedBy===me.id && (l.status==="pending") && (
                            <button style={{...S.btnSm,background:"#333",fontSize:10}}
                              onClick={()=>updHR({hrLeave:(leaveReqs||[]).filter(x=>x.id!==l.id)})}>
                              🗑 Withdraw
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            {(leaveReqs||[]).length===0&&<Empty text="Koi leave request nahi।" />}
          </div>
        </div>
      </>)}


      {/* ══════════════════════════════════════════════════════════════
          TAB: GRIEVANCES
      ══════════════════════════════════════════════════════════════ */}
      {tab==="grievances"&&(<>
        <div style={{display:"flex",gap:8,marginBottom:10,flexWrap:"wrap"}}>
          <button style={S.btnPrimary} onClick={()=>setGrvForm(true)}>＋ File Grievance / Complaint</button>
        </div>
        {grvForm&&(()=>{
          const GF = () => {
            const [gf,setGf] = useState({againstType:"contractor",againstId:"",againstName:"",title:"",description:"",severity:"medium"});
            const targets = gf.againstType==="contractor"?state.contractors||[]
              :gf.againstType==="staff"?users:[];
            return (
              <div style={S.formBox}>
                <div style={S.formTitle}>📢 File Grievance / Complaint</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(170px,1fr))",gap:10,marginBottom:12}}>
                  <div>
                    <label style={S.label}>Against Type</label>
                    <select style={S.select} value={gf.againstType} onChange={e=>setGf({...gf,againstType:e.target.value,againstId:"",againstName:""})}>
                      <option value="contractor">Sub-contractor</option>
                      <option value="labour">Labour</option>
                      <option value="staff">Staff</option>
                      <option value="other">Other</option>
                    </select>
                  </div>
                  {targets.length>0&&(
                    <div>
                      <label style={S.label}>Against</label>
                      <select style={S.select} value={gf.againstId}
                        onChange={e=>{const t=targets.find(x=>x.id===e.target.value);setGf({...gf,againstId:e.target.value,againstName:t?.name||""})}}>
                        <option value="">— Select —</option>
                        {targets.map(t=><option key={t.id} value={t.id}>{t.name}</option>)}
                      </select>
                    </div>
                  )}
                  {(gf.againstType==="labour"||gf.againstType==="other")&&(
                    <LI label="Name" value={gf.againstName} onChange={v=>setGf({...gf,againstName:v})} />
                  )}
                  <div>
                    <label style={S.label}>Severity</label>
                    <select style={S.select} value={gf.severity} onChange={e=>setGf({...gf,severity:e.target.value})}>
                      {["low","medium","high","critical"].map(s=><option key={s} value={s}>{s.toUpperCase()}</option>)}
                    </select>
                  </div>
                </div>
                <LI label="Title *" value={gf.title} onChange={v=>setGf({...gf,title:v})} />
                <div style={{marginBottom:10}}>
                  <label style={S.label}>Description *</label>
                  <textarea style={{...S.input,height:70,resize:"vertical"}} value={gf.description}
                    onChange={e=>setGf({...gf,description:e.target.value})}  />
                </div>
                <div style={{display:"flex",gap:8}}>
                  <button style={{...S.btnPrimary,background:"#e67e22"}}
                    onClick={()=>gf.title&&gf.description&&saveGrievance(gf)}>📢 Submit Grievance</button>
                  <button style={S.btnSecondary} onClick={()=>setGrvForm(null)}>Cancel</button>
                </div>
              </div>
            );
          };
          return <GF />;
        })()}
        <div style={S.card}>
          <div style={{overflowX:"auto"}}>
            <table style={S.table}>
              <thead><tr>
                {["Filed By","Against","Title","Severity","Status","Resolution","Actions"].map(h=>(
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {grievances.map(g=>(
                  <tr key={g.id} style={S.tr}>
                    <td style={{...S.td,fontWeight:600}}>{g.submittedByName||"—"}</td>
                    <td style={{...S.td,fontSize:11}}>{g.againstName||g.againstType||"—"}</td>
                    <td style={{...S.td,fontWeight:600}}>{g.title}</td>
                    <td style={S.td}>
                      <Tag color={g.severity==="critical"?"#e74c3c":g.severity==="high"?"#e67e22":"#2980b9"} small>
                        {g.severity?.toUpperCase()}
                      </Tag>
                    </td>
                    <td style={S.td}>
                      <Tag color={g.status==="resolved"?"#27ae60":"#e67e22"} small>{g.status}</Tag>
                    </td>
                    <td style={{...S.td,fontSize:11,color:"#aaa",maxWidth:150}}>{g.resolution||"Pending"}</td>
                    <td style={S.td}>
                      {g.status==="open"&&isHR&&(()=>{
                        const ResBtn = () => {
                          const [res,setRes] = useState("");
                          return (
                            <div style={{display:"flex",gap:4}}>
                              <input style={{...S.input,fontSize:11,padding:"3px 6px",width:100}}
                                placeholder="Resolution..." value={res} onChange={e=>setRes(e.target.value)} />
                              <button style={{...S.btnSm,background:"#0d2a0d",color:"#27ae60"}}
                                onClick={()=>res&&resolveGrievance(g.id,res)}>✅</button>
                            </div>
                          );
                        };
                        return <ResBtn />;
                      })()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {grievances.length===0&&<Empty text="Koi grievance nahi।" />}
          </div>
        </div>
      </>)}

      {/* ══════════════════════════════════════════════════════════════
          TAB: PENALTIES
      ══════════════════════════════════════════════════════════════ */}
      {tab==="penalties"&&(<>
        <div style={{display:"flex",gap:8,marginBottom:10,flexWrap:"wrap"}}>
          <button style={{...S.btnPrimary,background:"#e74c3c"}} onClick={()=>setPenForm(true)}>⚠️ Impose Penalty</button>
        </div>
        {penForm&&(()=>{
          const PF = () => {
            const [pf,setPf] = useState({targetType:"contractor",targetId:"",targetName:"",
              othersName:"",reason:"",amount:0,penaltyDate:today(),remarks:""});

            // ── Build target list based on type ──────────────────────────
            const musterLabour = (state.musterRoll||[])
              .flatMap(mr=>(mr.entries||mr.labours||[]))
              .reduce((acc,l)=>{
                const nm=(l.name||l.labourName||"").trim();
                if(nm&&!acc.find(x=>x.name===nm)) acc.push({id:"mr_"+nm.replace(/\s/g,"_"),name:nm});
                return acc;
              },[])
              .sort((a,b)=>a.name.localeCompare(b.name));

            const TYPE_CONFIG = {
              contractor: { label:"Sub-contractor", list: state.contractors||[] },
              supplier:   { label:"Supplier",       list: state.suppliers||[] },
              labour:     { label:"Labour (Muster Roll)", list: musterLabour },
              staff:      { label:"Staff / Junior", list: users.filter(u=>!u.isMaster) },
              others:     { label:"Others (unregistered)", list: [] },
            };

            const cfg     = TYPE_CONFIG[pf.targetType] || {};
            const targets  = cfg.list || [];
            const isOthers = pf.targetType === "others";

            const selectTarget = (id) => {
              const t = targets.find(x=>x.id===id);
              setPf({...pf, targetId:id, targetName:t?.name||""});
            };

            const canSubmit = pf.reason && pf.amount>0 &&
              (isOthers ? pf.othersName.trim() : pf.targetName.trim());

            return (
              <div style={S.formBox}>
                <div style={S.formTitle}>⚠️ Penalty Impose Karo</div>

                {/* Type selector — pill buttons */}
                <div style={{marginBottom:12}}>
                  <label style={S.label}>Kiske Upar Penalty</label>
                  <div style={{display:"flex",gap:6,flexWrap:"wrap",marginTop:4}}>
                    {Object.entries(TYPE_CONFIG).map(([k,v])=>(
                      <button key={k}
                        style={{...S.btnSm,
                          background:pf.targetType===k?"#e74c3c":"#1a0a0a",
                          color:pf.targetType===k?"#fff":"#aaa",
                          border:`1px solid ${pf.targetType===k?"#e74c3c":"#333"}`,
                          fontWeight:pf.targetType===k?700:400}}
                        onClick={()=>setPf({...pf,targetType:k,targetId:"",targetName:"",othersName:""})}>
                        {k==="contractor"?"👔":k==="supplier"?"🏪":k==="labour"?"👷":k==="staff"?"🧑‍💼":"❓"} {v.label}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Name selector — registered list */}
                {!isOthers && (
                  <div style={{marginBottom:10}}>
                    <label style={S.label}>
                      {cfg.label} — Naam Select Karo
                      <span style={{color:"#555",fontSize:10,marginLeft:6}}>
                        ({targets.length} registered)
                      </span>
                    </label>
                    {targets.length > 0 ? (
                      <select style={{...S.select,maxWidth:340}} value={pf.targetId} onChange={e=>selectTarget(e.target.value)}>
                        <option value="">— Select Karein —</option>
                        {targets.map(t=>(
                          <option key={t.id} value={t.id}>{t.name}{t.username?` (${t.username})`:""}</option>
                        ))}
                      </select>
                    ) : (
                      <div style={{fontSize:11,color:"#e67e22",padding:"6px 10px",
                        background:"#1a0e00",borderRadius:6,border:"1px solid #e67e22",maxWidth:340}}>
                        ⚠️ Koi registered {cfg.label} nahi mila।
                        <span style={{color:"#888",marginLeft:6}}>
                          {pf.targetType==="labour"?"Muster Roll mein entries add karein।":
                           pf.targetType==="staff"?"HR Module mein staff register karein।":
                           "Register karein ya Others select karein।"}
                        </span>
                      </div>
                    )}
                  </div>
                )}

                {/* Others — free text name */}
                {isOthers && (
                  <div style={{marginBottom:10}}>
                    <label style={S.label}>Naam Darj Karein (unregistered)</label>
                    <input style={{...S.input,maxWidth:340}}
                      placeholder="Jis par penalty hai uska naam likhein..."
                      value={pf.othersName}
                      onChange={e=>setPf({...pf,othersName:e.target.value,targetName:e.target.value})} />
                  </div>
                )}

                {/* Amount + Date */}
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:10,marginBottom:10}}>
                  <LI label="Penalty Amount (₹) *" type="number" value={pf.amount||""} onChange={v=>setPf({...pf,amount:+v})} />
                  <LI label="Date" type="date" value={pf.penaltyDate} onChange={v=>setPf({...pf,penaltyDate:v})} />
                </div>

                <LI label="Reason *" value={pf.reason} onChange={v=>setPf({...pf,reason:v})} />
                <LI label="Remarks (optional)" value={pf.remarks} onChange={v=>setPf({...pf,remarks:v})} />

                {/* Summary preview */}
                {canSubmit && (
                  <div style={{background:"#1a0a0a",border:"1px solid #e74c3c",borderRadius:8,
                    padding:"8px 14px",marginTop:8,fontSize:12,color:"#ccc"}}>
                    <b style={{color:"#e74c3c"}}>Preview:</b> {TYPE_CONFIG[pf.targetType]?.label} —&nbsp;
                    <b style={{color:"#fff"}}>{isOthers?pf.othersName:pf.targetName}</b> par&nbsp;
                    <b style={{color:"#e74c3c"}}>₹{(pf.amount||0).toLocaleString("en-IN")}</b> penalty —&nbsp;
                    <i style={{color:"#888"}}>{pf.reason}</i>
                  </div>
                )}

                <div style={{display:"flex",gap:8,marginTop:12}}>
                  <button style={{...S.btnPrimary,background:canSubmit?"#e74c3c":"#555",cursor:canSubmit?"pointer":"not-allowed"}}
                    onClick={()=>canSubmit&&savePenalty({...pf,targetName:isOthers?pf.othersName:pf.targetName})}>
                    ⚠️ Impose Penalty
                  </button>
                  <button style={S.btnSecondary} onClick={()=>setPenForm(null)}>Cancel</button>
                </div>
              </div>
            );
          };
          return <PF />;
        })()}
        <div style={S.card}>
          <div style={{overflowX:"auto"}}>
            <table style={S.table}>
              <thead><tr>
                {["Against","Type","Reason","Amount","Date","Imposed By","Status","Action"].map(h=>(
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {penalties.map(p=>(
                  <tr key={p.id} style={S.tr}>
                    <td style={{...S.td,fontWeight:700}}>{p.targetName||"—"}</td>
                    <td style={S.td}><Tag color="#e74c3c" small>{p.targetType}</Tag></td>
                    <td style={{...S.td,fontSize:11}}>{p.reason}</td>
                    <td style={{...S.td,fontWeight:800,color:"#e74c3c"}}>₹{(p.amount||0).toLocaleString("en-IN")}</td>
                    <td style={S.td}>{p.penaltyDate}</td>
                    <td style={{...S.td,fontSize:11,color:"#888"}}>{p.imposedByName||"—"}</td>
                    <td style={S.td}>
                      <Tag color={p.status==="active"?"#e74c3c":"#27ae60"} small>{p.status}</Tag>
                    </td>
                    <td style={S.td}>
                      {p.status==="active"&&isHR&&(
                        <button style={{...S.btnSm,background:"#0d2a0d",color:"#27ae60",fontSize:11}}
                          onClick={()=>updHR({hrPenalties:penalties.map(x=>x.id===p.id?{...x,status:"waived",waivedBy:me.name}:x)})}>
                          Waive
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {penalties.length===0&&<Empty text="Koi penalty record nahi।" />}
          </div>
        </div>
      </>)}

      {/* ══════════════════════════════════════════════════════════════
          TAB: EPF / ESIC COMPLIANCE
      ══════════════════════════════════════════════════════════════ */}
      {tab==="compliance"&&<ComplianceTab state={state} users={users} updHR={updHR} me={me} contractors={contractors} />}

      {/* ══════════════════════════════════════════════════════════════
          TAB: MY PROFILE
      ══════════════════════════════════════════════════════════════ */}
      {tab==="myprofile"&&me.id&&(<>
        <div style={S.card}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
            <div>
              <div style={{fontSize:"clamp(12px,3vw,22px)",fontWeight:800,color:"#e67e22",marginBottom:4}}>{me.name}</div>
              <Tag color={USER_ROLES[me.role]?.color||"#888"}>{USER_ROLES[me.role]?.label||me.role}</Tag>
              <div style={{marginTop:12}}>
                {[["Username",me.username],["Designation",me.designation||"—"],
                  ["Department",me.department||"—"],["Phone",me.phone||"—"],
                  ["Email",me.email||"—"],["Joining",me.joiningDate||"—"],
                  ["Reports To",users.find(u=>u.id===me.reportingTo)?.name||"—"],
                ].map(([k,v])=>(
                  <div key={k} style={{display:"flex",gap:10,padding:"5px 0",borderBottom:"1px solid #1a1a1a",fontSize:12}}>
                    <span style={{color:"#666",width:100,flexShrink:0}}>{k}</span>
                    <span style={{color:"#ccc"}}>{v}</span>
                  </div>
                ))}
              </div>
            </div>
            <div>
              <div style={{fontWeight:700,color:"#8e44ad",marginBottom:8}}>🔐 My Module Access</div>
              <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:12}}>
                {(me.rights||[]).map(r=>(
                  <Tag key={r} color="#8e44ad" small>{MODULE_LIST.find(m=>m.id===r)?.label||r}</Tag>
                ))}
              </div>
              <div style={{fontWeight:700,color:"#27ae60",marginBottom:8}}>✅ My Approval Rights</div>
              <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:16}}>
                {(me.approvalRights||[]).map(r=>(
                  <Tag key={r} color="#27ae60" small>{APPROVAL_MODULES.find(m=>m.id===r)?.label||r}</Tag>
                ))}
                {(me.approvalRights||[]).length===0&&<span style={{fontSize:11,color:"#555"}}>None</span>}
              </div>

              {/* Change Password */}
              <div style={{background:"#0a0a0a",border:"1px solid #333",borderRadius:8,padding:12}}>
                <div style={{fontWeight:700,color:"#e67e22",marginBottom:8,fontSize:12}}>🔑 Change My Password</div>
                {myPwd===null?(
                  <button style={{...S.btnSm,background:"#1a1a0a",color:"#e67e22",border:"1px solid #e67e22"}}
                    onClick={()=>setMyPwd({old:"",newP:"",confirm:""})}>Change Password</button>
                ):(()=>{
                  const PwdForm = () => {
                    const [pw,setPw] = useState({old:"",newP:"",confirm:""});
                    return (<div>
                      <LI label="Current Password" type="password" value={pw.old} onChange={v=>setPw({...pw,old:v})} />
                      <LI label="New Password" type="password" value={pw.newP} onChange={v=>setPw({...pw,newP:v})} />
                      <LI label="Confirm New Password" type="password" value={pw.confirm} onChange={v=>setPw({...pw,confirm:v})} />
                      <div style={{display:"flex",gap:6,marginTop:8}}>
                        <button style={{...S.btnPrimary,background:"#27ae60",fontSize:12}} onClick={()=>{
                          if(pw.old!==me.password){alert("Current password wrong!");return;}
                          if(pw.newP!==pw.confirm){alert("Passwords don't match!");return;}
                          if(pw.newP.length<4){alert("Password too short!");return;}
                          updHR({users:users.map(u=>u.id===me.id?{...u,password:pw.newP}:u)});
                          setMyPwd(null); alert("Password changed!");
                        }}>✅ Update</button>
                        <button style={S.btnSecondary} onClick={()=>setMyPwd(null)}>Cancel</button>
                      </div>
                    </div>);
                  };
                  return <PwdForm />;
                })()}
              </div>
            </div>
          </div>
        </div>
      </>)}

      {/* ══════════════════════════════════════════════════════════════
          TAB: DEPARTMENTS (HR only — platform-wide)
      ══════════════════════════════════════════════════════════════ */}
      {tab==="departments"&&isHR&&(
        <DepartmentManager
          departments={globalDepartments||DEFAULT_DEPARTMENTS}
          onAdd={addGlobalDepartment}
          onRemove={removeGlobalDepartment}
        />
      )}

      {/* ── WHISTLE BLOWER TAB (Master/Admin only) ── */}
      {tab==="whistleblower"&&isMaster&&(()=>{
        const WB = () => {
          const whistles = state.whistleBlower || [];
          const [filter, setFilter] = useState("all");
          const filtered = filter==="all" ? whistles : whistles.filter(w=>w.status===filter);
          const [resolveId, setResolveId] = useState(null);
          const [resolution, setResolution] = useState("");
          return (
            <div>
              <div style={{...S.card,marginBottom:12,border:"1px solid #e74c3c44",background:"rgba(231,76,60,0.04)"}}>
                <div style={{fontWeight:700,color:"#e74c3c",fontSize:14,marginBottom:4}}>
                  🔔 Whistle Blower Reports
                </div>
                <div style={{fontSize:11,color:"var(--text-dim)"}}>
                  Yeh reports strictly confidential hain — sirf aap (Admin/MD/Director/CEO) dekh sakte hain।
                  HR ko nahi dikhti।
                </div>
              </div>

              {/* Filter tabs */}
              <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap"}}>
                {[["all",`All (${whistles.length})`],["open",`🔴 Open (${whistles.filter(w=>w.status==="open").length})`],
                  ["in_progress",`🔄 In Progress (${whistles.filter(w=>w.status==="in_progress").length})`],
                  ["resolved",`✅ Resolved (${whistles.filter(w=>w.status==="resolved").length})`]
                ].map(([v,label])=>(
                  <button key={v} onClick={()=>setFilter(v)}
                    style={{...S.tabBtn,fontSize:11,
                      background:filter===v?"#e74c3c":"var(--bg-input)",
                      color:filter===v?"#fff":"var(--text-muted)",
                      border:`1px solid ${filter===v?"#e74c3c":"var(--border)"}`}}>
                    {label}
                  </button>
                ))}
              </div>

              {filtered.length===0 ? <Empty text="Koi report nahi।" /> :
                filtered.sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||"")).map(w=>(
                  <div key={w.id} style={{...S.card,marginBottom:10,
                    border:`1px solid ${w.urgency==="critical"?"#e74c3c":w.urgency==="urgent"?"#f39c12":"var(--border)"}`}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:8}}>
                      <div style={{flex:1}}>
                        <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:6}}>
                          <span style={{fontWeight:800,fontSize:14}}>{w.title}</span>
                          {w.urgency==="critical"&&<Tag color="#e74c3c" small>🚨 CRITICAL</Tag>}
                          {w.urgency==="urgent"&&<Tag color="#f39c12" small>🔴 URGENT</Tag>}
                          <Tag color={w.status==="resolved"?"#27ae60":w.status==="in_progress"?"#f39c12":"#e74c3c"} small>
                            {w.status}
                          </Tag>
                        </div>
                        <div style={{fontSize:11,color:"var(--text-dim)",marginBottom:6}}>
                          By: <b>{w.submittedByName||"Anonymous"}</b>
                          {w.againstName&&<span> | Against: <b>{w.againstName}</b></span>}
                          {" | "}{w.createdAt?.slice(0,10)||"—"}
                        </div>
                        <div style={{fontSize:12,color:"var(--text-muted)",lineHeight:1.5}}>{w.description}</div>
                        {w.resolution&&(
                          <div style={{marginTop:8,fontSize:12,color:"#27ae60",background:"#27ae6011",
                            padding:"6px 10px",borderRadius:6}}>
                            ✅ Resolution: {w.resolution} — {w.resolvedBy} ({w.resolvedAt})
                          </div>
                        )}
                      </div>
                      <div style={{display:"flex",gap:4,flexDirection:"column"}}>
                        {w.status!=="resolved"&&(
                          <>
                            {w.status==="open"&&(
                              <button style={{...S.btnSm,background:"#f39c12",fontSize:10}}
                                onClick={()=>upd({whistleBlower:(state.whistleBlower||[]).map(x=>x.id===w.id?{...x,status:"in_progress"}:x)})}>
                                🔄 In Progress
                              </button>
                            )}
                            {resolveId===w.id ? (
                              <div style={{display:"flex",gap:4,flexDirection:"column"}}>
                                <input style={{...S.input,fontSize:11,padding:"4px 8px",width:160}}
                                  placeholder="Resolution note..." value={resolution}
                                  onChange={e=>setResolution(e.target.value)} />
                                <button style={{...S.btnSm,background:"#27ae60",fontSize:10}}
                                  onClick={()=>{
                                    if(!resolution.trim()){alert("Resolution note daalen।");return;}
                                    upd({whistleBlower:(state.whistleBlower||[]).map(x=>x.id===w.id?{
                                      ...x,status:"resolved",resolution,
                                      resolvedBy:me.name,resolvedAt:today()
                                    }:x)});
                                    setResolveId(null); setResolution("");
                                  }}>✅ Resolve</button>
                                <button style={{...S.btnSm,background:"#555",fontSize:10}}
                                  onClick={()=>{setResolveId(null);setResolution("");}}>Cancel</button>
                              </div>
                            ) : (
                              <button style={{...S.btnSm,background:"#27ae60",fontSize:10}}
                                onClick={()=>setResolveId(w.id)}>✅ Resolve</button>
                            )}
                          </>
                        )}
                        <button style={{...S.btnSm,background:"#555",fontSize:10}}
                          onClick={()=>{
                            if(_isWeb&&!window.confirm("Delete karein?"))return;
                            upd({whistleBlower:(state.whistleBlower||[]).filter(x=>x.id!==w.id)});
                          }}>🗑</button>
                      </div>
                    </div>
                  </div>
                ))
              }
            </div>
          );
        };
        return <WB />;
      })()}

    </div>



  );
}
function UserForm({ data, existingUsers, onSave, onCancel }) {
  const [f, setF] = useState({ name: "", username: "", password: "", role: "supervisor", ...data });
  const [err, setErr] = useState("");
  const validate = () => {
    if (!f.name.trim()) { setErr("नाम आवश्यक है");
    return false; }
    if (!f.username.trim()) { setErr("Username आवश्यक है");
    return false; }
    if (f.username === MASTER_ADMIN.username) { setErr("यह username reserved है");
    return false; }
    if (!f.password || (f.password||"").length < 4) { setErr("Password कम से कम 4 characters का होना चाहिए");
    return false; }
    const dup = existingUsers.find((u) => u.username === f.username && u.id !== f.id);
    if (dup) { setErr("यह username पहले से लिया जा चुका है");
    return false; }
    return true;};
  return (
    <div style={{ ...S.formBox, marginTop: 12 }}>
      <div style={S.formTitle}>{data.id ? "✏️ User Edit करें" : "👤 नया User बनाएं"}</div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(200px,1fr))", gap: 12 }}>
        <LI label="पूरा नाम *" value={f.name} onChange={(v) => setF({ ...f, name: v })} />
        <LI label="Username * (login के लिए)" value={f.username} onChange={(v) => setF({ ...f, username: v.replace(/\s/g, "") })} />
        <LI label="Password * (min 4 chars)" value={f.password} onChange={(v) => setF({ ...f, password: v })} />
        <div>
          <label style={S.label}>Role / भूमिका *</label>
          <select style={S.select} value={f.role} onChange={(e) => setF({ ...f, role: e.target.value })}>
            {Object.entries(USER_ROLES).filter(([k]) => k !== "master_admin").map(([k, v]) => (
              <option key={k} value={k}>{v.label}</option>))}
          </select>
        </div>
      </div>
      {/* Show rights for selected role */}
      <div style={{ marginTop: 10, padding: 10, background: "#111", borderRadius: 6 }}>
        <div style={{ fontSize: 11, color: "#888", marginBottom: 4 }}>इस role को मिलने वाले अधिकार:</div>
        <div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>
          {(USER_ROLES[f.role]?.rights || []).map((r) => (
            <span key={r} style={{ fontSize: 10, padding: "1px 6px", background: "#1e1e1e", color: USER_ROLES[f.role]?.color, borderRadius: 4, border: `1px solid ${USER_ROLES[f.role]?.color}44` }}>{r}</span>
          ))}
        </div>
      </div>
      {err && <div style={{ color: "#e74c3c", fontSize: 13, marginTop: 8 }}>⚠ {err}</div>}
      <div style={{ ...S.row, gap: 8, marginTop: 12 }}>
        <button style={S.btnPrimary} onClick={() => { setErr(""); validate() && onSave(f); }}>
          {data.id ? "Update करें" : "User बनाएं"}
        </button>
        <button style={S.btnSecondary} onClick={onCancel}>Cancel</button>
      </div>
    </div>
  );
}
// ─── PROJECTS ──────────────────────────────────────────────────────────────────

function Projects({ state, upd, rights, companyType }) {
  const canCreateProject = (rights||[]).includes("create_project") || (rights||[]).includes("master_admin");
  const isMaster = (rights||[]).includes("master_admin");
  const [form, setForm] = useState(null);
  const [viewId, setViewId] = useState(null);
  const [showCatMgr, setShowCatMgr] = useState(false);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const allCategories = [...BUILTIN_CATEGORIES, ...(state.customCategories || [])];
  const saveProject = (data) => {
    if (data.id) {
      upd({ projects: (state.projects||[]).map((p) => p.id === data.id ? { ...p, ...data } : p) });
    } else {
      let substages = [];
      if (data.subcategoryId && data.subcategoryId !== "__blank__" && data.useTemplate !== false) {
        const cat = allCategories.find((c) => c.id === data.categoryId);
        const subcat = cat?.subcategories?.find((s) => s.id === data.subcategoryId);
        if (subcat) {
          const templates = resolveSubstages(cat, subcat, data.floorAreas || {});
          substages = buildSubstagesFromTemplate(templates)}
}
      const catName = allCategories.find((c) => c.id === data.categoryId)?.name || "";
      const subcatName = allCategories.find((c) => c.id === data.categoryId)?.subcategories?.find((s) => s.id === data.subcategoryId)?.name || "";
      const proj = { ...data, id: uid(), status: "active", substages, createdAt: today(), transactions: [], categoryName: catName, subcategoryName: subcatName };
      upd({ projects: [...state.projects, proj], activeProject: proj.id });}
    setForm(null);};
  const doDelete = (id) => {
    upd({
      projects: (state.projects||[]).filter((x) => x.id !== id),
      activeProject: state.activeProject === id ? null : state.activeProject,});
    setConfirmDeleteId(null);};
  if (viewId) {
    const proj = (state.projects||[]).find((p) => p.id === viewId);
    if (proj) return <ProjectDetail proj={proj} state={state} upd={upd} onBack={() => setViewId(null)} />;
}
  if (showCatMgr) return <CategoryManager state={state} upd={upd} onBack={() => setShowCatMgr(false)} />;
  return (
    <div>
      <div style={S.rowBetween}>
        <STitle>Projects</STitle>
        <div style={S.row}>
          <button style={{ ...S.btnSecondary, fontSize: 12 }} onClick={() => setShowCatMgr(true)}>⚙️ Categories</button>
          {canCreateProject && <button style={S.btnPrimary} onClick={() => setForm({})}>+ New Project</button>}
          {!canCreateProject && <div style={{fontSize:11,color:"#888",padding:"6px 10px",background:"var(--bg-input)",borderRadius:6}}>🔒 Project banana ke liye Admin se permission lein</div>}
        </div>
      </div>
      {form && <ProjectForm data={form} allCategories={allCategories} clients={state.clients||[]} companyType={companyType} onAddClient={(c)=>upd({clients:[...(state.clients||[]),{...c,id:uid(),createdAt:today()}]})} onSave={saveProject} onCancel={() => setForm(null)} />}
      <div style={S.cardGrid}>
        {(state.projects||[]).map((p) => (
          <div key={p.id} style={S.projCard}>
            <div style={{ fontWeight: 700, fontSize: 15, color: "#e67e22" }}>{p.name}</div>
            <div style={{ fontSize: 11, color: "#888", marginTop: 2 }}>
              {p.categoryName && <Tag color="#8e44ad" small style={{ marginRight: 4 }}>{p.categoryName}</Tag>}
              {p.subcategoryName && <Tag color="#2980b9" small>{p.subcategoryName}</Tag>}
            </div>
            <div style={{ fontSize: 12, color: "#999", marginTop: 4 }}>{p.client} | {p.location}</div>
            <div style={{ marginTop: 6 }}><Tag color={p.status === "active" ? "#27ae60" : "#888"}>{p.status}</Tag></div>
            {/* Budget vs Allocated warning */}
            {(() => {
              const allocTotal = (p.substages||[]).reduce((sum,ss) => sum + (ss.amount||0), 0);
              const projBudget = p.budget || 0;
              const isShort    = allocTotal > 0 && projBudget < allocTotal;
              const suggested  = Math.ceil(allocTotal * 1.10); // +10% supervision
              return (
                <>
                  <div style={{ fontSize:13, marginTop:6, display:"flex", alignItems:"center", gap:8, flexWrap:"wrap" }}>
                    <span>Budget: <b style={{color: isShort ? "#c0392b" : "#e67e22"}}>{INR(projBudget)}</b></span>
                    {allocTotal > 0 && (
                      <span style={{fontSize:11, color:"#888"}}>
                        | Allocated: <b style={{color: isShort?"#e74c3c":"#27ae60"}}>{INR(allocTotal)}</b>
                      </span>
                    )}
                  </div>
                  {isShort && (
                    <div style={{
                      marginTop:6, padding:"7px 10px",
                      background:"#1a0000", border:"1px solid #c0392b",
                      borderRadius:6, fontSize:12
                    }}>
                      <div style={{color:"#e74c3c", fontWeight:700, marginBottom:4}}>
                        ⚠️ Budget कम है! Allocated से <b>{INR(allocTotal - projBudget)}</b> कम
                      </div>
                      <div style={{color:"#aaa", fontSize:11, marginBottom:6}}>
                        Allocated {INR(allocTotal)} + 10% Supervision = <b style={{color:"#f39c12"}}>{INR(suggested)}</b>
                      </div>
                      <button
                        style={{...S.btnSm, background:"#27ae60", fontSize:11, padding:"3px 10px"}}
                        onClick={(e) => {
                          e.stopPropagation();
                          upd({ projects: (state.projects||[]).map(px =>
                            px.id === p.id ? {...px, budget: suggested} : px
                          )});
                        }}
                      >
                        ⚡ Budget बढ़ाएं → {INR(suggested)}
                      </button>
                    </div>
                  )}
                </>
              );
            })()}
            <div style={{ fontSize: 12, marginTop:4 }}>{p.startDate} → {p.endDate}</div>
            <ProgressBar pct={getProjPct(p)} style={{ marginTop: 8 }} />
            {/* Running + Last Completed Stage */}
            {(() => {
              const subs = p.substages || [];
              const running = subs.find(s => s.status === "ongoing");
              const completed = [...subs].reverse().find(s => s.status === "done");
              return (
                <div style={{marginTop:6,fontSize:11,display:"flex",flexWrap:"wrap",gap:6}}>
                  {running && <span style={{background:"#1a0e00",border:"1px solid #e67e22",borderRadius:4,padding:"2px 7px",color:"#e67e22"}}>▶ {running.name}</span>}
                  {completed && <span style={{background:"#0a1a0a",border:"1px solid #27ae60",borderRadius:4,padding:"2px 7px",color:"#27ae60"}}>✓ {completed.name}</span>}
                  {!running && !completed && <span style={{color:"#555"}}>अभी शुरू नहीं हुआ</span>}
                </div>
              );
            })()}
            {/* Inline delete confirmation */}
            {confirmDeleteId === p.id ? (
              <div style={{ marginTop: 10, background: "#2a0000", border: "1px solid #c0392b", borderRadius: 8, padding: 10 }}>
                <div style={{ fontSize: 12, color: "#e74c3c", marginBottom: 8 }}>⚠️ क्या सच में delete करें?<br/><span style={{color:"#999"}}>सारा data हमेशा के लिए हट जाएगा।</span></div>
                <div style={S.row}>
                  <button style={{ ...S.btnSm, background: "#c0392b" }} onClick={() => doDelete(p.id)}>हाँ, Delete करें</button>
                  <button style={{ ...S.btnSm, background: "#444" }} onClick={() => setConfirmDeleteId(null)}>Cancel</button>
                </div>
              </div>
            ) : (
              <div style={{ ...S.row, gap: 6, marginTop: 10 }}>
                <button style={S.btnSm} onClick={() => setViewId(p.id)}>View</button>
                <button style={S.btnSm} onClick={() => setForm(p)}>Edit</button>
                <button style={{ ...S.btnSm, background: "#c0392b" }} onClick={() => setConfirmDeleteId(p.id)}>🗑 Delete</button>
              </div>)}
          </div>))}
      </div>
      {(state.projects||[]).length === 0 && <Empty text="कोई project नहीं है। New Project बनाएं।" />}
    </div>
  );
}
// ─── CATEGORY MANAGER ─────────────────────────────────────────────────────────

function ClientsModule({ state, upd, rights }) {
  const canCreateClient   = (rights||[]).includes("create_client")   || (rights||[]).includes("master_admin");
  const canCreateProposal = (rights||[]).includes("create_proposal") || (rights||[]).includes("master_admin");
  const [tab, setTab] = useState("master");
  const [form, setForm] = useState(null);
  const [propForm, setPropForm] = useState(null);
  const [billForm, setBillForm] = useState(null);
  const [confirmDel, setConfirmDel] = useState(null);
  const [fromProposal, setFromProposal] = useState(null);
  const clients = state.clients || [];
  const proposals = state.proposals || [];
  const clientBills = state.clientBills || [];
  const agreements = (state.agreements||[]).filter(a=>a.type==="client");
  const saveClient = (data) => {
    if (data.id) upd({ clients: clients.map(c => c.id===data.id ? data : c) });
    else upd({ clients: [...clients, {...data, id:uid(), createdAt:today()}] });setForm(null);};
    const saveProp = (data) => {
    if (data.id) upd({ proposals: proposals.map(p => p.id===data.id ? {...data,updatedAt:today()} : p) });
    else upd({ proposals: [...proposals, {...data, id:uid(), status:data.status||"draft", createdAt:today()}] });setPropForm(null);};
    const saveBill = (data) => {
    if(data.id) upd({ clientBills: clientBills.map(b=>b.id===data.id?{...data,updatedAt:today()}:b) });
    else upd({ clientBills: [...clientBills, {...data, id:uid(), createdAt:today()}] });
    setBillForm(null);};
    const CSV_COLS = [{key:"name",label:"Name"},{key:"company",label:"Company"},{key:"mobile",label:"Mobile"},{key:"email",label:"Email"},{key:"address",label:"Address"}];
    return (
    <div><STitle>🤝 Client Management</STitle><div style={S.tabs}>{["master","proposals","agreements","bills"].map(t=>(
          <button key={t} style={{...S.tabBtn,background:tab===t?"#e67e22":"#2a2a2a"}} onClick={()=>setTab(t)}>
            {t==="master"?"👥 Clients":t==="proposals"?"📋 Proposals":t==="agreements"?"📝 Agreements":"🧾 Running Bills"}</button>))}</div>{tab==="master" && (<div><div style={S.rowBetween}>
            <ImportExportBar label="Clients" cols={CSV_COLS} data={clients} onExport={()=>exportCSV(clients,"Clients.csv",CSV_COLS)}
              onImport={(rows)=>upd({clients:[...clients,...rows.map(r=>({...r,id:uid(),createdAt:today()}))]})}/>{canCreateClient?<button style={S.btnPrimary} onClick={()=>setForm({})}>+ Add Client</button>:<span style={{fontSize:11,color:"#888",padding:"4px 8px",background:"var(--bg-input)",borderRadius:6,marginLeft:4}}>🔒 Permission nahi</span>}</div>{form && (
            <div style={S.formBox}><div style={S.formTitle}>{form.id?"Edit Client":"New Client"}</div><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:12}}>
                <LI label="Client Name *" value={form.name||""} onChange={v=>setForm({...form,name:v})} /><LI label="Company / Org." value={form.company||""} onChange={v=>setForm({...form,company:v})} />
                <LI label="Mobile" value={form.mobile||""} onChange={v=>setForm({...form,mobile:v})} /><LI label="Email" value={form.email||""} onChange={v=>setForm({...form,email:v.toLowerCase()})} />
                <LI label="Address" value={form.address||""} onChange={v=>setForm({...form,address:v})} /><LI label="GSTIN (if any)" value={form.gstin||""} onChange={v=>setForm({...form,gstin:v})} /><LI label="PAN No." value={form.panNo||""} onChange={v=>setForm({...form,panNo:v.toUpperCase().replace(/[^A-Z0-9]/g,"")})} /></div>
              <div style={{...S.row,gap:8,marginTop:12}}><button style={S.btnPrimary} onClick={()=>form.name&&saveClient(form)}>Save</button>
                <button style={S.btnSecondary} onClick={()=>setForm(null)}>Cancel</button></div></div>)}<div style={{overflowX:"auto"}}><table style={S.table}><thead><tr>
                <th style={S.th}>Name</th><th style={S.th}>Company</th><th style={S.th}>Mobile</th><th style={S.th}>Email</th><th style={S.th}>Projects</th><th style={S.th}>Actions</th></tr></thead><tbody>
                {clients.map(c=>{
                  const cProj = (state.projects||[]).filter(p=>p.client===c.name).length;
                  return (<tr key={c.id}><td style={{...S.td,fontWeight:700}}>{c.name}</td><td style={S.td}>{c.company}</td>
                      <td style={S.td}>{c.mobile}</td><td style={S.td}>{c.email}</td><td style={S.td}><Tag color="#27ae60" small>{cProj} Projects</Tag></td><td style={S.td}>{confirmDel===c.id ? (
                          <span style={{display:"flex",gap:4}}>
                            <button style={{...S.btnSm,background:"#c0392b",fontSize:11}} onClick={()=>{upd({clients:clients.filter(x=>x.id!==c.id)});setConfirmDel(null)}
                            }>Del</button>
                            <button style={{...S.btnSm,background:"#444",fontSize:11}} onClick={()=>setConfirmDel(null)}>✕</button></span>):(<span style={{display:"flex",gap:4}}>
                            <button style={S.btnSm} onClick={()=>setForm(c)}>✏</button><button style={{...S.btnSm,background:"#c0392b"}} onClick={()=>setConfirmDel(c.id)}>🗑</button>
                            <button style={{...S.btnSm,background:"#8e44ad"}} onClick={()=>setPropForm({clientId:c.id,clientName:c.name})}>Proposal</button></span>)}</td></tr>)
                            }
                          )}
                        </tbody></table>
            {clients.length===0 && <Empty text="कोई client नहीं है" />}</div></div>)}{tab==="proposals" && (<div><div style={S.rowBetween}>
            <div style={{fontSize:13,color:"#aaa"}}>{proposals.length} Proposals</div>{canCreateProposal?<button style={S.btnPrimary} onClick={()=>setPropForm({})}>+ New Proposal</button>:<span style={{fontSize:11,color:"#888",padding:"4px 8px",background:"var(--bg-input)",borderRadius:6}}>🔒 Permission nahi</span>}</div>
          {propForm && <ProposalForm data={propForm} clients={clients} projects={state.projects} categories={state.customCategories||[]} onSave={saveProp} onCancel={()=>setPropForm(null)} />}
          <div style={{overflowX:"auto",marginTop:12}}><table style={S.table}><thead><tr><th style={S.th}>Proposal No</th><th style={S.th}>Date</th><th style={S.th}>Client</th><th style={S.th}>Type</th>
                <th style={S.th}>Amount</th><th style={S.th}>Status</th><th style={S.th}>Actions</th></tr></thead><tbody>{proposals.map(p => (<tr key={p.id}>
                    <td style={{...S.td,color:"#e67e22",fontWeight:700}}>{p.propNo}</td><td style={S.td}>{p.date}</td><td style={{...S.td,fontWeight:600}}>{p.clientName}</td><td style={S.td}>
                      <Tag color="#2980b9" small>{p.proposalType||"Item Rate"}</Tag></td><td style={{...S.td,fontWeight:700,color:"#27ae60"}}>{INR(p.estimatedValue)}</td><td style={S.td}><select
                        style={{...S.select,padding:"2px 6px",fontSize:11,background: p.status==="accepted"?"#0d2a0d":p.status==="rejected"?"#2a0d0d":"#1a1a1a",
                          color: p.status==="accepted"?"#27ae60":p.status==="rejected"?"#e74c3c":p.status==="submitted"?"#e67e22":"#aaa"
                        }} value={p.status} onChange={e => upd({proposals: proposals.map(x => x.id===p.id ? {...x,status:e.target.value} : x)})}><option value="draft">Draft</option>
                        <option value="submitted">Submitted</option><option value="accepted">Accepted</option><option value="rejected">Rejected</option></select></td><td style={S.td}>
                      <span style={{display:"flex",gap:4,flexWrap:"wrap"}}><button style={{...S.btnSm,background:"#e67e22"}} onClick={()=>setPropForm(p)} title="Edit Proposal">✏</button>
                        <button style={{...S.btnSm,background:"#e74c3c"}} onClick={()=>{
                            const cli2 = clients.find(c=>c.id===p.clientId);
                            const amt = p.estimatedValue||0;
                            const html = buildProposalHTML(p,cli2,amt);
                            const blob = new Blob([html],{type:"text/html;charset=utf-8"});
                            const url = URL.createObjectURL(blob);
                            _openBlob(blob, "report.html");
                          }} title="Print / PDF">🖨</button>{p.status==="accepted" && (<button style={{...S.btnSm,background:"#27ae60",fontWeight:700}} onClick={()=>{ setFromProposal(p); setTab("agreements"); }}
                            title="Generate Agreement from this Proposal">📝 Agreement</button>)}<button style={{...S.btnSm,background:"#c0392b"}}
                          onClick={()=>upd({proposals:proposals.filter(x=>x.id!==p.id)})} title="Delete">🗑</button></span></td></tr>))}</tbody></table>
            {proposals.length===0 && <Empty text="कोई proposal नहीं है" />}</div></div>)}{tab==="agreements" && (<AgreementsPanel state={state} upd={upd} type="client" parties={clients} partyLabel="Client"
          fromProposal={fromProposal} onClearFromProposal={()=>setFromProposal(null)} />)}{tab==="bills" && (<div>{/* ── Pending Bill Alerts — completed stages without client bills ── */}{(() => {
            const approvedProg = (state.projectProgress||[]).filter(e=>e.status==="approved");
            const alerts = [];
            agreements.filter(ag=>ag.status!=="cancelled").forEach(ag=>{
              const proj = (state.projects||[]).find(p=>p.id===ag.projectId);
              if(!proj) return;
              (proj.substages||[]).filter(ss=>ss.status==="done").forEach(ss=>{
                const hasBill = clientBills.some(b=>b.agId===ag.id && (b.stageId===ss.id || b.stage===ss.name));
                const hasApproved = approvedProg.some(e=>
                  e.projectId===proj.id && (e.stageId===ss.id || e.stageName===ss.name));
                if(!hasBill && hasApproved) alerts.push({ag, proj, ss});
              });
            });
            if(!alerts.length) return null;
            return (
              <div style={{background:"#0d1a00",border:"2px solid #27ae60",borderRadius:8,padding:12,marginBottom:14}}>
                <div style={{color:"#27ae60",fontWeight:700,fontSize:13,marginBottom:8}}>
                  🔔 {alerts.length} Stage{alerts.length>1?"s":""} Complete — Client को Bill raise करें
                </div>
                {alerts.map((a,i)=>{
                  const matchedPT = (a.ag.paymentTerms||[]).find(pt=>
                    pt.stage?.toLowerCase().includes(a.ss.name?.toLowerCase().split(" ")[0]) ||
                    a.ss.name?.toLowerCase().includes(pt.stage?.toLowerCase().split(" ")[0]));
                  const grossAmt = matchedPT ? Math.round((a.ag.value||0)*matchedPT.pct/100) : 0;
                  return (
                    <div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between",background:"#111",borderRadius:6,padding:"8px 12px",marginBottom:6,flexWrap:"wrap",gap:8}}>
                      <div>
                        <span style={{color:"#fff",fontWeight:600}}>{a.ag.agNo||"Agreement"}</span>
                        <span style={{color:"#aaa",fontSize:12,marginLeft:8}}>{a.ag.partyName}</span>
                        <span style={{color:"#27ae60",fontSize:12,marginLeft:8}}>→ <b>{a.ss.name}</b></span>
                        <Tag color="#27ae60" small style={{marginLeft:6}}>✓ Completed {a.ss.completedDate||""}</Tag>
                        {matchedPT && <span style={{color:"#e67e22",fontSize:12,marginLeft:8}}>{matchedPT.pct}% = {INR(grossAmt)}</span>}
                      </div>
                      <button style={{...S.btnSm,background:"#27ae60",fontWeight:700}}
                        onClick={()=>{
                          const progEntries=(state.projectProgress||[]).filter(e=>e.status==="approved"&&e.projectId===a.proj.id&&(e.stageId===a.ss.id||e.stageName===a.ss.name));
                          setBillForm({
                            clientId:a.ag.partyId, clientName:a.ag.partyName, agId:a.ag.id, agNo:a.ag.agNo,
                            projectId:a.proj.id, projectName:a.proj.name, stageId:a.ss.id, stage:a.ss.name, workDone:a.ss.name,
                            billType:"Running Bill", grossAmount:grossAmt, paymentStageId:matchedPT?.id||"", _progressEntries:progEntries,
                          });
                        }}>
                        + Bill Raise करें
                      </button>
                    </div>
                  );
                })}
              </div>
            );
          })()}<div style={S.rowBetween}><div style={{fontSize:13,color:"#aaa"}}>{clientBills.length} Bills  | 
              Received: <b style={{color:"#27ae60"}}>{INR(clientBills.filter(b=>b.status==="paid").reduce((s,b)=>s+(b.netAmount||0),0))}</b>  
              Pending: <b style={{color:"#e74c3c"}}>{INR(clientBills.filter(b=>b.status!=="paid").reduce((s,b)=>s+(b.netAmount||0),0))}</b></div>
            <button style={S.btnPrimary} onClick={()=>setBillForm({})}>+ New Running Bill</button></div>
          <div style={{fontSize:12,color:"#888",marginBottom:10}}>ये bills हम client को देंगे — Agreement के payment stages के अनुसार</div>{billForm && (<RunningBillForm
              data={billForm} parties={clients} partyLabel="Client"partyKey="clientId" partyNameKey="clientName"workOrders={[]} projects={state.projects} agreements={agreements}
              allBills={clientBills} billType="client"progressEntries={state.projectProgress||[]} onSave={saveBill} onCancel={()=>setBillForm(null)}/>)}<div style={{overflowX:"auto",marginTop:12}}>
            <table style={S.table}><thead><tr><th style={S.th}>Bill No</th><th style={S.th}>Date</th><th style={S.th}>Client</th>
                <th style={S.th}>Ag. Ref</th><th style={S.th}>Stage</th><th style={S.th}>Source</th><th style={S.th}>Gross</th><th style={S.th}>Net</th>
                <th style={S.th}>Status</th><th style={S.th}>Actions</th></tr></thead><tbody>{clientBills.map(b=>(<tr key={b.id} style={{background:b.source==="progress_auto"?"#0d1a0d":undefined}}>
                    <td style={{...S.td,color:"#e67e22",fontWeight:700}}>{b.billNo}</td><td style={S.td}>{b.date}</td><td style={{...S.td,fontWeight:600}}>{b.clientName}</td><td style={S.td}>{b.agNo||"—"}</td>
                    <td style={S.td}>{b.stage||b.workDone ? <Tag color="#27ae60" small>{b.stage||b.workDone}</Tag> : "—"}</td>
                    <td style={S.td}><Tag color={b.source==="progress_auto"?"#2980b9":"#555"} small>{b.source==="progress_auto"?"Auto":"Manual"}</Tag></td><td style={S.td}>{INR(b.grossAmount)}</td>
                    <td style={{...S.td,fontWeight:700,color:"#27ae60"}}>{INR(b.netAmount)}</td><td style={S.td}><select style={{...S.select,padding:"2px 6px",fontSize:11,
                        background:b.status==="paid"?"#0d2a0d":b.status==="submitted"?"#1a1a0d":b.status==="draft"?"#1a1a1a":"#111",color:b.status==="paid"?"#27ae60":b.status==="submitted"?"#f39c12":"#e67e22"
                      }} value={b.status||"draft"} onChange={e=>upd({clientBills:clientBills.map(x=>x.id===b.id?{...x,status:e.target.value}:x)})}><option value="draft">📝 Draft</option>
                        <option value="submitted">📤 Submitted</option><option value="paid">💰 Paid ✓</option></select></td><td style={S.td}><span style={{display:"flex",gap:4}}>
                        <button style={{...S.btnSm,background:"#e67e22"}} onClick={()=>setBillForm(b)}>✏</button><button style={{...S.btnSm,background:"#e74c3c"}} onClick={()=>{
                          const cli2=clients.find(c=>c.id===b.clientId);
                          const ag2=agreements.find(a=>a.id===b.agId);
                          const html=buildRunningBillHTML(b,cli2,ag2,"client");
                          const blob=new Blob([html],{type:"text/html;charset=utf-8"});
                          _openBlob(blob, "report.html");
                        }}>🖨</button><button style={{...S.btnSm,background:"#c0392b"}} onClick={()=>upd({clientBills:clientBills.filter(x=>x.id!==b.id)})}>🗑</button></span></td></tr>))}</tbody></table>
            {clientBills.length===0 && <Empty text="कोई running bill नहीं है" />}</div></div>)}</div>
          );
        }
// ══════════════════════════════════════════════════════════════════════════════
