// ══════════════════════════════════════════════════════════════════
// ─── CSV IMPORT/EXPORT HELPERS ────────────────────────────────────
// ══════════════════════════════════════════════════════════════════

function exportCSV(data, filename, cols) {
  if (!_isWeb) { alert("CSV export sirf web browser mein kaam karta hai।"); return; }
  try {
    const header = cols.map(c => c.label).join(",");
    const rows = data.map(row => cols.map(c => `"${(row[c.key]||"").toString().replace(/"/g,'""')}"`).join(","));
    const csv = [header, ...rows].join("\n");
    const blob = new Blob([csv], {type:"text/csv"});
    _downloadBlob(blob, filename);
  } catch(e) { alert("Export failed: " + e.message); }
}

// Safe download helper — works in web, shows message in non-web env
function _downloadBlob(blob, filename) {
  if (!_isWeb) { alert("Download sirf web browser mein kaam karta hai।"); return; }
  // Use setTimeout to break call stack
  setTimeout(() => {
    try {
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = filename || "download";
      a.style.display = "none";
      document.body.appendChild(a);
      a.click();
      setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }, 1000);
    } catch(e) {
      alert("Download failed: " + e.message);
    }
  }, 0);
}

// Safe open-in-new-tab helper
function _openBlob(blob, filename) {
  if (!_isWeb) { alert("Print/Preview sirf web browser mein kaam karta hai।"); return; }
  // Use setTimeout to break call stack and avoid "Maximum call stack size exceeded"
  setTimeout(() => {
    try {
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.target = "_blank";
      a.rel = "noopener";
      a.download = filename || "report.html";
      document.body.appendChild(a);
      a.click();
      setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }, 1000);
    } catch(e) {
      // Fallback: open in current tab
      try {
        const reader = new FileReader();
        reader.onload = () => { window.open(reader.result, "_blank"); };
        reader.readAsDataURL(blob);
      } catch(e2) {
        alert("Print failed: " + e2.message + "\nKripya browser popup blocker band karein।");
      }
    }
  }, 0);
}


function ImportExportBar({ label, cols, onImport, onExport, data }) {
  const fileRef = useState(null);
  const handleFile = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const text = ev.target.result;
      // Proper CSV parser — handles quoted fields with commas inside
      const parseCSVLine = (line) => {
        const result = [];
        let cur = "";
        let inQuote = false;
        for (let i = 0; i < line.length; i++) {
          const ch = line[i];
          if (ch === '"') {
            if (inQuote && line[i+1] === '"') { cur += '"'; i++; }
            else { inQuote = !inQuote; }
          } else if (ch === ',' && !inQuote) {
            result.push(cur.trim());
            cur = "";
          } else {
            cur += ch;
          }
        }
        result.push(cur.trim());
        return result;
      };
      const allLines = text.split(/\r?\n/).filter(l => l.trim());
      const headers = parseCSVLine(allLines[0]);
      const rows = allLines.slice(1).map(line => {
        const vals = parseCSVLine(line);
        const obj = { id: uid() };
        headers.forEach((h, i) => { obj[h] = vals[i] ?? ""; });
        return obj;
      });
      onImport(rows);
    };
    reader.readAsText(file);
    e.target.value = "";
  };
  return (
    <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:12 }}>
      <label style={{ ...S.btnSm, background:"#27ae60", cursor:"pointer", padding:"5px 12px" }}>
        📥 Import CSV
        <input type="file" accept=".csv" style={{ display:"none" }} onChange={handleFile} />
      </label>
      <button style={{ ...S.btnSm, background:"#2980b9" }} onClick={() => exportCSV(data, `${label}.csv`, cols)}>📤 Export CSV</button>
      <span style={{ fontSize:11, color:"#666" }}>{data.length} records</span>
    </div>
  );
}
