// ─── ITEM MASTER MODULE ───────────────────────────────────────────
// ══════════════════════════════════════════════════════════════════

// ── AutoRow: Input with scrollable dropdown suggestions ──────────────────────
function AutoRow({ nameVal, suggestions, qtyVal, unitVal, units, namePlaceholder,
  onNameChange, onNameSelect, onQtyChange, onUnitChange, onDel }) {
  const [open, setOpen] = useState(false);
  const [localVal, setLocalVal] = useState(nameVal);
  const ref = useRef(null);

  // sync if parent changes
  useEffect(() => { setLocalVal(nameVal); }, [nameVal]);

  // close on outside click
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const filtered = (localVal.trim()
    ? suggestions.filter(s => s.toLowerCase().includes(localVal.toLowerCase()))
    : suggestions.slice(0, 50)  // limit initial list to 50
  ).slice(0, 100); // max 100 results

  return (
    <div style={{ display:"flex", gap:8, marginTop:6, alignItems:"center" }} ref={ref}>
      {/* Name input with dropdown */}
      <div style={{ flex:2, position:"relative" }}>
        <input
          style={{ ...S.input, width:"100%" }}
          placeholder={namePlaceholder}
          value={localVal}
          onChange={e => { setLocalVal(e.target.value); onNameChange(e.target.value); setOpen(true); }}
          onFocus={() => setOpen(true)}
          onKeyDown={e => { if(e.key==="Escape") setOpen(false); }}
          autoComplete="off"
        />
        {open && localVal.trim().length > 0 && filtered.length > 0 && (
          <div style={{
            position:"absolute", top:"100%", left:0, right:0, zIndex:9999,
            background:"#1a1a1a", border:"1px solid #3a3a3a", borderRadius:"0 0 6px 6px",
            maxHeight:200, overflowY:"auto", boxShadow:"0 4px 16px #000a"
          }}>
            {filtered.map((s, i) => (
              <div key={i}
                onMouseDown={e => { e.preventDefault(); setLocalVal(s); onNameSelect(s); setOpen(false); }}
                style={{
                  padding:"7px 12px", fontSize:13, cursor:"pointer", color:"#ddd",
                  background:"transparent", borderBottom:"1px solid #252525",
                  transition:"background .1s"
                }}
                onMouseEnter={e => e.currentTarget.style.background="#2a2a2a"}
                onMouseLeave={e => e.currentTarget.style.background="transparent"}
              >
                {s}
              </div>
            ))}
          </div>
        )}
      </div>
      {/* Qty */}
      <input style={{ ...S.input, width:70 }} type="number" placeholder="Qty"
        value={qtyVal} onChange={e=>onQtyChange(e.target.value)} />
      {/* Unit */}
      <select style={{ ...S.select, width:90 }} value={unitVal} onChange={e=>onUnitChange(e.target.value)}>
        {units.map(u => <option key={u}>{u}</option>)}
      </select>
      {/* Delete */}
      <button style={{ ...S.btnSm, background:"#c0392b", padding:"4px 8px" }} onClick={onDel}>✕</button>
    </div>
  );
}


function ItemMasterModule({ state, upd }) {
  const [sel, setSel] = useState(null);
  const [form, setForm] = useState(null);
  const [search, setSearch] = useState("");
  const [filterCat, setFilterCat] = useState("All");
  const formRef = useRef(null);

  const openForm = (data) => {
    setForm(data);
    // Scroll to form after render
    setTimeout(() => {
      if (formRef.current) {
        formRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
      }
    }, 80);
  };

  const items = (state.itemMaster && state.itemMaster.length > 0)
    ? state.itemMaster : [...ITEM_MASTER_DEFAULTS];
  const cats = ["All", ...new Set(items.map(i => i.category))];
  const filtered = items.filter(it =>
    (filterCat === "All" || it.category === filterCat) &&
    (it.name.toLowerCase().includes(search.toLowerCase()) || it.code.toLowerCase().includes(search.toLowerCase())));
  const selItem = items.find(i => i.id === sel);
  const save = (data) => {
    if (data.id) upd({ itemMaster: items.map(i => i.id === data.id ? data : i) });
    else upd({ itemMaster: [...items, { ...data, id: uid() }] });
    setForm(null);};
  const del = (id) => upd({ itemMaster: items.filter(i => i.id !== id) });
  const CSV_COLS = [{key:"code",label:"Code"},{key:"name",label:"Name"},{key:"category",label:"Category"},{key:"uom",label:"UoM"}];
  return (
    <div>
      <div style={S.rowBetween}>
        <STitle>📐 Item Master</STitle>
        <button style={S.btnPrimary} onClick={() => openForm({ materials:[], manpower:[], machinery:[]})}>+ New Item</button>
      </div>
      <ImportExportBar label="ItemMaster" cols={CSV_COLS} data={items}
        onExport={() => exportCSV(items, "ItemMaster.csv", CSV_COLS)}
        onImport={(rows) => upd({ itemMaster: [...items, ...rows.map(r => {
          const parseJ = (v) => { try { return v ? JSON.parse(v) : []; } catch { return []; } };
          return {
            ...r,
            id: uid(),
            materials:  parseJ(r.materials),
            manpower:   parseJ(r.manpower),
            machinery:  parseJ(r.machinery),
          };
        })] })}
      />
      <div ref={formRef}>
        {form && <ItemMasterForm data={form} onSave={save} onCancel={() => setForm(null)} state={state} />}
      </div>
      <div style={{ display:"flex", gap:8, marginBottom:12, flexWrap:"wrap" }}>
        <input style={{ ...S.input, width:200 }} placeholder="Search name / code..." value={search} onChange={e=>setSearch(e.target.value)} />
        <select style={S.select} value={filterCat} onChange={e=>setFilterCat(e.target.value)}>
          {cats.map(c=><option key={c}>{c}</option>)}
        </select>
      </div>
      <div style={{ display:"flex", gap:14, flexWrap:"wrap" }}>
        {/* List Panel */}
        <div style={{ width:320, flexShrink:0 }}>
          {filtered.map(it => (
            <div key={it.id} onClick={() => setSel(it.id)}
              style={{ padding:"8px 12px", marginBottom:4, borderRadius:8, cursor:"pointer", border:`1px solid ${sel===it.id?"#e67e22":"#2a2a2a"}`, background:sel===it.id?"#2a1800":"#111" }}>
              <div style={{ display:"flex", justifyContent:"space-between" }}>
                <div>
                  <span style={{ fontSize:11, color:"#e67e22", fontWeight:700 }}>{it.code}</span>
                  <div style={{ fontSize:13, fontWeight:600 }}>{it.name}</div>
                  <div style={{ fontSize:11, color:"#888" }}>{it.category} | {it.uom}</div>
                </div>
                <div style={{ display:"flex", gap:4, alignItems:"flex-start" }}>
                  <button style={{ ...S.btnSm, background:"transparent", color:"#aaa", border:"none" }} onClick={e=>{e.stopPropagation(); openForm(it)}
                  }>✏</button>
                  <button style={{ ...S.btnSm, background:"transparent", color:"#c0392b", border:"none" }} onClick={e=>{e.stopPropagation(); del(it.id)}
                  }>🗑</button>
                </div>
              </div>
            </div>))}
          {filtered.length === 0 && <Empty text="कोई item नहीं मिला" />}
        </div>
        {/* Detail Panel */}
        {selItem && (
          <div style={{ flex:1, minWidth:320 }}>
            <div style={S.card}>
              <div style={{ fontWeight:700, fontSize:16, color:"#e67e22" }}>{selItem.name}</div>
              <div style={{ fontSize:12, color:"#aaa" }}>{selItem.code} | UoM: <b style={{color:"#fff"}}>{selItem.uom}</b> | Category: {selItem.category}</div>
              {/* Materials */}
              {selItem.materials?.length > 0 && (
                <div style={{ marginTop:12 }}>
                  <div style={{ fontWeight:700, color:"#3498db", marginBottom:6 }}>🧱 Materials (per {selItem.uom})</div>
                  <table style={S.table}>
                    <thead><tr><th style={S.th}>Material</th><th style={S.th}>Qty</th><th style={S.th}>Unit</th></tr></thead>
                    <tbody>{selItem.materials.map((m,i)=><tr key={i}><td style={S.td}>{m.name}</td><td style={S.td}>{m.qty}</td><td style={S.td}>{m.unit}</td></tr>)}</tbody>
                  </table>
                </div>)}
              {/* Manpower */}
              {selItem.manpower?.length > 0 && (
                <div style={{ marginTop:12 }}>
                  <div style={{ fontWeight:700, color:"#27ae60", marginBottom:6 }}>👷 Manpower (per {selItem.uom})</div>
                  <table style={S.table}>
                    <thead><tr><th style={S.th}>Role</th><th style={S.th}>Qty</th><th style={S.th}>Unit</th></tr></thead>
                    <tbody>{selItem.manpower.map((m,i)=><tr key={i}><td style={S.td}>{m.role}</td><td style={S.td}>{m.qty}</td><td style={S.td}>{m.unit}</td></tr>)}</tbody>
                  </table>
                </div>)}
              {/* Machinery */}
              {selItem.machinery?.length > 0 && (
                <div style={{ marginTop:12 }}>
                  <div style={{ fontWeight:700, color:"#e67e22", marginBottom:6 }}>🚜 Machinery / Equipment (per {selItem.uom})</div>
                  <table style={S.table}>
                    <thead><tr><th style={S.th}>Equipment</th><th style={S.th}>Qty</th><th style={S.th}>Unit</th></tr></thead>
                    <tbody>{selItem.machinery.map((m,i)=><tr key={i}><td style={S.td}>{m.name}</td><td style={S.td}>{m.qty}</td><td style={S.td}>{m.unit}</td></tr>)}</tbody>
                  </table>
                </div>)}
            </div>
          </div>)}
      </div>
    </div>
  );
}

function ItemMasterForm({ data, onSave, onCancel, state }) {
  const [f, setF] = useState(() => ({ code:"", name:"", category:"", uom:"Cum", materials:[], manpower:[], machinery:[], ...(data||{}) }));
  // Sync when data changes (e.g. edit mode)
  useEffect(() => { setF(p => ({ ...p, ...(data||{}) })); }, [data?.id]);
  const updList = (key, idx, patch) => { const a=[...f[key]]; a[idx]={...a[idx],...patch}; setF({...f,[key]:a}); };
  const addRow  = (key, def) => { if(!f[key]) return; setF({...f, [key]:[...f[key], def]}); };
  const delRow  = (key, idx) => setF({...f, [key]:f[key].filter((_,i)=>i!==idx)});

  // Source lists for autocomplete
  const matMaster   = (state?.materialMaster && state.materialMaster.length > 0) ? state.materialMaster : DEFAULT_MATERIAL_MASTER;
  const matNames    = [...new Set(matMaster.map(m => m?.name||"").filter(Boolean))].sort();
  const manpowerRoles = ["Mason","Helper","Carpenter","Bar Bender","Painter","Plumber","Electrician",
    "Welder","Fitter","Operator","Supervisor","Labour","Tiler","Waterproofing Worker"];

  return (
    <div style={S.formBox}>
      <div style={S.formTitle}>{f.id ? "Edit Item" : "New Item"}</div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))", gap:12 }}>
        <LI label="Item Code *" value={f.code} onChange={v=>setF({...f,code:v})} />
        <LI label="Item Name *" value={f.name} onChange={v=>setF({...f,name:v})} />
        <LI label="Category" value={f.category} onChange={v=>setF({...f,category:v})} />
        <div>
          <label style={S.label}>UoM</label>
          <select style={S.select} value={f.uom} onChange={e=>setF({...f,uom:e.target.value})}>
            {["Cum","Sqm","RFT","Kg","MT","Nos","Bags","Liter","Hr","LS","cft","Trip","Sqft"].map(u=><option key={u}>{u}</option>)}
          </select>
        </div>
      </div>

      {/* Materials */}
      <div style={{ marginTop:14 }}>
        <div style={S.rowBetween}>
          <b style={{color:"#3498db"}}>Materials</b>
          <button style={{...S.btnSm,background:"#2980b9"}} onClick={()=>addRow("materials",{name:"",qty:0,unit:"Nos"})}>+ Add</button>
        </div>
        {(f.materials||[]).map((m,i)=>(
          <AutoRow key={i}
            nameVal={m.name}
            suggestions={matNames}
            qtyVal={m.qty}
            unitVal={m.unit}
            units={["Nos","KG","Bags","Cum","Sqm","Liter","cft","LS","RFT","MT"]}
            namePlaceholder="Material name..."
            onNameChange={v=>{ updList("materials",i,{name:v}); }}
            onNameSelect={v=>{
              const found = matMaster.find(mm=>mm.name===v);
              updList("materials",i,{ name:v, unit: found?.unit||m.unit });
            }}
            onQtyChange={v=>updList("materials",i,{qty:+v})}
            onUnitChange={v=>updList("materials",i,{unit:v})}
            onDel={()=>delRow("materials",i)}
          />
        ))}
        {(f.materials||[]).length===0 && <div style={{color:"#555",fontSize:12,padding:"6px 0"}}>कोई material नहीं — + Add करें</div>}
      </div>

      {/* Manpower */}
      <div style={{ marginTop:14 }}>
        <div style={S.rowBetween}>
          <b style={{color:"#27ae60"}}>Manpower</b>
          <button style={{...S.btnSm,background:"#27ae60"}} onClick={()=>addRow("manpower",{role:"",qty:0,unit:"Nos"})}>+ Add</button>
        </div>
        {(f.manpower||[]).map((m,i)=>(
          <AutoRow key={i}
            nameVal={m.role}
            suggestions={manpowerRoles}
            qtyVal={m.qty}
            unitVal={m.unit}
            units={["Nos","Days","Hr","LS"]}
            namePlaceholder="Role (Mason, Helper...)"
            onNameChange={v=>updList("manpower",i,{role:v})}
            onNameSelect={v=>updList("manpower",i,{role:v})}
            onQtyChange={v=>updList("manpower",i,{qty:+v})}
            onUnitChange={v=>updList("manpower",i,{unit:v})}
            onDel={()=>delRow("manpower",i)}
          />
        ))}
        {(f.manpower||[]).length===0 && <div style={{color:"#555",fontSize:12,padding:"6px 0"}}>कोई manpower नहीं — + Add करें</div>}
      </div>

      {/* Machinery */}
      <div style={{ marginTop:14 }}>
        <div style={S.rowBetween}>
          <b style={{color:"#e67e22"}}>Machinery / Equipment</b>
          <button style={{...S.btnSm}} onClick={()=>addRow("machinery",{name:"",qty:0,unit:"Hr"})}>+ Add</button>
        </div>
        {(f.machinery||[]).map((m,i)=>(
          <AutoRow key={i}
            nameVal={m.name}
            suggestions={[...new Set([
              ...((state?.equipmentMaster||[]).map(e=>e.name||"").filter(Boolean)),
              "Concrete Mixer","Vibrator","Bar Cutting Machine","Bar Bending Machine",
              "Transit Mixer","Batching Plant","Tower Crane","Mobile Crane","Excavator","JCB",
              "Dumper","Water Tanker","Compactor","Roller","Generator","Pump"
            ])].sort()}
            qtyVal={m.qty}
            unitVal={m.unit}
            units={["Hr","Trip","LS","Days","Nos"]}
            namePlaceholder="Equipment name..."
            onNameChange={v=>updList("machinery",i,{name:v})}
            onNameSelect={v=>updList("machinery",i,{name:v})}
            onQtyChange={v=>updList("machinery",i,{qty:+v})}
            onUnitChange={v=>updList("machinery",i,{unit:v})}
            onDel={()=>delRow("machinery",i)}
          />
        ))}
        {(f.machinery||[]).length===0 && <div style={{color:"#555",fontSize:12,padding:"6px 0"}}>कोई machinery नहीं — + Add करें</div>}
      </div>

      <div style={{...S.row,gap:8,marginTop:14}}>
        <button style={S.btnPrimary} onClick={()=>f.code&&f.name&&onSave(f)}>Save Item</button>
        <button style={S.btnSecondary} onClick={onCancel}>Cancel</button>
      </div>
    </div>
  );
}
// ══════════════════════════════════════════════════════════════════
// ─── MATERIAL MASTER MODULE ───────────────────────────────────────
// ══════════════════════════════════════════════════════════════════

function MaterialMasterModule({ state, upd }) {
  const [selCat, setSelCat]     = useState(null);   // currently selected category
  const [form, setForm]         = useState(null);    // add/edit material form
  const [catForm, setCatForm]   = useState(false);   // new category modal
  const [newCatName, setNewCatName] = useState("");
  const [search, setSearch]     = useState("");
  const [confirmDel, setConfirmDel] = useState(null);
  const [inlineEdit, setInlineEdit] = useState(null);

  const mats = state.materialMaster || DEFAULT_MATERIAL_MASTER;

  // All categories, maintaining insertion order (Set preserves insertion order)
  const allCats = [...new Set(mats.map(m => m.category).filter(Boolean))];

  // Items in selected category
  const catMats = selCat
    ? (mats||[]).filter(m => m.category === selCat &&
        (m.name.toLowerCase().includes(search.toLowerCase()) ||
         (m.code||"").toLowerCase().includes(search.toLowerCase())))
    : [];

  // auto-generate next code for a category
  const nextCode = (cat) => {
    const prefix = cat.replace(/[^A-Z0-9]/gi,"").substring(0,3).toUpperCase();
    const existing = (mats||[]).filter(m => (m.code||"").startsWith(prefix+"-")).map(m => parseInt((m.code||"").split("-")[1])||0);
    const next = existing.length ? Math.max(...existing)+1 : 1;
    return `${prefix}-${String(next).padStart(3,"0")}`;
  };

  const save = (data) => {
    if (data.id) upd({ materialMaster: mats.map(m => m.id === data.id ? data : m) });
    else upd({ materialMaster: [...mats, { ...data, id: uid() }] });
    setForm(null);
  };
  const saveInline = (id, patch) => {
    upd({ materialMaster: mats.map(m => m.id === id ? { ...m, ...patch } : m) });
    setInlineEdit(null);
  };
  const deleteMat = (id) => {
    upd({ materialMaster: (mats||[]).filter(m => m.id !== id) });
    setConfirmDel(null);
  };
  const addCategory = () => {
    const name = newCatName.trim();
    if (!name) return;
    if (allCats.includes(name)) { alert("यह category पहले से मौजूद है"); return; }
    // Add a placeholder entry to register the category, or just set selCat + open form
    setSelCat(name);
    setNewCatName("");
    setCatForm(false);
    setForm({ category: name, code: nextCode(name), unit:"Nos", gst:18, rate:0, hsnCode:"" });
  };
  const isSteelCat = (cat) => (cat||"") === "Steel";

  const CSV_COLS = [
    { key:"code", label:"Code" }, { key:"name", label:"Name" }, { key:"category", label:"Category" },
    { key:"unit", label:"Unit" }, { key:"rate", label:"Rate" }, { key:"gst", label:"GST%" },
    { key:"hsnCode", label:"HSN" }, { key:"dia", label:"Dia(mm)" }, { key:"grade", label:"Grade" }, { key:"wtPerMtr", label:"Wt/m(kg)" }
  ];

  return (
    <div style={{ display:"flex", gap:0, minHeight:500 }}>

      {/* ── LEFT: Category Panel ── */}
      <div style={{ width:200, minWidth:160, background:"#111", borderRight:"1px solid #2a2a2a",
        display:"flex", flexDirection:"column", borderRadius:"8px 0 0 8px", overflow:"hidden" }}>
        <div style={{ padding:"12px 10px 8px", borderBottom:"1px solid #222", fontSize:13, fontWeight:700, color:"#e67e22" }}>
          📂 Categories
        </div>
        <div style={{ overflowY:"auto", flex:1 }}>
          {allCats.map(cat => {
            const count = (mats||[]).filter(m => m.category === cat).length;
            return (
              <div key={cat} onClick={() => { setSelCat(cat); setSearch(""); setForm(null); }}
                style={{ padding:"9px 10px", cursor:"pointer", fontSize:13, fontWeight: selCat===cat ? 700 : 400,
                  background: selCat===cat ? "#1e3a1e" : "transparent",
                  borderLeft: selCat===cat ? "3px solid #27ae60" : "3px solid transparent",
                  color: selCat===cat ? "#27ae60" : "#bbb",
                  display:"flex", justifyContent:"space-between", alignItems:"center",
                  transition:"all .15s"
                }}>
                <span style={{ overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{cat}</span>
                <span style={{ background:"#222", borderRadius:10, fontSize:10, padding:"1px 6px", color:"#888", minWidth:20, textAlign:"center" }}>{count}</span>
              </div>
            );
          })}
        </div>
        {/* Add Category Button */}
        <div style={{ padding:8, borderTop:"1px solid #222" }}>
          {catForm ? (
            <div style={{ display:"flex", flexDirection:"column", gap:4 }}>
              <input autoFocus style={{ ...S.input, fontSize:12, padding:"4px 6px" }}
                placeholder="Category name..."
                value={newCatName} onChange={e=>setNewCatName(e.target.value)}
                onKeyDown={e=>{ if(e.key==="Enter") addCategory(); if(e.key==="Escape") setCatForm(false); }} />
              <div style={{ display:"flex", gap:4 }}>
                <button style={{ ...S.btnSm, background:"#27ae60", flex:1, fontSize:11 }} onClick={addCategory}>✓ Add</button>
                <button style={{ ...S.btnSm, background:"#555", flex:1, fontSize:11 }} onClick={()=>{ setCatForm(false); setNewCatName(""); }}>✕</button>
              </div>
            </div>
          ) : (
            <button style={{ ...S.btnSm, width:"100%", background:"#1a3a2a", color:"#27ae60", fontSize:12, border:"1px dashed #27ae60" }}
              onClick={()=>setCatForm(true)}>+ New Category</button>
          )}
        </div>
      </div>

      {/* ── RIGHT: Material List ── */}
      <div style={{ flex:1, padding:"0 0 0 0", display:"flex", flexDirection:"column", minWidth:0 }}>
        {!selCat ? (
          <div style={{ display:"flex", alignItems:"center", justifyContent:"center", height:300, color:"#555", fontSize:14 }}>
            ← कोई Category चुनें
          </div>
        ) : (
          <>
            {/* Header */}
            <div style={{ display:"flex", alignItems:"center", gap:8, padding:"10px 12px", borderBottom:"1px solid #1a1a1a", flexWrap:"wrap" }}>
              <span style={{ fontWeight:700, color:"#e67e22", fontSize:15 }}>📦 {selCat}</span>
              <span style={{ fontSize:12, color:"#666" }}>{(mats||[]).filter(m=>m.category===selCat).length} items)</span>
              <div style={{ flex:1 }} />
              <input style={{ ...S.input, width:180, fontSize:12 }} placeholder="🔍 Search..."
                value={search} onChange={e=>setSearch(e.target.value)} />
              <button style={{ ...S.btnSm, background:"#1a3a5a", color:"#3498db", border:"1px solid #3498db", fontSize:12 }}
                onClick={()=>{ const c=nextCode(selCat); setForm({ category:selCat, code:c, unit:"Nos", gst:18, rate:0, hsnCode:"" }); }}>
                + Add Material
              </button>
              <ImportExportBar label="MaterialMaster" cols={CSV_COLS} data={mats}
                onExport={()=>exportCSV(mats,"MaterialMaster.csv",CSV_COLS)}
                onImport={(rows)=>upd({ materialMaster:[...mats,...rows.map(r=>({...r,id:uid(),rate:+r.rate||0,gst:+r.gst||0}))] })} />
              {/* Sync from BUILTIN_CATEGORIES / Templates */}
              <button style={{...S.btnSm,background:"#1a3a1a",color:"#27ae60",border:"1px solid #27ae60",fontSize:11}}
                title="BUILTIN_CATEGORIES के सभी items को materialMaster में add करें (duplicate skip)"
                onClick={()=>{
                  const existing = new Set(mats.map(m=>(m.name||"").toLowerCase()));
                  const toAdd = [];
                  for (const cat of BUILTIN_CATEGORIES) {
                    for (const sub of (cat.subcategories||[])) {
                      for (const stage of (sub.substages||[])) {
                        for (const item of (stage.items||[])) {
                          if (!existing.has((item.name||"").toLowerCase())) {
                            toAdd.push({ id:uid(), name:item.name, unit:item.unit||"Nos",
                              rate:item.rate||0, category:cat.name, gst:18, hsnCode:"",
                              code:nextCode(cat.name) });
                            existing.add((item.name||"").toLowerCase());
                          }
                        }
                      }
                    }
                  }
                  if (toAdd.length === 0) { alert("सभी items पहले से materialMaster में हैं!"); return; }
                  if (!_isWeb || window.confirm(`${toAdd.length} नए items add होंगे। Continue?`))
                    upd({ materialMaster:[...mats,...toAdd] });
                }}>
                🔄 Sync from Templates
              </button>
            </div>

            {/* ── Add / Edit Form ── */}
            {form && (
              <div style={{ ...S.formBox, margin:"10px 12px", padding:14 }}>
                <div style={S.formTitle}>{form.id ? "✏ Edit Material" : `➕ New Material — ${form.category}`}</div>
                <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))", gap:10 }}>
                  {/* Code — auto filled, editable */}
                  <div>
                    <label style={S.label}>Code (auto)</label>
                    <input style={{ ...S.input, color:"#e67e22" }} value={form.code||""}
                      onChange={e=>setForm({...form,code:e.target.value.toUpperCase()})} />
                  </div>
                  <div style={{ gridColumn:"span 2" }}>
                    <LI label="Material Name *" value={form.name||""} onChange={v=>{
                      const info = getMaterialInfo(v, mats, state.masterRates);
                      setForm({...form, name:v,
                        unit: form.unit||"Nos" !== "Nos" ? form.unit : (info.unit||form.unit||"Nos"),
                        rate: form.rate > 0 ? form.rate : (info.rate || 0),
                        gst: form.gst || info.gst || 18,
                        hsnCode: form.hsnCode || info.hsnCode || "",
                      });
                    }} />
                  </div>
                  <div>
                    <label style={S.label}>Unit</label>
                    <select style={S.select} value={form.unit||"Nos"} onChange={e=>setForm({...form,unit:e.target.value})}>
                      {["KG","MT","Bags","Cft","Cum","Sqm","Sqft","Nos","Liter","RFT","Ton","LS","Trip","RMT"].map(u=><option key={u}>{u}</option>)}
                    </select>
                  </div>
                  <LI label="Rate (₹) *" type="number" value={form.rate||0} onChange={v=>setForm({...form,rate:+v})} />
                  <LI label="GST %" type="number" value={form.gst||18} onChange={v=>setForm({...form,gst:+v})} />
                  <LI label="HSN Code" value={form.hsnCode||""} onChange={v=>setForm({...form,hsnCode:v})} />
                  {isSteelCat(form.category) && (<>
                    <div>
                      <label style={S.label}>Dia (mm)</label>
                      <select style={S.select} value={form.dia||""} onChange={e=>{
                        const d=+e.target.value; const wt=d?+(d*d/162).toFixed(3):undefined;
                        setForm({...form,dia:d||undefined,wtPerMtr:wt})}}>
                        <option value="">-- None --</option>
                        {[8,10,12,16,20,25,28,32].map(d=><option key={d} value={d}>{d} mm</option>)}
                      </select>
                    </div>
                    <div>
                      <label style={S.label}>Grade</label>
                      <select style={S.select} value={form.grade||"Fe500"} onChange={e=>setForm({...form,grade:e.target.value})}>
                        {["Fe415","Fe500","Fe550","Fe600"].map(g=><option key={g}>{g}</option>)}
                      </select>
                    </div>
                    <div>
                      <label style={S.label}>Wt/m (kg) — auto</label>
                      <input style={{...S.input,color:"#aaa"}} type="number" value={form.wtPerMtr||""} readOnly placeholder="Auto from dia" />
                    </div>
                  </>)}
                </div>
                <div style={{...S.row,gap:8,marginTop:10}}>
                  <button style={S.btnPrimary} onClick={()=>form.name&&form.rate&&save(form)}>💾 Save</button>
                  <button style={S.btnSecondary} onClick={()=>setForm(null)}>Cancel</button>
                </div>
              </div>
            )}

            {/* ── Table ── */}
            <div style={{ overflowX:"auto", overflowY:"auto", flex:1, padding:"0 12px 12px" }}>
              <table style={{ ...S.table, marginTop:8 }}>
                <thead><tr>
                  <th style={S.th}>Code</th>
                  <th style={S.th}>Name</th>
                  <th style={S.th}>Unit</th>
                  <th style={S.th}>Rate (₹)</th>
                  <th style={S.th}>GST%</th>
                  <th style={S.th}>HSN</th>
                  {selCat === "Steel" && <th style={S.th}>Dia / Grade / Wt</th>}
                  <th style={S.th}>Actions</th>
                </tr></thead>
                <tbody>
                  {catMats.map(m => (
                    <tr key={m.id} style={{ background: inlineEdit===m.id ? "#1a1a0d" : "transparent" }}>
                      <td style={{...S.td,color:"#e67e22",fontWeight:700}}>{m.code}</td>
                      <td style={{...S.td,fontWeight:600}}>{m.name}</td>
                      <td style={S.td}>{m.unit}</td>
                      <td style={S.td}>
                        {inlineEdit===m.id ? (
                          <input autoFocus type="number"
                            style={{...S.input,width:90,fontSize:13,fontWeight:700,color:"#27ae60"}}
                            defaultValue={m.rate}
                            onBlur={e=>saveInline(m.id,{rate:+e.target.value})}
                            onKeyDown={e=>{if(e.key==="Enter")saveInline(m.id,{rate:+e.target.value});if(e.key==="Escape")setInlineEdit(null);}} />
                        ) : (
                          <span style={{color:"#27ae60",fontWeight:700,cursor:"pointer",borderBottom:"1px dashed #27ae6066"}}
                            title="Click to edit rate" onClick={()=>setInlineEdit(m.id)}>{INR(m.rate)}</span>
                        )}
                      </td>
                      <td style={S.td}>{m.gst}%</td>
                      <td style={S.td}>{m.hsnCode}</td>
                      {selCat==="Steel" && (
                        <td style={S.td}>
                          {m.dia ? <span style={{fontSize:11}}><b style={{color:"#e67e22"}}>⌀{m.dia}mm</b>{m.grade&&<span style={{color:"#aaa"}}> | {m.grade}</span>}{m.wtPerMtr&&<span style={{color:"#888"}}> | {m.wtPerMtr}kg/m</span>}</span> : <span style={{color:"#555"}}>—</span>}
                        </td>
                      )}
                      <td style={S.td}>
                        <div style={{...S.row,gap:4}}>
                          <button style={{...S.btnSm,padding:"3px 8px",fontSize:11}} onClick={()=>setForm(m)}>✏</button>
                          <button style={{...S.btnSm,background:"#2a0a0a",color:"#c0392b",padding:"3px 8px",fontSize:11}}
                            onClick={()=>setConfirmDel(m.id)}>🗑</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {catMats.length===0 && (
                    <tr><td colSpan={selCat==="Steel"?8:7} style={{...S.td,textAlign:"center",color:"#444",padding:24}}>
                      {search ? "कोई result नहीं" : "इस category में कोई material नहीं — ऊपर + Add करें"}
                    </td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </>
        )}
      </div>

      {/* Confirm Delete */}
      {confirmDel && (
        <div style={{position:"fixed",inset:0,background:"#000a",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center"}}>
          <div style={{background:"#1a0000",border:"2px solid #c0392b",borderRadius:8,padding:24,maxWidth:320,textAlign:"center"}}>
            <div style={{color:"#c0392b",fontWeight:700,marginBottom:12}}>⚠ Delete Material?</div>
            <div style={{color:"#aaa",fontSize:13,marginBottom:16}}>यह material हमेशा के लिए delete हो जाएगा।</div>
            <div style={{...S.row,gap:8,justifyContent:"center"}}>
              <button style={{...S.btnSm,background:"#c0392b"}} onClick={()=>deleteMat(confirmDel)}>🗑 Delete</button>
              <button style={S.btnSecondary} onClick={()=>setConfirmDel(null)}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      {/* Steel Weight Calculator */}
      {selCat==="Steel" && <SteelWeightCalculator materialMaster={mats} />}
    </div>
  );
}
